var surah007 = {
  number: 7,
  nameArabic: "al-A'raf ",
  nameEnglish: "Al-A'raf",
  meaning: "The Heights",
  totalAyahs: 206,
  ayahs: [
    { number: 1, arabic: "الٓمٓصٓ", transliteration: "Aliflammeemsad", transliterationB: "Alif-Laaam-Meeem-Saaad", english: "Alif, Lam, Mim, Sad", romanUrdu: "Alif Laam Meem Saad" },
    { number: 2, arabic: "كِتَٰبٌ أُنزِلَ إِلَيْكَ فَلَا يَكُن فِى صَدْرِكَ حَرَجٌۭ مِّنْهُ لِتُنذِرَ بِهِۦ وَذِكْرَىٰ لِلْمُؤْمِنِينَ", transliteration: "Kitabun onzila ilayka fala yakun fee sadrika harajun minhu litunthira bihi wathikra lilmumineena", transliterationB: "Kitaabun unzila ilaika falaa yakum fee sadrika harajum minhu litunzira bihee wa zikraa lilmu'mineen", english: "A Book revealed unto thee,- So let thy heart be oppressed no more by any difficulty on that account,- that with it thou mightest warn (the erring) and teach the Believers", romanUrdu: "Yeh ek kitab hai jo tumhari taraf nazil ki gayi hai, pas (aey Muhammad), tumhare dil mein issey koi jhijak na ho, iske utaarne ki garz yeh hai ke tum iske zariye se (munkireen ko) darao aur iman laney waley logon ko yaad dihani ho" },
    { number: 3, arabic: "ٱتَّبِعُوا۟ مَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُمْ وَلَا تَتَّبِعُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ۗ قَلِيلًۭا مَّا تَذَكَّرُونَ", transliteration: "IttabiAAoo ma onzila ilaykum min rabbikum wala tattabiAAoo min doonihi awliyaa qaleelan ma tathakkaroona", transliterationB: "Ittabi'oo maaa unzila 'ilaikum mir Rabbikum wa laa tattabi'oo min dooniheee awliyaaa'; qaleelam maa tazakkaroon", english: "Follow (O men!) the revelation given unto you from your Lord, and follow not, as friends or protectors, other than Him. Little it is ye remember of admonition", romanUrdu: "Logon, jo kuch tumhare Rubb ki taraf se tumpar nazil kiya gaya hai uski pairwi karo aur apne Rubb ko chodh kar dusre sarparaton ki pairwi na karo, magar tum naseehat kam hi maante ho" },
    { number: 4, arabic: "وَكَم مِّن قَرْيَةٍ أَهْلَكْنَٰهَا فَجَآءَهَا بَأْسُنَا بَيَٰتًا أَوْ هُمْ قَآئِلُونَ", transliteration: "Wakam min qaryatin ahlaknaha fajaaha basuna bayatan aw hum qailoona", transliterationB: "Wa kam min qaryatin ahlaknaahaa fajaaa'ahaa baasunaa bayaatan aw hum qaaa'iloon", english: "How many towns have We destroyed (for their sins)? Our punishment took them on a sudden by night or while they slept for their afternoon rest", romanUrdu: "Kitni hi bastiyan hain jinhein humne halaak kardiya, unpar hamara azaab achanak raat ke waqt toot pada, ya din dahade aise waqt aaya jab woh aaraam kar rahey thay" },
    { number: 5, arabic: "فَمَا كَانَ دَعْوَىٰهُمْ إِذْ جَآءَهُم بَأْسُنَآ إِلَّآ أَن قَالُوٓا۟ إِنَّا كُنَّا ظَٰلِمِينَ", transliteration: "Fama kana daAAwahum ith jaahum basuna illa an qaloo inna kunna thalimeena", transliterationB: "Famaa kaana da'waahum iz jaaa'ahum baasunaa illaaa an qaalooo innaa kunnaa zaalimeen", english: "When (thus) Our punishment took them, no cry did they utter but this: \"Indeed we did wrong", romanUrdu: "Aur jab hamara azaab unpar aa gaya to unki zubaan par iske siwa koi sadaa na thi ke waqayi hum zalim thay" },
    { number: 6, arabic: "فَلَنَسْـَٔلَنَّ ٱلَّذِينَ أُرْسِلَ إِلَيْهِمْ وَلَنَسْـَٔلَنَّ ٱلْمُرْسَلِينَ", transliteration: "Falanasalanna allatheena orsila ilayhim walanasalanna almursaleena", transliterationB: "Falanas 'alannal lazeena ursila ilaihim wa lanas 'alannal mursaleen", english: "Then shall we question those to whom Our message was sent and those by whom We sent it", romanUrdu: "Pas yeh zaroor hokar rehna hai ke hum un logon se baaz-purs karein jinki taraf humne paigambar bheje hain aur paigambaron se bhi puchein (ke unhon ne paigaam rasani ka farz kahan tak anjaam diya aur unhein iska kya jawab mila)" },
    { number: 7, arabic: "فَلَنَقُصَّنَّ عَلَيْهِم بِعِلْمٍۢ ۖ وَمَا كُنَّا غَآئِبِينَ", transliteration: "Falanaqussanna AAalayhim biAAilmin wama kunna ghaibeena", transliterationB: "Falanaqussanna 'alaihim bi'ilminw wa maa kunnaa ghaaa'ibeen", english: "And verily, We shall recount their whole story with knowledge, for We were never absent (at any time or place)", romanUrdu: "Phir hum khud purey ilm ke saath saari sargushist (whole account) unke aagey pesh kardenge. Aakhir hum kahin gayab to nahin thay" },
    { number: 8, arabic: "وَٱلْوَزْنُ يَوْمَئِذٍ ٱلْحَقُّ ۚ فَمَن ثَقُلَتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Waalwaznu yawmaithini alhaqqu faman thaqulat mawazeenuhu faolaika humu almuflihoona", transliterationB: "Walwaznu Yawma'izinil haqq; faman saqulat mawaa zeenuhoo fa-ulaaa'ika humul muflihoon", english: "The balance that day will be true (to nicety): those whose scale (of good) will be heavy, will prosper", romanUrdu: "Aur wazan us roz ain e haqq hoga, jinke padley bhaari hongey wahi falaah payenge" },
    { number: 9, arabic: "وَمَنْ خَفَّتْ مَوَٰزِينُهُۥ فَأُو۟لَٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُم بِمَا كَانُوا۟ بِـَٔايَٰتِنَا يَظْلِمُونَ", transliteration: "Waman khaffat mawazeenuhu faolaika allatheena khasiroo anfusahum bima kanoo biayatina yathlimoona", transliterationB: "Wa man khaffat mawaazeenuhoo fa ulaaa'ikal lazeena khasirooo anfusahum bimaa kaanoo bi Aayaatinaa yazlimoon", english: "Those whose scale will be light, will be their souls in perdition, for that they wrongfully treated Our signs", romanUrdu: "Aur jinke padley halke rahenge wahi apne aap ko khasarey (nuksan) mein mubtila karne waley hongey, kyunke woh hamari aayat ke saath zalimana bartao karte rahey thay" },
    { number: 10, arabic: "وَلَقَدْ مَكَّنَّٰكُمْ فِى ٱلْأَرْضِ وَجَعَلْنَا لَكُمْ فِيهَا مَعَٰيِشَ ۗ قَلِيلًۭا مَّا تَشْكُرُونَ", transliteration: "Walaqad makkannakum fee alardi wajaAAalna lakum feeha maAAayisha qaleelan ma tashkuroona", transliterationB: "Wa laqad makkannaakum fil ardi wa ja'alnaa lakum feehaa ma'aayish; qaleelam maa tashkuroon", english: "It is We Who have placed you with authority on earth, and provided you therein with means for the fulfilment of your life: small are the thanks that ye give", romanUrdu: "Humne tumhein zameen mein ikhtiyarat ke saath basaya aur tumhare liye yahan samaan e zeist faraham kiya Magar tumlog kam hi shukar-guzar hotey ho" },
    { number: 11, arabic: "وَلَقَدْ خَلَقْنَٰكُمْ ثُمَّ صَوَّرْنَٰكُمْ ثُمَّ قُلْنَا لِلْمَلَٰٓئِكَةِ ٱسْجُدُوا۟ لِءَادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ لَمْ يَكُن مِّنَ ٱلسَّٰجِدِينَ", transliteration: "Walaqad khalaqnakum thumma sawwarnakum thumma qulna lilmalaikati osjudoo liadama fasajadoo illa ibleesa lam yakun mina alssajideena", transliterationB: "Wa laqad khalaqnaakum summa sawwarnaakum summa qulnaa lilmalaaa'ikatis judoo li Aadama fa-sajadooo illaaa Ibleesa lam yakum minas saajideen", english: "It is We Who created you and gave you shape; then We bade the angels prostrate to Adam, and they prostrate; not so Iblis; He refused to be of those who prostrate", romanUrdu: "Humne tumhari takhleeq (creation) ki ibteda ki, phir tumhari surat banayi, phir farishton se kaha Adam ko sajda karo. Is hukm par sabne sajda kiya magar Iblis sajda karne walon mein shamil na hua" },
    { number: 12, arabic: "قَالَ مَا مَنَعَكَ أَلَّا تَسْجُدَ إِذْ أَمَرْتُكَ ۖ قَالَ أَنَا۠ خَيْرٌۭ مِّنْهُ خَلَقْتَنِى مِن نَّارٍۢ وَخَلَقْتَهُۥ مِن طِينٍۢ", transliteration: "Qala ma manaAAaka alla tasjuda ith amartuka qala ana khayrun minhu khalaqtanee min narin wakhalaqtahu min teenin", transliterationB: "Qaala maa mana'aka allaa tasjuda iz amartuka qaala ana khairum minhu khalaqtanee min naarinw wa khalaqtahoo min teen", english: "(Allah) said: \"What prevented thee from prostrating when I commanded thee?\" He said: \"I am better than he: Thou didst create me from fire, and him from clay", romanUrdu: "Pucha, “ tujhey kis cheez ne sajda karne se roka jabke maine tujhko hukum diya tha?” bola , main ussey behtar hoon. Tu nay mujhey aag se paida kiya hai aur usey mitti se”" },
    { number: 13, arabic: "قَالَ فَٱهْبِطْ مِنْهَا فَمَا يَكُونُ لَكَ أَن تَتَكَبَّرَ فِيهَا فَٱخْرُجْ إِنَّكَ مِنَ ٱلصَّٰغِرِينَ", transliteration: "Qala faihbit minha fama yakoonu laka an tatakabbara feeha faokhruj innaka mina alssaghireena", transliterationB: "Qaala fahbit minhaa famaa yakoonu laka an tatakabbara feehaa fakhruj innaka minas saaghireen", english: "(Allah) said: \"Get thee down from this: it is not for thee to be arrogant here: get out, for thou art of the meanest (of creatures)", romanUrdu: "Farmaya, “accha tu yahan se nichey utar , tujhey haqq nahin hai ke yahan badayi ka ghamand karey, nikal jaa ke dar-haqeeqat tu un logon mein se hai jo khud apni zillat chahte hain”" },
    { number: 14, arabic: "قَالَ أَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ", transliteration: "Qala anthirnee ila yawmi yubAAathoona", transliterationB: "Qaala anzirneee ilaa Yawmi yub'asoon", english: "He said: \"Give me respite till the day they are raised up", romanUrdu: "Bola, “ mujhey us din tak mohlat de jabke yeh sab dobara uthaye jayenge”" },
    { number: 15, arabic: "قَالَ إِنَّكَ مِنَ ٱلْمُنظَرِينَ", transliteration: "Qala innaka mina almunthareena", transliterationB: "Qaala innaka minal munzareen", english: "(Allah) said: \"Be thou among those who have respite", romanUrdu: "Farmaya “ tujhey mohlat hai.”" },
    { number: 16, arabic: "قَالَ فَبِمَآ أَغْوَيْتَنِى لَأَقْعُدَنَّ لَهُمْ صِرَٰطَكَ ٱلْمُسْتَقِيمَ", transliteration: "Qala fabima aghwaytanee laaqAAudanna lahum sirataka almustaqeema", transliterationB: "Qaala fabimaaa aghway tanee la aq'udanna lahum Siraatakal Mustaqeem", english: "He said: \"Because thou hast thrown me out of the way, lo! I will lie in wait for them on thy straight way", romanUrdu: "Bola, “accha to jis tarah tu nay mujhey gumraahi mein mubtala kiya main bhi ab teri seedhi raah par" },
    { number: 17, arabic: "ثُمَّ لَءَاتِيَنَّهُم مِّنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ وَعَنْ أَيْمَٰنِهِمْ وَعَن شَمَآئِلِهِمْ ۖ وَلَا تَجِدُ أَكْثَرَهُمْ شَٰكِرِينَ", transliteration: "Thumma laatiyannahum min bayni aydeehim wamin khalfihim waAAan aymanihim waAAan shamailihim wala tajidu aktharahum shakireena", transliterationB: "Summa la aatiyannahum mim baine aideehim wa min khalfihim wa 'an aimaanihim wa 'an shamaaa'ilihim wa laa tajidu aksarahum shaakireen", english: "Then will I assault them from before them and behind them, from their right and their left: Nor wilt thou find, in most of them, gratitude (for thy mercies)", romanUrdu: "In Insaano ki ghaath mein laga rahunga, aagey aur pichey, dayein aur bayein, har taraf se inko gherunga aur tu in mein se aksar ko shukarguzar na payega”" },
    { number: 18, arabic: "قَالَ ٱخْرُجْ مِنْهَا مَذْءُومًۭا مَّدْحُورًۭا ۖ لَّمَن تَبِعَكَ مِنْهُمْ لَأَمْلَأَنَّ جَهَنَّمَ مِنكُمْ أَجْمَعِينَ", transliteration: "Qala okhruj minha mathooman madhooran laman tabiAAaka minhum laamlaanna jahannama minkum ajmaAAeena", transliterationB: "Qaalakh ruj mnhaa maz'oomam madhooraa; laman tabi'aka minhum la amla'anna Jahannama minkum ajma'een", english: "(Allah) said: \"Get out from this, disgraced and expelled. If any of them follow thee,- Hell will I fill with you all", romanUrdu: "Farmaya, “nikal jaa yahan se zaleel aur thukraya hua, yakeen rakh ke in mein se jo teri pairwi karenge, tujh sameith un sab se jahannum ko bhar doonga" },
    { number: 19, arabic: "وَيَٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ فَكُلَا مِنْ حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّٰلِمِينَ", transliteration: "Waya adamu oskun anta wazawjuka aljannata fakula min haythu shituma wala taqraba hathihi alshshajarata fatakoona mina alththalimeena", transliterationB: "Wa yaaa Aadamus kun anta wa zawjukal Jannata fakulaa min haisu shi'tumaa wa laa taqrabaa haazihish shajarata fatakoonaa minza zaalimeen", english: "O Adam! dwell thou and thy wife in the Garden, and enjoy (its good things) as ye wish: but approach not this tree, or ye run into harm and transgression", romanUrdu: "Aur aey Adam, tu aur teri biwi, dono is jannat mein raho, jahan jis cheez ko tumhara jee chahe khao, magar us darakht ke paas na phatakna warna zalimon mein se ho jaogey”" },
    { number: 20, arabic: "فَوَسْوَسَ لَهُمَا ٱلشَّيْطَٰنُ لِيُبْدِىَ لَهُمَا مَا وُۥرِىَ عَنْهُمَا مِن سَوْءَٰتِهِمَا وَقَالَ مَا نَهَىٰكُمَا رَبُّكُمَا عَنْ هَٰذِهِ ٱلشَّجَرَةِ إِلَّآ أَن تَكُونَا مَلَكَيْنِ أَوْ تَكُونَا مِنَ ٱلْخَٰلِدِينَ", transliteration: "Fawaswasa lahuma alshshaytanu liyubdiya lahuma ma wooriya AAanhuma min sawatihima waqala ma nahakuma rabbukuma AAan hathihi alshshajarati illa an takoona malakayni aw takoona mina alkhalideena", transliterationB: "Fawaswasa lahumash Shaitaanu liyubdiya lahumaa maa wooriya 'anhumaa min saw aatihimaa wa qaala maa nahaakumaa Rabbukumaa 'an haazihish shajarati illaaa an takoonaa malakaini aw takoonaa minal khaalideen", english: "Then began Satan to whisper suggestions to them, bringing openly before their minds all their shame that was hidden from them (before): he said: \"Your Lord only forbade you this tree, lest ye should become angels or such beings as live for ever", romanUrdu: "Phir Shaytan ne unko behkaya taa-ke unki sharmgaahein jo ek dusre se chupayi gayi thin unke saamne khol de. Usne unse kaha, “tumhare Rubb ne tumhein jo is darakh se roka hai iski wajah iske siwa kuch nahin hai ke kahin tum Farishtey na ban jao, ya tumhein hameshgi ki zindagi hasil na ho jaye" },
    { number: 21, arabic: "وَقَاسَمَهُمَآ إِنِّى لَكُمَا لَمِنَ ٱلنَّٰصِحِينَ", transliteration: "Waqasamahuma innee lakuma lamina alnnasiheena", transliterationB: "Wa qaasamahumaaa innee lakumaa laminan naasiheen", english: "And he swore to them both, that he was their sincere adviser", romanUrdu: "Aur usne kasam kha kar unse kaha ke main tumhara saccha khair-khwa hoon" },
    { number: 22, arabic: "فَدَلَّىٰهُمَا بِغُرُورٍۢ ۚ فَلَمَّا ذَاقَا ٱلشَّجَرَةَ بَدَتْ لَهُمَا سَوْءَٰتُهُمَا وَطَفِقَا يَخْصِفَانِ عَلَيْهِمَا مِن وَرَقِ ٱلْجَنَّةِ ۖ وَنَادَىٰهُمَا رَبُّهُمَآ أَلَمْ أَنْهَكُمَا عَن تِلْكُمَا ٱلشَّجَرَةِ وَأَقُل لَّكُمَآ إِنَّ ٱلشَّيْطَٰنَ لَكُمَا عَدُوٌّۭ مُّبِينٌۭ", transliteration: "Fadallahuma bighuroorin falamma thaqa alshshajarata badat lahuma sawatuhuma watafiqa yakhsifani AAalayhima min waraqi aljannati wanadahuma rabbuhuma alam anhakuma AAan tilkuma alshshajarati waaqul lakuma inna alshshaytana lakuma AAaduwwun mubeenun", transliterationB: "Fadallaahumaa bighuroor; falammaa zaaqash shajarata badat lahumaa saw aatuhumaa wa tafiqaa yakhsifaani 'alaihimaa minw waraqil jannati wa naadaahumaa Rabbuhumaaa alam anhakumaa 'an tilkumash shajarati wa aqul lakumaaa innash Shaitaana lakumaa 'aduwwum mubeen", english: "So by deceit he brought about their fall: when they tasted of the tree, their shame became manifest to them, and they began to sew together the leaves of the garden over their bodies. And their Lord called unto them: \"Did I not forbid you that tree, and tell you that Satan was an avowed enemy unto you", romanUrdu: "Is tarah dhoka dekar woh un dono ko rafta rafta apne dhap par le aaya. Aakhir e kaar jab unhon ne us darakht ka maza chakkha to unke satr ek dusre ke saamne khul gaye aur woh apne jismon ko jannat ke patton se dhankne lagey. Tab unke Rubb ne unhein pukara, “kya maine tumhein is darakht se na roka tha aur na kaha tha ke shaytan tumhara khula dushman hai?”" },
    { number: 23, arabic: "قَالَا رَبَّنَا ظَلَمْنَآ أَنفُسَنَا وَإِن لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ ٱلْخَٰسِرِينَ", transliteration: "Qala rabbana thalamna anfusana wain lam taghfir lana watarhamna lanakoonanna mina alkhasireena", transliterationB: "Qaalaa Rabbanaa zalamnaaa anfusanaa wa illam taghfir lanaa wa tarhamnaa lanakoonanna minal khaasireen", english: "They said: \"Our Lord! We have wronged our own souls: If thou forgive us not and bestow not upon us Thy Mercy, we shall certainly be lost", romanUrdu: "Dono bol utthey, “Aey Rubb, humne apne upar sitam (zulm) kiya, ab agar tu nay humse darguzar na farmaya aur reham na kiya to yakeenan hum tabaah ho jayenge.”" },
    { number: 24, arabic: "قَالَ ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّۭ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّۭ وَمَتَٰعٌ إِلَىٰ حِينٍۢ", transliteration: "Qala ihbitoo baAAdukum libaAAdin AAaduwwun walakum fee alardi mustaqarrun wamataAAun ila heenin", transliterationB: "Qaalah bitoo ba'dukum liba'din aduwwunw wa lakum fil ardi mmustaqarrunw wa mataa'un ilaaheen", english: "(Allah) said: \"Get ye down. With enmity between yourselves. On earth will be your dwelling-place and your means of livelihood,- for a time", romanUrdu: "Farmaya, “utar jao, tum ek dusre ke dushman ho. Aur tumhare liye ek khaas muddat tak zameen hi mein jaye-qarar (dwelling) aur samaan-e-zeist (dwelling and provision) hai”" },
    { number: 25, arabic: "قَالَ فِيهَا تَحْيَوْنَ وَفِيهَا تَمُوتُونَ وَمِنْهَا تُخْرَجُونَ", transliteration: "Qala feeha tahyawna wafeeha tamootoona waminha tukhrajoona", transliterationB: "Qaala feehaa tahyawna wa feehaa tamootoona wa minhaa tukhrajoon", english: "He said: \"Therein shall ye live, and therein shall ye die; but from it shall ye be taken out (at last)", romanUrdu: "Aur farmaya, “wahin tumko jeena aur wahin marna hai aur usi mein se tumko aakhir kaar nikala jayega.”" },
    { number: 26, arabic: "يَٰبَنِىٓ ءَادَمَ قَدْ أَنزَلْنَا عَلَيْكُمْ لِبَاسًۭا يُوَٰرِى سَوْءَٰتِكُمْ وَرِيشًۭا ۖ وَلِبَاسُ ٱلتَّقْوَىٰ ذَٰلِكَ خَيْرٌۭ ۚ ذَٰلِكَ مِنْ ءَايَٰتِ ٱللَّهِ لَعَلَّهُمْ يَذَّكَّرُونَ", transliteration: "Ya banee adama qad anzalna AAalaykum libasan yuwaree sawatikum wareeshan walibasu alttaqwa thalika khayrun thalika min ayati Allahi laAAallahum yaththakkaroona", transliterationB: "Yaa Baneee Aadama qad anzalnaa 'alaikum libaasany yuwaaree saw aatikum wa reeshanw wa libaasut taqwaa zaalika khair; zaalika min Aayaatil laahi la'allahum yaz zakkaroon", english: "O ye Children of Adam! We have bestowed raiment upon you to cover your shame, as well as to be an adornment to you. But the raiment of righteousness,- that is the best. Such are among the Signs of Allah, that they may receive admonition", romanUrdu: "Aey aulad e Adam, humne tumpar libas nazil kiya hai ke tumhare jism ke qabil e sharm hisson ko dhaanke aur tumhare liye jism ki hifazat aur zeenat ka zariya bhi ho. Aur behtareen libas taqwe (piety) ka libas hai. Yeh Allah ki nishaniyon mein se ek nihsani hai, shayad ke log issey sabaq lein" },
    { number: 27, arabic: "يَٰبَنِىٓ ءَادَمَ لَا يَفْتِنَنَّكُمُ ٱلشَّيْطَٰنُ كَمَآ أَخْرَجَ أَبَوَيْكُم مِّنَ ٱلْجَنَّةِ يَنزِعُ عَنْهُمَا لِبَاسَهُمَا لِيُرِيَهُمَا سَوْءَٰتِهِمَآ ۗ إِنَّهُۥ يَرَىٰكُمْ هُوَ وَقَبِيلُهُۥ مِنْ حَيْثُ لَا تَرَوْنَهُمْ ۗ إِنَّا جَعَلْنَا ٱلشَّيَٰطِينَ أَوْلِيَآءَ لِلَّذِينَ لَا يُؤْمِنُونَ", transliteration: "Ya banee adama la yaftinannakumu alshshaytanu kama akhraja abawaykum mina aljannati yanziAAu AAanhuma libasahuma liyuriyahuma sawatihima innahu yarakum huwa waqabeeluhu min haythu la tarawnahum inna jaAAalna alshshayateena awliyaa lillatheena la yuminoona", transliterationB: "Yaa Banee Aadama laa yaftinannnakumush Shaitaanu kamaaa akhraja abawaikum minal Jannati yanzi'u 'anhumaa libaasahumaa liyuriyahumaa saw aatihimaaa; innahoo yaraakum huwa wa qabeeluhoo min haisu laa tarawnahum; innaa ja'alnash Shayaateena awliyaaa'a lillazeena laa yu'minoon", english: "O ye Children of Adam! Let not Satan seduce you, in the same manner as He got your parents out of the Garden, stripping them of their raiment, to expose their shame: for he and his tribe watch you from a position where ye cannot see them: We made the evil ones friends (only) to those without faith", romanUrdu: "Aey bani Adam, aisa na ho ke shaytan tumhein phir usi tarah fitne mein mubtala karde jis tarah usne tumhare walidain ko jannat se nikalwaya tha aur unke libas unpar se utarwa diye thay taa-ke unke sharmgaahein ek dusre ke saamne khole. Woh aur uske saathi tumhein aisi jagah se dekhte hain jahan se tum unhein nahin dekh sakte. In shayateen ko humne un logon ka sarparast bana diya hai jo iman nahin latey" },
    { number: 28, arabic: "وَإِذَا فَعَلُوا۟ فَٰحِشَةًۭ قَالُوا۟ وَجَدْنَا عَلَيْهَآ ءَابَآءَنَا وَٱللَّهُ أَمَرَنَا بِهَا ۗ قُلْ إِنَّ ٱللَّهَ لَا يَأْمُرُ بِٱلْفَحْشَآءِ ۖ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Waitha faAAaloo fahishatan qaloo wajadna AAalayha abaana waAllahu amarana biha qul inna Allaha la yamuru bialfahshai ataqooloona AAala Allahi ma la taAAlamoona", transliterationB: "Wa izaa fa'aloo faahishatan qaaloo wajadnaa 'alaihaaa aabaaa'ana wallaahu amaranaa bihaa; qul innal laaha laa yaamuru bilfahshaaa'i a-taqooloona 'alal laahi mmaa laa ta'lamoon", english: "When they do aught that is shameful, they say: \"We found our fathers doing so\"; and \"Allah commanded us thus\": Say: \"Nay, Allah never commands what is shameful: do ye say of Allah what ye know not", romanUrdu: "Yeh log jab koi sharmnaak kaam karte hain to kehte hain humne apne baap dada ko isi tareeqe par paya hai aur Allah hi ne humein aisa karne ka hukum diya hai. Insey kaho Allah be-hayayi ka hukm kabhi nahin diya karta. Kya tum Allah ka naam lekar woh baatein kehte ho jinke mutaaliq tumhein ilm nahin hai (woh Allah ki taraf se hain)" },
    { number: 29, arabic: "قُلْ أَمَرَ رَبِّى بِٱلْقِسْطِ ۖ وَأَقِيمُوا۟ وُجُوهَكُمْ عِندَ كُلِّ مَسْجِدٍۢ وَٱدْعُوهُ مُخْلِصِينَ لَهُ ٱلدِّينَ ۚ كَمَا بَدَأَكُمْ تَعُودُونَ", transliteration: "Qul amara rabbee bialqisti waaqeemoo wujoohakum AAinda kulli masjidin waodAAoohu mukhliseena lahu alddeena kama badaakum taAAoodoona", transliterationB: "Qul amara Rabbee bilqisti wa aqeemoo wujoohakum 'inda kulli masjidin wad'oohu mukhliseena lahud deen; kamaa bada akum ta'oodoon", english: "Say: \"My Lord hath commanded justice; and that ye set your whole selves (to Him) at every time and place of prayer, and call upon Him, making your devotion sincere as in His sight: such as He created you in the beginning, so shall ye return", romanUrdu: "(Aey Muhammad), insey kaho, mere Rubb ne to raasti o insaaf ka hukum diya hai, aur uska hukum to yeh hai ke har ibadat mein apna rukh theek rakkho aur usi ko pukaaro apne deen ko uske liye khaalis rakh kar, jis tarah usne tumhein ab paida kiya hai usi tarah tum phir paida kiye jaogey" },
    { number: 30, arabic: "فَرِيقًا هَدَىٰ وَفَرِيقًا حَقَّ عَلَيْهِمُ ٱلضَّلَٰلَةُ ۗ إِنَّهُمُ ٱتَّخَذُوا۟ ٱلشَّيَٰطِينَ أَوْلِيَآءَ مِن دُونِ ٱللَّهِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ", transliteration: "Fareeqan hada wafareeqan haqqa AAalayhimu alddalalatu innahumu ittakhathoo alshshayateena awliyaa min dooni Allahi wayahsaboona annahum muhtadoona", transliterationB: "Fareeqan hadaa wa fareeqan haqqa 'alaihimud dalaalah; innahumut takhazush Shayaateena awliyaaa'a min doonil laahi wa yahsaboona annnahum muhtadoon", english: "Some He hath guided: Others have (by their choice) deserved the loss of their way; in that they took the evil ones, in preference to Allah, for their friends and protectors, and think that they receive guidance", romanUrdu: "Ek giroh ko to usne seedha raasta dikha diya hai, magar dusre giroh par gumraahi chaspan hokar reh gayi hai, kyunke unhon ne khuda ke bajaye Shayateen ko apna sarparast bana liya hai aur woh samajh rahey hain ke hum seedhi raah par hain" },
    { number: 31, arabic: "۞ يَٰبَنِىٓ ءَادَمَ خُذُوا۟ زِينَتَكُمْ عِندَ كُلِّ مَسْجِدٍۢ وَكُلُوا۟ وَٱشْرَبُوا۟ وَلَا تُسْرِفُوٓا۟ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْرِفِينَ", transliteration: "Ya banee adama khuthoo zeenatakum AAinda kulli masjidin wakuloo waishraboo wala tusrifoo innahu la yuhibbu almusrifeena", transliterationB: "Yaa Banneee Adama khuzoo zeenatakum 'inda kulli masjidinw wa kuloo washraboo wa laa tusrifoo; innahoo laa yuhibbul musrifeen", english: "O Children of Adam! wear your beautiful apparel at every time and place of prayer: eat and drink: But waste not by excess, for Allah loveth not the wasters", romanUrdu: "Aey bani Adam, har ibadat ke muaqe par apni zeenat se aaraasta raho aur khao peeo aur hadd se tajauz na karo. Allah hadd se badhne walon ko pasand nahin karta" },
    { number: 32, arabic: "قُلْ مَنْ حَرَّمَ زِينَةَ ٱللَّهِ ٱلَّتِىٓ أَخْرَجَ لِعِبَادِهِۦ وَٱلطَّيِّبَٰتِ مِنَ ٱلرِّزْقِ ۚ قُلْ هِىَ لِلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا خَالِصَةًۭ يَوْمَ ٱلْقِيَٰمَةِ ۗ كَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَعْلَمُونَ", transliteration: "Qul man harrama zeenata Allahi allatee akhraja liAAibadihi waalttayyibati mina alrrizqi qul hiya lillatheena amanoo fee alhayati alddunya khalisatan yawma alqiyamati kathalika nufassilu alayati liqawmin yaAAlamoona", transliterationB: "Qul man harrama zeenatal laahil lateee akhraja li'ibaadihee wattaiyibaati minar rizq; qul hiya lillazeena aamanoo fil hayaatid dunyaa khaalisatany Yawmal Qiyaamah; kazaalika nufassihul Aayaati liqawminy ya'lamoon", english: "Say: Who hath forbidden the beautiful (gifts) of Allah, which He hath produced for His servants, and the things, clean and pure, (which He hath provided) for sustenance? Say: They are, in the life of this world, for those who believe, (and) purely for them on the Day of Judgment. Thus do We explain the signs in detail for those who understand", romanUrdu: "(Aey Muhammad), Insey kaho kisne Allah ki us zeenat ko haraam kardiya jisey Allah ne apne bandon ke liye nikala tha aur kisne khuda ki bakshi hui paak cheezein mamnu (forbidden) kardi? Kaho, yeh saari cheezein duniya ki zindagi mein bhi iman laney walon ke liye hain, aur qayamat ke roz to khaalisatan unhi ke liye hongi. Is tarah hum apni baatein saaf saaf bayaan karte hain un logon ke liye jo ilm rakhne waley hain" },
    { number: 33, arabic: "قُلْ إِنَّمَا حَرَّمَ رَبِّىَ ٱلْفَوَٰحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَٱلْإِثْمَ وَٱلْبَغْىَ بِغَيْرِ ٱلْحَقِّ وَأَن تُشْرِكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَٰنًۭا وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Qul innama harrama rabbiya alfawahisha ma thahara minha wama batana waalithma waalbaghya bighayri alhaqqi waan tushrikoo biAllahi ma lam yunazzil bihi sultanan waan taqooloo AAala Allahi ma la taAAlamoona", transliterationB: "Qul innamaa harrama Rabbiyal fawaahisha maa zahara minhaa wa maa bataa wal isma walbaghya bighairil haqqi wa an tushrikoo billaahi maa lam yunazzil bihee sultaananw wa an taqooloo 'alal laahi maa laa ta'lamoon", english: "Say: the things that my Lord hath indeed forbidden are: shameful deeds, whether open or secret; sins and trespasses against truth or reason; assigning of partners to Allah, for which He hath given no authority; and saying things about Allah of which ye have no knowledge", romanUrdu: "(Aey Muhammad), insey kaho ke mere Rubb ne jo cheezein haraam ki hain woh to yeh hain : besharmi ke kaam khwa khuley hon ya chupey, aur gunaah aur haqq ke khilaf ziyadati, aur yeh ke Allah ke saath tum kisi ko shareek karo jiske liye usne koi sanad nazil nahin ki, aur yeh ke Allah ke naam par koi aisi baat kaho jiske mutaaliq tumhein ilm na ho ke woh haqeeqat mein usi ne farmayi hai" },
    { number: 34, arabic: "وَلِكُلِّ أُمَّةٍ أَجَلٌۭ ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَأْخِرُونَ سَاعَةًۭ ۖ وَلَا يَسْتَقْدِمُونَ", transliteration: "Walikulli ommatin ajalun faitha jaa ajaluhum la yastakhiroona saAAatan wala yastaqdimoona", transliterationB: "Wa likulli ummatin ajalun fa izaa jaaa'a ajaluhum laa yastaakhiroona saa'atanw wa laa yastaqdimoon", english: "To every people is a term appointed: when their term is reached, not an hour can they cause delay, nor (an hour) can they advance (it in anticipation)", romanUrdu: "Har qaum ke liye mohlat ki ek muddat muqarrar hai, phir jab kisi qaum ki muddat aan puri hoti hai to ek ghadi bhar ki takheer o taqdeem bhi nahin hoti" },
    { number: 35, arabic: "يَٰبَنِىٓ ءَادَمَ إِمَّا يَأْتِيَنَّكُمْ رُسُلٌۭ مِّنكُمْ يَقُصُّونَ عَلَيْكُمْ ءَايَٰتِى ۙ فَمَنِ ٱتَّقَىٰ وَأَصْلَحَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ", transliteration: "Ya banee adama imma yatiyannakum rusulun minkum yaqussoona AAalaykum ayatee famani ittaqa waaslaha fala khawfun AAalayhim wala hum yahzanoona", transliterationB: "yaa Banee Aadama immaa yaatiyannakum Rusulum minkum yaqussoona 'alaikum Aayaatee famanit taqaa wa aslaha falaa khawfun 'alaihim wa laa hum yahzanoon", english: "O ye Children of Adam! whenever there come to you messengers from amongst you, rehearsing My signs unto you,- those who are righteous and mend (their lives),- on them shall be no fear nor shall they grieve", romanUrdu: "(Aur yeh baat Allah ne aagaaz e takhleeq hi mein saaf farma di thi ke) aey bani Adam, yaad rakkho, agar tumhare paas khud tumhi mein se aisey Rasool aayein jo tumhein meri aayat suna rahey hon, to jo koi nafarmani se bachega aur apne rawayye ki islaah karlega uske liye kisi khauf aur ranjj ka mauqa nahin hai" },
    { number: 36, arabic: "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Waallatheena kaththaboo biayatina waistakbaroo AAanha olaika ashabu alnnari hum feeha khalidoona", transliterationB: "Wallazeena kazzaboo bi Aayaatinaa wastakbaroo 'anhhaaa ulaaa'ika Ashaabun naari hum feehaa khaalidoon", english: "But those who reject Our signs and treat them with arrogance,- they are companions of the Fire, to dwell therein (for ever)", romanUrdu: "Aur jo log hamari aayat ko jhutlayenge aur unke muqable mein sarkashi bartenge wahi ehle dozakh hongey jahan woh hamesha rahenge" },
    { number: 37, arabic: "فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِـَٔايَٰتِهِۦٓ ۚ أُو۟لَٰٓئِكَ يَنَالُهُمْ نَصِيبُهُم مِّنَ ٱلْكِتَٰبِ ۖ حَتَّىٰٓ إِذَا جَآءَتْهُمْ رُسُلُنَا يَتَوَفَّوْنَهُمْ قَالُوٓا۟ أَيْنَ مَا كُنتُمْ تَدْعُونَ مِن دُونِ ٱللَّهِ ۖ قَالُوا۟ ضَلُّوا۟ عَنَّا وَشَهِدُوا۟ عَلَىٰٓ أَنفُسِهِمْ أَنَّهُمْ كَانُوا۟ كَٰفِرِينَ", transliteration: "Faman athlamu mimmani iftara AAala Allahi kathiban aw kaththaba biayatihi olaika yanaluhum naseebuhum mina alkitabi hatta itha jaathum rusuluna yatawaffawnahum qaloo ayna ma kuntum tadAAoona min dooni Allahi qaloo dalloo AAanna washahidoo AAala anfusihim annahum kanoo kafireena", transliterationB: "Faman azlamu mimmanif taraa 'alal laahi kaziban aw kazzaba bi Aayaatih; ulaaa'ika yanaaluhum naseebuhum minal Kitaab; hataaa izaa jaaa'at hum rusulunaa yatawaf fawnahum qaalooo aina maa kuntum tad'oonaa min doonil laahi qaaloo dalloo 'annaa wa shahidoo 'alaaa anfusihim annahum kaanoo kaafieen", english: "Who is more unjust than one who invents a lie against Allah or rejects His Signs? For such, their portion appointed must reach them from the Book (of decrees): until, when our messengers (of death) arrive and take their souls, they say: \"Where are the things that ye used to invoke besides Allah?\" They will reply, \"They have left us in the lurch,\" And they will bear witness against themselves, that they had rejected Allah", romanUrdu: "Zahir hai ke ussey bada zalim aur kaun hoga jo biklul jhooti baatein ghadh kar Allah ki taraf mansooq karey ya Allah ki sacchi aayat ko jhutlaye? Aisey log apne nawishta e taqdeer ke mutabiq apna hissa paatey rahenge, yahan tak ke woh ghadi aa jayegi jab hamare bheje huey Farishtey unki roohein(souls) qabz karne ke liye pahunchenge. Us waqt woh unse puchenge ke batao ab kahan hain tumhare woh mabood jinko tum khuda ke bajaye pukarte thay? Woh kahenge ke, “Sab humse ghum ho gaye” aur woh khud apne khilaaf gawahi denge ke hum waqayi munkir e haqq thay" },
    { number: 38, arabic: "قَالَ ٱدْخُلُوا۟ فِىٓ أُمَمٍۢ قَدْ خَلَتْ مِن قَبْلِكُم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ فِى ٱلنَّارِ ۖ كُلَّمَا دَخَلَتْ أُمَّةٌۭ لَّعَنَتْ أُخْتَهَا ۖ حَتَّىٰٓ إِذَا ٱدَّارَكُوا۟ فِيهَا جَمِيعًۭا قَالَتْ أُخْرَىٰهُمْ لِأُولَىٰهُمْ رَبَّنَا هَٰٓؤُلَآءِ أَضَلُّونَا فَـَٔاتِهِمْ عَذَابًۭا ضِعْفًۭا مِّنَ ٱلنَّارِ ۖ قَالَ لِكُلٍّۢ ضِعْفٌۭ وَلَٰكِن لَّا تَعْلَمُونَ", transliteration: "Qala odkhuloo fee omamin qad khalat min qablikum mina aljinni waalinsi fee alnnari kullama dakhalat ommatun laAAanat okhtaha hatta itha iddarakoo feeha jameeAAan qalat okhrahum lioolahum rabbana haolai adalloona faatihim AAathaban diAAfan mina alnnari qala likullin diAAfun walakin la taAAlamoona", transliterationB: "Qaalad khuloo feee umamin qad khalat min qablikum minal jinni wal insifin naari kullamaa dakhalat ummatul la'anat ukhtahaa hattaaa izad daarakoo feehaa jamee'an qaalat ukhraahum li oolaahum Rabbannaa haaa'u laaa'i adalloonaa fa aatihim 'azaaban di'fam minan naari qaala likullin di funw wa laakil laa ta'lamoon", english: "He will say: \"Enter ye in the company of the peoples who passed away before you - men and jinns, - into the Fire.\" Every time a new people enters, it curses its sister-people (that went before), until they follow each other, all into the Fire. Saith the last about the first: \"Our Lord! it is these that misled us: so give them a double penalty in the Fire.\" He will say: \"Doubled for all\": but this ye do not understand", romanUrdu: "Allah farmayega jao, tum bhi usi jahannum mein chale jao jismein tumse pehle guzrey huey giroh Jinn o Ins (Insaan) jaa chuke hain. Har giroh jab jahannum mein dakhil hoga to apne peshrow giroh(that went before it) par laanat karta hua dakhil hoga, hatta ke jab sab wahan jamaa ho jayenge to har baad wala giroh pehle giroh ke haqq mein kahega ke aey Rubb, yeh log thay jinhon ne humko gumraah kiya, lihaza inhein aag ka dohra azaab de. Jawab mein irshad hoga, har ek ke liye dohra hi azaab hai magar tum jantey nahin ho" },
    { number: 39, arabic: "وَقَالَتْ أُولَىٰهُمْ لِأُخْرَىٰهُمْ فَمَا كَانَ لَكُمْ عَلَيْنَا مِن فَضْلٍۢ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْسِبُونَ", transliteration: "Waqalat oolahum liokhrahum fama kana lakum AAalayna min fadlin fathooqoo alAAathaba bima kuntum taksiboona", transliterationB: "Wa qaalat oolaahum li ukhraahum famaa kaana lakum 'alainaa min fadlin fazooqul azaaba bimaa kuntum taksiboon", english: "Then the first will say to the last: \"See then! No advantage have ye over us; so taste ye of the penalty for all that ye did", romanUrdu: "Aur pehla giroh dusre giroh se kahega ke (agar hum qaabil e ilzam thay) to tumhi ko humpar kaunsi fazilat haasil thi, ab apni kamayi ke nateejey mein azaab ka maza chakkho" },
    { number: 40, arabic: "إِنَّ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَا لَا تُفَتَّحُ لَهُمْ أَبْوَٰبُ ٱلسَّمَآءِ وَلَا يَدْخُلُونَ ٱلْجَنَّةَ حَتَّىٰ يَلِجَ ٱلْجَمَلُ فِى سَمِّ ٱلْخِيَاطِ ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُجْرِمِينَ", transliteration: "Inna allatheena kaththaboo biayatina waistakbaroo AAanha la tufattahu lahum abwabu alssamai wala yadkhuloona aljannata hatta yalija aljamalu fee sammi alkhiyati wakathalika najzee almujrimeena", transliterationB: "Innal lazeena kazzaboo bi Aayaatinaa wastakbaroo 'anhaa laa tufattahu lahum ahwaabus samaaa'i wa laa yadkhuloonal jannata hattaa yalijal jamalu fee sammil khiyaat; wa kazaalika najzil mujrimeen", english: "To those who reject Our signs and treat them with arrogance, no opening will there be of the gates of heaven, nor will they enter the garden, until the camel can pass through the eye of the needle: Such is Our reward for those in sin", romanUrdu: "Yaqeen jaano, jin logon ne hamari aayat ko jhutlaya hai aur inke muqable mein sarkashi ki hai unke liye aasman ke darwaze hargiz na kholey jayenge. Unka jannat mein jana utna hi namumkin hai jitna suii (needle) ke naake se ount(camel) ka guzarna. Mujreemon ko hamare haan aisa hi badla mila karta hai" },
    { number: 41, arabic: "لَهُم مِّن جَهَنَّمَ مِهَادٌۭ وَمِن فَوْقِهِمْ غَوَاشٍۢ ۚ وَكَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ", transliteration: "Lahum min jahannama mihadun wamin fawqihim ghawashin wakathalika najzee alththalimeena", transliterationB: "Lahum min jahannama mihaadunw wa min fawqihim ghawaash; wa kazaalika najziz zaalimeen", english: "For them there is Hell, as a couch (below) and folds and folds of covering above: such is Our requital of those who do wrong", romanUrdu: "Unke liye to jahannum ka bichona hoga aur jahannum hi ka oadna. Yeh hai woh jaza jo hum zalimon ko diya karte hain" },
    { number: 42, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ لَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَآ أُو۟لَٰٓئِكَ أَصْحَٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَٰلِدُونَ", transliteration: "Waallatheena amanoo waAAamiloo alssalihati la nukallifu nafsan illa wusAAaha olaika ashabu aljannati hum feeha khalidoona", transliterationB: "Wallazeena aamanoo wa 'amilus saalihaati la nukallifu nafsan illaa wus'ahaaa ulaaa'ika Ashaabul jannati hum feehaa khaalidoon", english: "But those who believe and work righteousness,- no burden do We place on any soul, but that which it can bear,- they will be Companions of the Garden, therein to dwell (for ever)", romanUrdu: "Ba-khilaf iske jin logon ne hamari aayat ko maan liya hai aur acchey kaam kiye hain aur is baab mein hum har ek ko uski istetaat (capability) hi ke mutaabiq zimmedar thehrate hain. Woh ehle jannat hain jahan woh hamesha rahengey" },
    { number: 43, arabic: "وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّۢ تَجْرِى مِن تَحْتِهِمُ ٱلْأَنْهَٰرُ ۖ وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى هَدَىٰنَا لِهَٰذَا وَمَا كُنَّا لِنَهْتَدِىَ لَوْلَآ أَنْ هَدَىٰنَا ٱللَّهُ ۖ لَقَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ ۖ وَنُودُوٓا۟ أَن تِلْكُمُ ٱلْجَنَّةُ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "WanazaAAna ma fee sudoorihim min ghillin tajree min tahtihimu alanharu waqaloo alhamdu lillahi allathee hadana lihatha wama kunna linahtadiya lawla an hadana Allahu laqad jaat rusulu rabbina bialhaqqi wanoodoo an tilkumu aljannatu oorithtumooha bima kuntum taAAmaloona", transliterationB: "Wa naza'naa maa fee sudoorihim min ghillin tajree min tahtihimul anhaaru wa qaalul hamdu lillaahil lazee hadaanaa lihaaza wa maa kunna linahtadiya law laaa ann hadaanal laahu laqad jaaa'at Rusulu Rabbinaa bilhaqq; wa noodoo an tilkumul jannnatu ooristumoohaa bimaa kuntum ta'maloon", english: "And We shall remove from their hearts any lurking sense of injury;- beneath them will be rivers flowing;- and they shall say: \"Praise be to Allah, who hath guided us to this (felicity): never could we have found guidance, had it not been for the guidance of Allah: indeed it was the truth, that the messengers of our Lord brought unto us.\" And they shall hear the cry: \"Behold! the garden before you! Ye have been made its inheritors, for your deeds (of righteousness)", romanUrdu: "Unke dilon mein ek dusre ke khilaf jo kuch kadurat (rancour) hogi usey hum nikal denge, unke nichey nehrein behti hongi, aur woh kahenge ke “taareef khuda hi ke liye hai jisne humein yeh raasta dikhaya, hum khud raah na paa sakte thay agar khuda hamari rehnumayi na karta. Hamare Rubb ke bheje huey Rasool waqayi Haqq hi lekar aaye thay”. Us waqt nida (voice) aayegi ke “ yeh jannat jiske tum waris banaye gaye ho tumhein un aamal ke badle mein mili hai jo tum karte rahey thay”" },
    { number: 44, arabic: "وَنَادَىٰٓ أَصْحَٰبُ ٱلْجَنَّةِ أَصْحَٰبَ ٱلنَّارِ أَن قَدْ وَجَدْنَا مَا وَعَدَنَا رَبُّنَا حَقًّۭا فَهَلْ وَجَدتُّم مَّا وَعَدَ رَبُّكُمْ حَقًّۭا ۖ قَالُوا۟ نَعَمْ ۚ فَأَذَّنَ مُؤَذِّنٌۢ بَيْنَهُمْ أَن لَّعْنَةُ ٱللَّهِ عَلَى ٱلظَّٰلِمِينَ", transliteration: "Wanada ashabu aljannati ashaba alnnari an qad wajadna ma waAAadana rabbuna haqqan fahal wajadtum ma waAAada rabbukum haqqan qaloo naAAam faaththana muaththinun baynahum an laAAnatu Allahi AAala alththalimeena", transliterationB: "Wa naadaa Ashaabul jannati ashaaban Naari an qad wajadnaa maa wa'adannaa Rabbunaa haqqan fahal wajattum maa wa'ada Rabbukum haqqan qaaloo na'am; fa azzana mu'azzinum bainahum al la'natul laahi 'alaz zaalimeen", english: "The Companions of the Garden will call out to the Companions of the Fire: \"We have indeed found the promises of our Lord to us true: Have you also found Your Lord's promises true?\" They shall say, \"Yes\"; but a crier shall proclaim between them: \"The curse of Allah is on the wrong-doers", romanUrdu: "Phir yeh jannat ke log dozakh walon se pukar kar kahenge, “ humne un sarey waadon ko theek paa liya jo hamare Rubb ne humse kiye thay, kya tumne bhi un waadon ko theek paya jo tumhare Rubb ne kiye thay?” Woh jawab denge “haan” tab ek pukarne wala unke darmiyan pukarega ke “ khuda ki laanat un zalimon par" },
    { number: 45, arabic: "ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًۭا وَهُم بِٱلْءَاخِرَةِ كَٰفِرُونَ", transliteration: "Allatheena yasuddoona AAan sabeeli Allahi wayabghoonaha AAiwajan wahum bialakhirati kafiroona", transliterationB: "Allazeena yasuddoona 'an sabeelil laahi wa yabghoo nahaa 'iwajanw wa hum bil Aakhirati kaafiroon", english: "Those who would hinder (men) from the path of Allah and would seek in it something crooked: they were those who denied the Hereafter", romanUrdu: "Jo Allah ke rastey se logon ko roakte aur usey tedha karna chahte thay aur aakhirat ke munkir thay”" },
    { number: 46, arabic: "وَبَيْنَهُمَا حِجَابٌۭ ۚ وَعَلَى ٱلْأَعْرَافِ رِجَالٌۭ يَعْرِفُونَ كُلًّۢا بِسِيمَىٰهُمْ ۚ وَنَادَوْا۟ أَصْحَٰبَ ٱلْجَنَّةِ أَن سَلَٰمٌ عَلَيْكُمْ ۚ لَمْ يَدْخُلُوهَا وَهُمْ يَطْمَعُونَ", transliteration: "Wabaynahuma hijabun waAAala alaAArafi rijalun yaAArifoona kullan biseemahum wanadaw ashaba aljannati an salamun AAalaykum lam yadkhulooha wahum yatmaAAoona", transliterationB: "Wa bainahumaa hijaab; wa 'alal A'raafi rijaaluny ya'rifoona kullam biseemaahum; wa naadaw Ashaabal jannati an salaamun 'alaikum; lam yadkhuloohaa wa hum yatma'oon", english: "Between them shall be a veil, and on the heights will be men who would know every one by his marks: they will call out to the Companions of the Garden, \"peace on you\": they will not have entered, but they will have an assurance (thereof)", romanUrdu: "In dono girohon ke darmiyan ek oat (barrier) hayal hogi jiski bulandiyon (Araaf) par kuch aur log honge yeh har ek ko uske kiyafa (marks) se pehchanenge aur jannat walon se pukaar kar kahenge ke “salamati ho tumpar”. Yeh log jannat mein dakhil to nahin huey magar uske umeedwar honge”" },
    { number: 47, arabic: "۞ وَإِذَا صُرِفَتْ أَبْصَٰرُهُمْ تِلْقَآءَ أَصْحَٰبِ ٱلنَّارِ قَالُوا۟ رَبَّنَا لَا تَجْعَلْنَا مَعَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Waitha surifat absaruhum tilqaa ashabi alnnari qaloo rabbana la tajAAalna maAAa alqawmi alththalimeena", transliterationB: "Wa izaa surifat absaaruhum tilqaaa'a Ashaabin Naari qaalo Rabbanaa laa taj'alnaa ma'al qawmiz zaalimneen", english: "When their eyes shall be turned towards the Companions of the Fire, they will say: \"Our Lord! send us not to the company of the wrong-doers", romanUrdu: "Aur jab unki nigahein dozakh walon ki taraf phirengi to kahenge, “Aey Rubb! Humein in zalim logon mein shamil na kijiyo”" },
    { number: 48, arabic: "وَنَادَىٰٓ أَصْحَٰبُ ٱلْأَعْرَافِ رِجَالًۭا يَعْرِفُونَهُم بِسِيمَىٰهُمْ قَالُوا۟ مَآ أَغْنَىٰ عَنكُمْ جَمْعُكُمْ وَمَا كُنتُمْ تَسْتَكْبِرُونَ", transliteration: "Wanada ashabu alaAArafi rijalan yaAArifoonahum biseemahum qaloo ma aghna AAankum jamAAukum wama kuntum tastakbiroona", transliterationB: "Wa naadaaa Ashaabul A'raffi rijaalany ya'rifoonahum biseemaahum qaaloo maaa aghnaa 'ankum jam'ukum wa maa kuntum tastakbiroon", english: "The men on the heights will call to certain men whom they will know from their marks, saying: \"Of what profit to you were your hoards and your arrogant ways", romanUrdu: "Phir yeh Araaf ke log dozakh ki chandh badi badi shakhsiyaton(personalities) ko unki alamaton se pehchan kar pukarenge ke “dekh liya tumne, aaj na tumhare jatthey (gatherings/numbers) tumhare kisi kaam aaye aur na woh saaz o samaan jinko tum badi cheez samajhte thay" },
    { number: 49, arabic: "أَهَٰٓؤُلَآءِ ٱلَّذِينَ أَقْسَمْتُمْ لَا يَنَالُهُمُ ٱللَّهُ بِرَحْمَةٍ ۚ ٱدْخُلُوا۟ ٱلْجَنَّةَ لَا خَوْفٌ عَلَيْكُمْ وَلَآ أَنتُمْ تَحْزَنُونَ", transliteration: "Ahaolai allatheena aqsamtum la yanaluhumu Allahu birahmatin odkhuloo aljannata la khawfun AAalaykum wala antum tahzanoona", transliterationB: "A haaa'ulaaa'il lazeena aqsamtum laa yanaaluhumul laahu birahma; udkhulul Jannata laa khawfun 'alaikum wa laaa antum tahzanoon", english: "Behold! are these not the men whom you swore that Allah with His Mercy would never bless? Enter ye the Garden: no fear shall be on you, nor shall ye grieve", romanUrdu: "Aur kya yeh ehle jannat wahi log nahin hain jinke mutaaliq tum kasamein kha kha kar kehte thay ke inko to khuda apni rehmat mein se kuch bhi na dega? Aaj inhi se kaha gaya ke dakhil ho jao jannat mein, tumhare liye na khauf hai na ranjj”" },
    { number: 50, arabic: "وَنَادَىٰٓ أَصْحَٰبُ ٱلنَّارِ أَصْحَٰبَ ٱلْجَنَّةِ أَنْ أَفِيضُوا۟ عَلَيْنَا مِنَ ٱلْمَآءِ أَوْ مِمَّا رَزَقَكُمُ ٱللَّهُ ۚ قَالُوٓا۟ إِنَّ ٱللَّهَ حَرَّمَهُمَا عَلَى ٱلْكَٰفِرِينَ", transliteration: "Wanada ashabu alnari ashaba aljannati an afeedoo AAalayna mina almai aw mimma razaqakumu Allahu qaloo inna Allaha harramahuma AAala alkafireena", transliterationB: "Wa naadaaa Ashaabun Naari Ashaabal jannati an afeedoo 'alainaa minal maaa'i aw mimma razaqakumul laah; qaaloo innal laaha harrama humaa 'alal kaafireen", english: "The Companions of the Fire will call to the Companions of the Garden: \"Pour down to us water or anything that Allah doth provide for your sustenance.\" They will say: \"Both these things hath Allah forbidden to those who rejected Him", romanUrdu: "Aur dozakh ke log jannat walon ko pukarenge ke kuch thoda sa pani humpar daal do ya jo rizq Allah ne tumhein diya hai usi mein se kuch phenk do. Woh jawab denge ke “Allah ne yeh dono cheezein un munkireen e haqq par haraam kardi hain" },
    { number: 51, arabic: "ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَهُمْ لَهْوًۭا وَلَعِبًۭا وَغَرَّتْهُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ نَنسَىٰهُمْ كَمَا نَسُوا۟ لِقَآءَ يَوْمِهِمْ هَٰذَا وَمَا كَانُوا۟ بِـَٔايَٰتِنَا يَجْحَدُونَ", transliteration: "Allatheena ittakhathoo deenahum lahwan walaAAiban wagharrathumu alhayatu alddunya faalyawma nansahum kama nasoo liqaa yawmihim hatha wama kanoo biayatina yajhadoona", transliterationB: "Allazeenat takhazoo deenahu lahwanw wa la'i-banw wa gharrat humul hayaatud dunyaa; fal Yawma nnannsaahum kamaa nasoo liqaaa'a Yawmihim haazaa wa maa kaanoo bi aayaatinaa yajhadoon", english: "Such as took their religion to be mere amusement and play, and were deceived by the life of the world.\" That day shall We forget them as they forgot the meeting of this day of theirs, and as they were wont to reject Our signs", romanUrdu: "Jinhon ne apne deen ko khel aur tafree bana liya tha. Aur jinhein duniya ki zindagi ne fareb mein mubtila kar rakkha tha. Allah farmata hai ke aaj hum bhi unhein usi tarah bhula denge jis tarah woh is din ki mulaqat ko bhoole rahey aur hamari aayaton ka inkar karte rahey”" },
    { number: 52, arabic: "وَلَقَدْ جِئْنَٰهُم بِكِتَٰبٍۢ فَصَّلْنَٰهُ عَلَىٰ عِلْمٍ هُدًۭى وَرَحْمَةًۭ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Walaqad jinahum bikitabin fassalnahu AAala AAilmin hudan warahmatan liqawmin yuminoona", transliterationB: "Wa laqad ji'naahum bi Kitaabin fassalnaahu 'alaa 'ilmin hudanw wa rahmatal liqawminy-yu'miinoon", english: "For We had certainly sent unto them a Book, based on knowledge, which We explained in detail,- a guide and a mercy to all who believe", romanUrdu: "Hum in logon ke paas ek aisi kitab le aaye hain jisko humne ilm ki bina par mufassal (expounded) banaya hai aur jo iman laney walon ke liye hidayat aur rehmat hai" },
    { number: 53, arabic: "هَلْ يَنظُرُونَ إِلَّا تَأْوِيلَهُۥ ۚ يَوْمَ يَأْتِى تَأْوِيلُهُۥ يَقُولُ ٱلَّذِينَ نَسُوهُ مِن قَبْلُ قَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ فَهَل لَّنَا مِن شُفَعَآءَ فَيَشْفَعُوا۟ لَنَآ أَوْ نُرَدُّ فَنَعْمَلَ غَيْرَ ٱلَّذِى كُنَّا نَعْمَلُ ۚ قَدْ خَسِرُوٓا۟ أَنفُسَهُمْ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ", transliteration: "Hal yanthuroona illa taweelahu yawma yatee taweeluhu yaqoolu allatheena nasoohu min qablu qad jaat rusulu rabbina bialhaqqi fahal lana min shufaAAaa fayashfaAAoo lana aw nuraddu fanaAAmala ghayra allathee kunna naAAmalu qad khasiroo anfusahum wadalla AAanhum ma kanoo yaftaroona", transliterationB: "hal yanzuroona illaa taa weelah; yawma yaatee taaweeluhoo yaqoolul lazeena nasoohu min qablu qad jaaa'at Rusulu Rabbinaa bilhaqq; fahal lanaa min shufa'aaa'a fa yashfa'oo lanaaa aw nuraddu fana'mala ghairal lazee kunnaa na'mal; qad khasirooo anfusahum wa dalla 'anhum maa kaanoo yaftaroon", english: "Do they just wait for the final fulfilment of the event? On the day the event is finally fulfilled, those who disregarded it before will say: \"The messengers of our Lord did indeed bring true (tidings). Have we no intercessors now to intercede on our behalf? Or could we be sent back? then should we behave differently from our behaviour in the past.\" In fact they will have lost their souls, and the things they invented will leave them in the lurch", romanUrdu: "Ab kya yeh log iske siwa kisi aur baat ke muntazir hain ke woh anjaam saamne aa jaye jiski yeh kitab khabar de rahi hai? Jis roz woh anjaam saamne aa gaya to wahi log jinhon ne usey nazar-andaz kardiya tha kahenge ke “waqayi hamare Rubb ke Rasool haqq lekar aaye thay, phir kya ab humein kuch sifarishi milenge jo hamare haqq mein sifarish karein? Ya humein dobara wapas hi bhej diya jaye taa-ke jo kuch hum pehle karte thay uske bajaye ab dusre tareeqe par kaam karke dikhayein”. Unhon ne apne aap ko khasare (nuksaan) mein daal diya aur woh sarey jhoot jo unhon ne tasneef kar rakkhey thay aaj unse ghum ho gaye" },
    { number: 54, arabic: "إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍۢ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ يُغْشِى ٱلَّيْلَ ٱلنَّهَارَ يَطْلُبُهُۥ حَثِيثًۭا وَٱلشَّمْسَ وَٱلْقَمَرَ وَٱلنُّجُومَ مُسَخَّرَٰتٍۭ بِأَمْرِهِۦٓ ۗ أَلَا لَهُ ٱلْخَلْقُ وَٱلْأَمْرُ ۗ تَبَارَكَ ٱللَّهُ رَبُّ ٱلْعَٰلَمِينَ", transliteration: "Inna rabbakumu Allahu allathee khalaqa alssamawati waalarda fee sittati ayyamin thumma istawa AAala alAAarshi yughshee allayla alnnahara yatlubuhu hatheethan waalshshamsa waalqamara waalnnujooma musakhkharatin biamrihi ala lahu alkhalqu waalamru tabaraka Allahu rabbu alAAalameena", transliterationB: "Inna Rabbakkumul laahul lazee khalaqas sammaawaati wal arda fee sittati qiyaamin summmas tawaa 'alal 'arshi yughshil lailan nahaara yatlu buhoo haseesanw washshamsa walqamara wannujooma musakhkharaatim bi amrih; alaa lahul khalqu wal-amr; tabaarakal laahu Rabbul 'aalameen", english: "Your Guardian-Lord is Allah, Who created the heavens and the earth in six days, and is firmly established on the throne (of authority): He draweth the night as a veil o'er the day, each seeking the other in rapid succession: He created the sun, the moon, and the stars, (all) governed by laws under His command. Is it not His to create and to govern? Blessed be Allah, the Cherisher and Sustainer of the worlds", romanUrdu: "Dar haqeeqat tumhara Rubb Allah hi hai jisne aasman aur zameen ko chey( six) dino mein paida kiya, phir apne takht e sultanat par jalwa farma hua, jo raat ko din par dhank deta hai aur phir din raat ke pichey dauda chala aata hai, jisne Suraj aur chand aur taarey paida kiye sab uske farmaan ke tabeh hain. Khabardar raho! Usi ki khalq (creation) hai aur usi ka amr(command) hai. Bada ba-barakat hai Allah, sarey jahaano ka maalik o parwardigar" },
    { number: 55, arabic: "ٱدْعُوا۟ رَبَّكُمْ تَضَرُّعًۭا وَخُفْيَةً ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُعْتَدِينَ", transliteration: "OdAAoo rabbakum tadarruAAan wakhufyatan innahu la yuhibbu almuAAtadeena", transliterationB: "Ud'oo Rabbakum tadarru'anw wa khufyah; innahoo laa yuhibbul mu'tadeen", english: "Call on your Lord with humility and in private: for Allah loveth not those who trespass beyond bounds", romanUrdu: "Apne Rubb ko pukaro gidgidate (with humility) huey aur chupke chupke. Yakeenan woh hadd se guzarne walon ko pasand nahin karta" },
    { number: 56, arabic: "وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَٰحِهَا وَٱدْعُوهُ خَوْفًۭا وَطَمَعًا ۚ إِنَّ رَحْمَتَ ٱللَّهِ قَرِيبٌۭ مِّنَ ٱلْمُحْسِنِينَ", transliteration: "Wala tufsidoo fee alardi baAAda islahiha waodAAoohu khawfan watamaAAan inna rahmata Allahi qareebun mina almuhsineena", transliterationB: "Wa laa tufsidoo fil ardi ba'da islaahihaa wad'oohu khawfanw wa tama'aa; inna rahmatal laahi qareebum minal muhsineen", english: "Do no mischief on the earth, after it hath been set in order, but call on Him with fear and longing (in your hearts): for the Mercy of Allah is (always) near to those who do good", romanUrdu: "Zameen mein fasaad barpa na karo jabke uski islaah ho chuki hai aur khuda hi ko pukaro khauff ke saath aur tama (umeed) ke saath. Yaqeenan Allah ki rehmat neik kirdaar (who do good) logon se qareeb hai" },
    { number: 57, arabic: "وَهُوَ ٱلَّذِى يُرْسِلُ ٱلرِّيَٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۖ حَتَّىٰٓ إِذَآ أَقَلَّتْ سَحَابًۭا ثِقَالًۭا سُقْنَٰهُ لِبَلَدٍۢ مَّيِّتٍۢ فَأَنزَلْنَا بِهِ ٱلْمَآءَ فَأَخْرَجْنَا بِهِۦ مِن كُلِّ ٱلثَّمَرَٰتِ ۚ كَذَٰلِكَ نُخْرِجُ ٱلْمَوْتَىٰ لَعَلَّكُمْ تَذَكَّرُونَ", transliteration: "Wahuwa allathee yursilu alrriyaha bushran bayna yaday rahmatihi hatta itha aqallat sahaban thiqalan suqnahu libaladin mayyitin faanzalna bihi almaa faakhrajna bihi min kulli alththamarati kathalika nukhriju almawta laAAallakum tathakkaroona", transliterationB: "Wa Huwal lazee yursilur riyaaha bushram baina yadai rahmatihee hattaaa izaaa aqallat sahaaban siqaalan suqnaahu libaladim maiyitin fa annzalnaa bihil maaa'a fa akhrajnaa bihee minn kullis samaraat; kazaalika nukhrijul mawtaa la'allakum tazakkaroon", english: "It is He Who sendeth the winds like heralds of glad tidings, going before His mercy: when they have carried the heavy-laden clouds, We drive them to a land that is dead, make rain to descend thereon, and produce every kind of harvest therewith: thus shall We raise up the dead: perchance ye may remember", romanUrdu: "Aur woh Allah hi hai jo hawaon ko apni rehmat ke aagey aagey khush-khabri liye huey bhejta hai, phir jab woh pani se ladey huey badal utha leti hain to unhein kisi murda sar-zameen ki taraf harakat deta hai, aur wahan meh (barish) barsa kar (usi mari hui zameen se) tarah tarah ke phal nikal laata hai. Dekho, is tarah hum murdon ko halat e maut se nikalte hain, shayad ke tum is mushahide se sabaq lo" },
    { number: 58, arabic: "وَٱلْبَلَدُ ٱلطَّيِّبُ يَخْرُجُ نَبَاتُهُۥ بِإِذْنِ رَبِّهِۦ ۖ وَٱلَّذِى خَبُثَ لَا يَخْرُجُ إِلَّا نَكِدًۭا ۚ كَذَٰلِكَ نُصَرِّفُ ٱلْءَايَٰتِ لِقَوْمٍۢ يَشْكُرُونَ", transliteration: "Waalbaladu alttayyibu yakhruju nabatuhu biithni rabbihi waallathee khabutha la yakhruju illa nakidan kathalika nusarrifu alayati liqawmin yashkuroona", transliterationB: "Walbaladut taiyibu yakhruju nabaatuhoo bi-izni Rabbihee wallazee khabusa laa yakhruju illaa nakidaa; kazaalika nusarriful Aayaati liqawminy yashkuroon", english: "From the land that is clean and good, by the will of its Cherisher, springs up produce, (rich) after its kind: but from the land that is bad, springs up nothing but that which is niggardly: thus do we explain the signs by various (symbols) to those who are grateful", romanUrdu: "Jo zameen acchi hoti hai woh apne Rubb ke hukum se khoob phal phool lati hai aur jo zameen kharab hoti hai ussey naqis (poor) paidawar ke siwa kuch nahin nikalta. Is tarah hum nishaniyon ko baar baar pesh karte hain un logon ke liye jo shukarguzar honay waley hain" },
    { number: 59, arabic: "لَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍۢ", transliteration: "Laqad arsalna noohan ila qawmihi faqala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu innee akhafu AAalaykum AAathaba yawmin AAatheemin", transliterationB: "Laqad arsalnaa noohan ilaa qawmihee faqaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuhoo inneee akhaafu 'alaikum 'azaaba Yawmin 'Azeem", english: "We sent Noah to his people. He said: \"O my people! worship Allah! ye have no other god but Him. I fear for you the punishment of a dreadful day", romanUrdu: "Humne Nooh ko uski qaum ki taraf bheja, usne kaha “aey biradraan e qaum, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai, main tumhare haqq mein ek haulnaak din (awesome day) ke azaab se darta hoon”" },
    { number: 60, arabic: "قَالَ ٱلْمَلَأُ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Qala almalao min qawmihi inna lanaraka fee dalalin mubeenin", transliterationB: "Qaalal mala-u min qaw miheee innaa lanaraaka fee dalaalim mubeen", english: "The leaders of his people said: \"Ah! we see thee evidently wandering (in mind)", romanUrdu: "Uski qaum ke sardaron ne jawab diya “ humko to yeh nazar aata hai ke tum sareeh gumraahi mein mubtila ho”" },
    { number: 61, arabic: "قَالَ يَٰقَوْمِ لَيْسَ بِى ضَلَٰلَةٌۭ وَلَٰكِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", transliteration: "Qala ya qawmi laysa bee dalalatun walakinnee rasoolun min rabbi alAAalameena", transliterationB: "Qaala yaa qawmi laisa bee dalaalatunw wa laakinnee Rasoolum mir Rabbil 'aalameen", english: "He said: \"O my people! No wandering is there in my (mind): on the contrary I am a messenger from the Lord and Cherisher of the worlds", romanUrdu: "Nooh ne kaha “aey biradraan e qaum, main kisi gumraahi mein nahin pada hoon balke, main Rubb ul alameen ka Rasool hoon" },
    { number: 62, arabic: "أُبَلِّغُكُمْ رِسَٰلَٰتِ رَبِّى وَأَنصَحُ لَكُمْ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ", transliteration: "Oballighukum risalati rabbee waansahu lakum waaAAlamu mina Allahi ma la taAAlamoona", transliterationB: "Uballighukum Risaalaati Rabbee wa ansahu lakum wa a'lamu minal laahi maa laa ta'lamoon", english: "I but fulfil towards you the duties of my Lord's mission: Sincere is my advice to you, and I know from Allah something that ye know not", romanUrdu: "Tumhein apne Rubb ke paigamaat pahunchata hoon, tumhara khair-khwa hoon, aur mujhey Allah ki taraf se woh kuch maloom hai jo tumhein maloom nahin hai" },
    { number: 63, arabic: "أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌۭ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍۢ مِّنكُمْ لِيُنذِرَكُمْ وَلِتَتَّقُوا۟ وَلَعَلَّكُمْ تُرْحَمُونَ", transliteration: "AwaAAajibtum an jaakum thikrun min rabbikum AAala rajulin minkum liyunthirakum walitattaqoo walaAAallakum turhamoona", transliterationB: "awa'ajibtum an jaaa'akum zikrum mir Rabbikum 'alaa rajulim minkum liyunzirakum wa litattaqoo wa la'allakum turhamoon", english: "Do ye wonder that there hath come to you a message from your Lord, through a man of your own people, to warn you,- so that ye may fear Allah and haply receive His Mercy", romanUrdu: "Kya tumhein is baat par tajjub hua ke tumhare paas khud tumhari apni qaum ke ek aadmi ke zariye se tumhare Rubb ki yaad dehani aayi taa-ke tumhein khabardaar karey, aur tum galat rawi se bach jao aur tumpar reham kiya jaye?”" },
    { number: 64, arabic: "فَكَذَّبُوهُ فَأَنجَيْنَٰهُ وَٱلَّذِينَ مَعَهُۥ فِى ٱلْفُلْكِ وَأَغْرَقْنَا ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا عَمِينَ", transliteration: "Fakaththaboohu faanjaynahu waallatheena maAAahu fee alfulki waaghraqna allatheena kaththaboo biayatina innahum kanoo qawman AAameena", transliterationB: "Fakazzaboohu fa anjai naahu wallazeena ma'ahoo fil fulki wa aghraqnal lazeena kazzaboo bi Aayaatinaa; innahum kaanoo qawman 'ameen", english: "But they rejected him, and We delivered him, and those with him, in the Ark: but We overwhelmed in the flood those who rejected Our signs. They were indeed a blind people", romanUrdu: "Magar unhon ne usko jhutla diya. Aakhir e kaar humne usey aur uske saathiyon ko ek kashti mein najaat di aur un logon ko dubo diya jinhon ne hamari aayat ko jhutlaya tha. Yaqeenan woh andhey log thay" },
    { number: 65, arabic: "۞ وَإِلَىٰ عَادٍ أَخَاهُمْ هُودًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥٓ ۚ أَفَلَا تَتَّقُونَ", transliteration: "Waila AAadin akhahum hoodan qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu afala tattaqoona", transliterationB: "Wa ilaa 'aadin akhaahum Hoodaa; qaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuh; afalaa tattaqoon", english: "To the 'Ad people, (We sent) Hud, one of their (own) brethren: He said: O my people! worship Allah! ye have no other god but Him will ye not fear (Allah)", romanUrdu: "Aur Aad ki taraf humne unke bhai Hud ko bheja. Usne kaha “aey biradraan e qaum, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai phir kya tum galat rawi se parheiz na karogey?”" },
    { number: 66, arabic: "قَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى سَفَاهَةٍۢ وَإِنَّا لَنَظُنُّكَ مِنَ ٱلْكَٰذِبِينَ", transliteration: "Qala almalao allatheena kafaroo min qawmihi inna lanaraka fee safahatin wainna lanathunnuka mina alkathibeena", transliterationB: "Qaalal mala ul lazeena kafaroo min qawmiheee innaa lanaraaka fee safaahatinw wa innaa lannazunnuka minal kaazibeen", english: "The leaders of the Unbelievers among his people said: \"Ah! we see thou art an imbecile!\" and \"We think thou art a liar", romanUrdu: "Uski qaum ke sardaron ne, jo uski baat maanne se inkar kar rahey thay, jawab mein kaha “ hum to tumhein be-aqali (in folly)mein mubtila samajhte hain aur humein gumaan hai ke tum jhootey ho”" },
    { number: 67, arabic: "قَالَ يَٰقَوْمِ لَيْسَ بِى سَفَاهَةٌۭ وَلَٰكِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", transliteration: "Qala ya qawmi laysa bee safahatun walakinnee rasoolun min rabbi alAAalameena", transliterationB: "Qaala yaa qawmi laisa bee safaahatunw wa laakinnee Rasoolum mir Rabbil 'aalameen", english: "He said: \"O my people! I am no imbecile, but (I am) a messenger from the Lord and Cherisher of the worlds", romanUrdu: "Usne kaha “ aey biradraan e qaum, main be-aqali mein mubtila nahin hoon balke main Rubb ul aalameen ka Rasool hoon" },
    { number: 68, arabic: "أُبَلِّغُكُمْ رِسَٰلَٰتِ رَبِّى وَأَنَا۠ لَكُمْ نَاصِحٌ أَمِينٌ", transliteration: "Oballighukum risalati rabbee waana lakum nasihun ameenun", transliterationB: "Uballighukum Risaalaati Rabbee wa ana lakum naasihun ameen", english: "I but fulfil towards you the duties of my Lord's mission: I am to you a sincere and trustworthy adviser", romanUrdu: "Tumko apne Rubb ke paigaamaat pahunchata hoon, aur tumhara aisa khair-khwah hoon jispar bharosa kiya jaa sakta hai" },
    { number: 69, arabic: "أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌۭ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍۢ مِّنكُمْ لِيُنذِرَكُمْ ۚ وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ قَوْمِ نُوحٍۢ وَزَادَكُمْ فِى ٱلْخَلْقِ بَصْۜطَةًۭ ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ لَعَلَّكُمْ تُفْلِحُونَ", transliteration: "AwaAAajibtum an jaakum thikrun min rabbikum AAala rajulin minkum liyunthirakum waothkuroo ith jaAAalakum khulafaa min baAAdi qawmi noohin wazadakum fee alkhalqi bastatan faothkuroo alaa Allahi laAAallakum tuflihoona", transliterationB: "awa 'ajibtum an jaaa'akum zikrum mir Rabbikum 'alaa rajulim minkum liyunzirakum; wazkurooo iz ja'alakum khulafaaa'a mim ba'di qawmi noohinw wa zaadakum filkhalqi bastatan fazkurooo aalaaa'al laahi la'allakum tuflihoon", english: "Do ye wonder that there hath come to you a message from your Lord through a man of your own people, to warn you? call in remembrance that He made you inheritors after the people of Noah, and gave you a stature tall among the nations. Call in remembrance the benefits (ye have received) from Allah: that so ye may prosper", romanUrdu: "Kya tumhein is baat par tajjub hua ke tumhare paas khud tumhari apni qaum ke ek aadmi ke zariye se tumhare Rubb ki yaad dehani aayi taa-ke woh tumhein khabardaar karey? Bhool na jao ke tumhare Rubb ne Nooh ki qaum ke baad tumko uska jaanasheen(successors) banaya aur tumhein khoob tano-mand kiya(amply increased you in stature) , pas Allah ki qudrat ke karishmon ko yaad rakkho, umeed hai ke falaah paogey”" },
    { number: 70, arabic: "قَالُوٓا۟ أَجِئْتَنَا لِنَعْبُدَ ٱللَّهَ وَحْدَهُۥ وَنَذَرَ مَا كَانَ يَعْبُدُ ءَابَآؤُنَا ۖ فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Qaloo ajitana linaAAbuda Allaha wahdahu wanathara ma kana yaAAbudu abaona fatina bima taAAiduna in kunta mina alssadiqeena", transliterationB: "Qaalooo aji'tanaa lina'budal laaha wahdahoo wa nazara maa kaana ya'budu aabaaa'u naa faatinaa bimaa ta'idunaaa in kunta minas saadiqeen", english: "They said: \"Comest thou to us, that we may worship Allah alone, and give up the cult of our fathers? bring us what thou threatenest us with, if so be that thou tellest the truth", romanUrdu: "Unhon ne jawab diya “kya tu hamare paas is liye aaya hai ke hum akele Allah hi ki ibadat karein aur unhein chodh dein jinki ibadat hamare baap dada karte aaye hain? Accha to ley aa woh azaab jiski tu humein dhamki deta hai agar tu saccha hai”" },
    { number: 71, arabic: "قَالَ قَدْ وَقَعَ عَلَيْكُم مِّن رَّبِّكُمْ رِجْسٌۭ وَغَضَبٌ ۖ أَتُجَٰدِلُونَنِى فِىٓ أَسْمَآءٍۢ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّا نَزَّلَ ٱللَّهُ بِهَا مِن سُلْطَٰنٍۢ ۚ فَٱنتَظِرُوٓا۟ إِنِّى مَعَكُم مِّنَ ٱلْمُنتَظِرِينَ", transliteration: "Qala qad waqaAAa AAalaykum min rabbikum rijsun waghadabun atujadiloonanee fee asmain sammaytumooha antum waabaokum ma nazzala Allahu biha min sultanin faintathiroo innee maAAakum mina almuntathireena", transliterationB: "Qaala qad waqa'a alaikum mir Rabbikum rijsunw wa ghadab, atujaadiloonanee feee asmaaa'in sammaitumoohaaa antum wa aabaaa'ukum maa nazzalal laahu bihaa min sultaan; fantazirooo innee ma'akum minal muntazireen", english: "He said: \"Punishment and wrath have already come upon you from your Lord: dispute ye with me over names which ye have devised - ye and your fathers,- without authority from Allah? then wait: I am amongst you, also waiting", romanUrdu: "Usne kaha “tumhare Rubb ki phitkar tum par padh gayi aur uska gazab toot pada, kya tum mujhse un naamo (names) par jhagadte ho jo tumne aur tumhare baap dada ne rakh liye hain, jinke liye Allah ne koi sanad nazil nahin ki hai. Accha to tum bhi intezaar karo aur main bhi tumhare saath intezaar karta hoon”" },
    { number: 72, arabic: "فَأَنجَيْنَٰهُ وَٱلَّذِينَ مَعَهُۥ بِرَحْمَةٍۢ مِّنَّا وَقَطَعْنَا دَابِرَ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا ۖ وَمَا كَانُوا۟ مُؤْمِنِينَ", transliteration: "Faanjaynahu waallatheena maAAahu birahmatin minna waqataAAna dabira allatheena kaththaboo biayatina wama kanoo mumineena", transliterationB: "Fa anjainaahu wallazeena ma'ahoo birahmatim minnaa wa qata'naa daabiral lazeena kazzaboo bi Aayaatinaa wa maa kaanoo mu'mineen", english: "We saved him and those who adhered to him. By Our mercy, and We cut off the roots of those who rejected Our signs and did not believe", romanUrdu: "Aakhir e kaar humne apni meharbani se Hud aur uske saathiyon ko bacha liye aur un logo ki jadd (roots) kaat di jo hamari aayat ko jhutla chuke thay aur iman laney waley na thay" },
    { number: 73, arabic: "وَإِلَىٰ ثَمُودَ أَخَاهُمْ صَٰلِحًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌۭ مِّن رَّبِّكُمْ ۖ هَٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمْ ءَايَةًۭ ۖ فَذَرُوهَا تَأْكُلْ فِىٓ أَرْضِ ٱللَّهِ ۖ وَلَا تَمَسُّوهَا بِسُوٓءٍۢ فَيَأْخُذَكُمْ عَذَابٌ أَلِيمٌۭ", transliteration: "Waila thamooda akhahum salihan qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu qad jaatkum bayyinatun min rabbikum hathihi naqatu Allahi lakum ayatan fatharooha takul fee ardi Allahi wala tamassooha bisooin fayakhuthakum AAathabun aleemun", transliterationB: "Wa ilaa Samooda akhaahum Saalihaa; qaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuhoo qad jaaa'atkum baiyinatum mir Rabbikum haazihee naaqatul laahi lakum Aayatan fazaroohaa taakul feee ardil laahi wa laa tamassoohaa bisooo'in fa yaakhuzakum 'azaabun aleem", english: "To the Thamud people (We sent) Salih, one of their own brethren: He said: \"O my people! worship Allah: ye have no other god but Him. Now hath come unto you a clear (Sign) from your Lord! This she-camel of Allah is a Sign unto you: So leave her to graze in Allah's earth, and let her come to no harm, or ye shall be seized with a grievous punishment", romanUrdu: "Aur Samood ki taraf humne unke bhai Saleh ko bheja. Usne kaha “aey biradraan e qaum, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai. Tumhare paas tumhare Rubb ki khuli daleel aa gayi hai. Yeh Allah ki ounti (she-camel) tumhare liye ek nishani ke taur par hai, lihaza isey chodh do ke khuda ki zameen mein charti phirey, isko kisi burey irade se haath na lagana warna ek dardnaak azaab tumhein aa lega" },
    { number: 74, arabic: "وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ عَادٍۢ وَبَوَّأَكُمْ فِى ٱلْأَرْضِ تَتَّخِذُونَ مِن سُهُولِهَا قُصُورًۭا وَتَنْحِتُونَ ٱلْجِبَالَ بُيُوتًۭا ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ", transliteration: "Waothkuroo ith jaAAalakum khulafaa min baAAdi AAadin wabawwaakum fee alardi tattakhithoona min suhooliha qusooran watanhitoona aljibala buyootan faothkuroo alaa Allahi wala taAAthaw fee alardi mufsideena", transliterationB: "Wazkkurooo iz ja'alakum khulafaaa'a mim ba'di 'Aadinw wa bawwa akum fil ardi tattakhizoona min suhoolihaa qusooranw wa tanhitoonal jibaala buyootan fazkurooo aalaaa'al laahi wa laa ta'saw fil ardi mufsideen", english: "And remember how He made you inheritors after the 'Ad people and gave you habitations in the land: ye build for yourselves palaces and castles in (open) plains, and carve out homes in the mountains; so bring to remembrance the benefits (ye have received) from Allah, and refrain from evil and mischief on the earth", romanUrdu: "Yaad karo woh waqt jab Allah ne qaum e Aad ke baad tumhein uska jaanasheen (successors) banaya aur tumko zameen mein yeh manzilat bakshi ke aaj tum uske humwaar maidaano mein aali shaan mehal banate aur uske pahadon ko makanaat ki shakal mein tarashte ho. Pas uski qudrat ke karishmon se gaafil na ho jao aur zameen mein fasaad barpa na karo.”" },
    { number: 75, arabic: "قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لِلَّذِينَ ٱسْتُضْعِفُوا۟ لِمَنْ ءَامَنَ مِنْهُمْ أَتَعْلَمُونَ أَنَّ صَٰلِحًۭا مُّرْسَلٌۭ مِّن رَّبِّهِۦ ۚ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلَ بِهِۦ مُؤْمِنُونَ", transliteration: "Qala almalao allatheena istakbaroo min qawmihi lillatheena istudAAifoo liman amana minhum ataAAlamoona anna salihan mursalun min rabbihi qaloo inna bima orsila bihi muminoona", transliterationB: "Qaalal mala ul lazeenas takbaroo min qawmihee lillazeenas tud'ifoo liman aamana minhum ata'almoona anna Saaliham mursalum mir Rabbih; qaalooo innaa bimaaa ursila bihee mu'minoon", english: "The leaders of the arrogant party among his people said to those who were reckoned powerless - those among them who believed: \"know ye indeed that Salih is a messenger from his Lord?\" They said: \"We do indeed believe in the revelation which hath been sent through him", romanUrdu: "Uski qaum ke sardaron ne jo badey baney huey thay, kamzoor tabqey ke un logon se jo iman le aaye thay kaha “kya tum waqayi yeh jantey ho ke Saleh apne Rubb ka paigambar hai?” Unhon ne jawab diya “beshak jis paigam ke saath woh bheja gaya hai usey hum maante hain.”" },
    { number: 76, arabic: "قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا بِٱلَّذِىٓ ءَامَنتُم بِهِۦ كَٰفِرُونَ", transliteration: "Qala allatheena istakbaroo inna biallathee amantum bihi kafiroona", transliterationB: "Qaalal lazeenas takbarooo innaa billazeee aamanntum bihee kaafiroon", english: "The Arrogant party said: \"For our part, we reject what ye believe in", romanUrdu: "Un burayi ke muddaiyon (haughty ones) ne kaha jis cheez ko tumne maana hai hum uske munkir hain.”" },
    { number: 77, arabic: "فَعَقَرُوا۟ ٱلنَّاقَةَ وَعَتَوْا۟ عَنْ أَمْرِ رَبِّهِمْ وَقَالُوا۟ يَٰصَٰلِحُ ٱئْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلْمُرْسَلِينَ", transliteration: "FaAAaqaroo alnnaqata waAAataw AAan amri rabbihim waqaloo ya salihu itina bima taAAiduna in kunta mina almursaleena", transliterationB: "Fa'aqarun naaqata wa'ataw 'an amri Rabbihim wa qaaloo yaa Saalihu' tinaa bimaa ta'idunaaa in kunta minal mursaleen", english: "Then they ham-strung the she-camel, and insolently defied the order of their Lord, saying: \"O Salih! bring about thy threats, if thou art a messenger (of Allah)", romanUrdu: "Phir unhon ne us ountni (she-camel) ko maar dala aur purey tammarrud (disdainfuliy disobeyed) ke saath apne Rubb ke hukum ki khilaf warzi kar guzrey. Aur Saleh se keh diya ke le aa woh azaab jiski tu humein dhamki deta hai agar tu waqayi paigambaron mein se hai" },
    { number: 78, arabic: "فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", transliteration: "Faakhathathumu alrrajfatu faasbahoo fee darihim jathimeena", transliterationB: "Fa akhazat humur rajftu fa asbahoo fee daarihim jaasimmeen", english: "So the earthquake took them unawares, and they lay prostrate in their homes in the morning", romanUrdu: "Aakhir e kaar ek dehla dene wali aafat ne unhein aa liya aur woh apne gharon mein aundhey paday ke paday reh gaye" },
    { number: 79, arabic: "فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَالَةَ رَبِّى وَنَصَحْتُ لَكُمْ وَلَٰكِن لَّا تُحِبُّونَ ٱلنَّٰصِحِينَ", transliteration: "Fatawalla AAanhum waqala ya qawmi laqad ablaghtukum risalata rabbee wanasahtu lakum walakin la tuhibboona alnnasiheena", transliterationB: "Fa tawalla 'anhum wa qaala yaa qawmi laqad ablaghtukum Risaalata Rabbee wa nasahtu lakum wa laakil laa tuhibboonan naasiheen", english: "So Salih left them, saying: \"O my people! I did indeed convey to you the message for which I was sent by my Lord: I gave you good counsel, but ye love not good counsellors", romanUrdu: "Aur Saleh yeh kehta hua unki bastiyon se nikal gaya ke “ aey meri qaum, maine apne Rubb ka paigam tujhey pahuncha diya aur maine teri bahut khair khwahi ki, magar main kya karoon ke tujhey apne khair khwah pasand hi nahin hain”" },
    { number: 80, arabic: "وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍۢ مِّنَ ٱلْعَٰلَمِينَ", transliteration: "Walootan ith qala liqawmihi atatoona alfahishata ma sabaqakum biha min ahadin mina alAAalameena", transliterationB: "Wa Lootan iz qaala liqawmiheee ataatoonal faahishata maa sabaqakum bihaa min ahadim minal 'aalameen", english: "We also (sent) Lut: He said to his people: \"Do ye commit lewdness such as no people in creation (ever) committed before you", romanUrdu: "Aur Lut ko humne paigambar banakar bheja, phir yaad karo jab usne apni qaum se kaha, “ kya tum aisey be-haya ho gaye ho, ke woh fahash kaam karte ho jo tumse pehle duniya mein kisi ne nahin kiya" },
    { number: 81, arabic: "إِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةًۭ مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌۭ مُّسْرِفُونَ", transliteration: "Innakum latatoona alrrijala shahwatan min dooni alnnisai bal antum qawmun musrifoona", transliterationB: "Innakum lataatoonar rijaala shahwatam min doonin nisaaa'; bal antumqawmum musrifoon", english: "For ye practise your lusts on men in preference to women: ye are indeed a people transgressing beyond bounds", romanUrdu: "Tum auraton ko chodh kar mardon se apni khwaish poori karte ho. Haqeeqat yeh hai ke tum bilkul hi hadd se guzar janey waley log ho”" },
    { number: 82, arabic: "وَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوهُم مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌۭ يَتَطَهَّرُونَ", transliteration: "Wama kana jawaba qawmihi illa an qaloo akhrijoohum min qaryatikum innahum onasun yatatahharoona", transliterationB: "Wa maa kaana jawaaba qawmihee illaa an qaalooo akhrijoohum min qaryatikum innahum unaasuny yatatah haroon", english: "And his people gave no answer but this: they said, \"Drive them out of your city: these are indeed men who want to be clean and pure", romanUrdu: "Magar uski qaum ka jawab iske siwa kuch na tha ke “ nikalo in logon ko apni bastiyon se, badey paakbaaz bante hain yeh”" },
    { number: 83, arabic: "فَأَنجَيْنَٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَٰبِرِينَ", transliteration: "Faanjaynahu waahlahu illa imraatahu kanat mina alghabireena", transliterationB: "Fa anjainaahu wa ahlahooo illam ra atahoo kaanat minal ghaabireen", english: "But we saved him and his family, except his wife: she was of those who legged behind", romanUrdu: "Aakhir e kaar humne Lut aur uske gharwalon ko bajuz uski biwi ke jo pichey reh janey walon mein thi" },
    { number: 84, arabic: "وَأَمْطَرْنَا عَلَيْهِم مَّطَرًۭا ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُجْرِمِينَ", transliteration: "Waamtarna AAalayhim mataran faonthur kayfa kana AAaqibatu almujrimeena", transliterationB: "Wa 'amtarnaa 'alaihim mataran fanzur kaifa kaana aaqibatul mujjrimeen", english: "And we rained down on them a shower (of brimstone): Then see what was the end of those who indulged in sin and crime", romanUrdu: "Bacha kar nikal diya aur us qaum par barsayi ek baarish, phir dekho ke un mujreemon ka kya anjaam hua" },
    { number: 85, arabic: "وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًۭا ۗ قَالَ يَٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌۭ مِّن رَّبِّكُمْ ۖ فَأَوْفُوا۟ ٱلْكَيْلَ وَٱلْمِيزَانَ وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَٰحِهَا ۚ ذَٰلِكُمْ خَيْرٌۭ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ", transliteration: "Waila madyana akhahum shuAAayban qala ya qawmi oAAbudoo Allaha ma lakum min ilahin ghayruhu qad jaatkum bayyinatun min rabbikum faawfoo alkayla waalmeezana wala tabkhasoo alnnasa ashyaahum wala tufsidoo fee alardi baAAda islahiha thalikum khayrun lakum in kuntum mumineena", transliterationB: "Wa ilaa Madyana akhaahum Shu'aybaa; qaala yaa qawmi' budul laaha maa lakum min ilaahin ghairuhoo qad jaaa'atkum baiyinatum mir Rabbikum fa awful kaila walmeezaana wa laa tabkhasun naasa ashyaa'ahum wa laa tufsidoo fil ardi ba'da islaahihaa; zaalikum khairul lakum in kuntum mu'mineen", english: "To the Madyan people We sent Shu'aib, one of their own brethren: he said: \"O my people! worship Allah; Ye have no other god but Him. Now hath come unto you a clear (Sign) from your Lord! Give just measure and weight, nor withhold from the people the things that are their due; and do no mischief on the earth after it has been set in order: that will be best for you, if ye have Faith", romanUrdu: "Aur Madiyan walon ki taraf humne unke bhai Shoaib ko bheja. Usne kaha “ aey biradraan e qaum, Allah ki bandagi karo, uske siwa tumhara koi khuda nahin hai. Tumhare paas tumhare Rubb ki saaf rehnumayi aa gayi hai, lihaza wazan(weight) aur paimane purey karo. Logon ko unki cheezon mein ghaata(loss) na do, aur zameen mein fasaad barpa na karo jabke uski islaah ho chuki hai. Isi mein tumhari bhalayi hai agar tum waqayi momin ho" },
    { number: 86, arabic: "وَلَا تَقْعُدُوا۟ بِكُلِّ صِرَٰطٍۢ تُوعِدُونَ وَتَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ بِهِۦ وَتَبْغُونَهَا عِوَجًۭا ۚ وَٱذْكُرُوٓا۟ إِذْ كُنتُمْ قَلِيلًۭا فَكَثَّرَكُمْ ۖ وَٱنظُرُوا۟ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ", transliteration: "Wala taqAAudoo bikulli siratin tooAAidoona watasuddoona AAan sabeeli Allahi man amana bihi watabghoonaha AAiwajan waothkuroo ith kuntum qaleelan fakaththarakum waonthuroo kayfa kana AAaqibatu almufsideena", transliterationB: "Wa laa taq'udoo bikulli siraatin too'idoona wa tasuddoona 'an sabeelil laahi man aamana bihee wa abghoonahaa 'iwajaa; waz kurooo iz kuntum qaleelan fakassarakum wanzuroo kaifa kaana 'aaqibatul mufsideen", english: "And squat not on every road, breathing threats, hindering from the path of Allah those who believe in Him, and seeking in it something crooked; But remember how ye were little, and He gave you increase. And hold in your mind's eye what was the end of those who did mischief", romanUrdu: "Aur (zindagi ke) har rastey par rehzan (lie in ambush) bankar na baith jao ke logon ko khauf zadah karne aur iman laney walon ko khuda ke rastey se rokne lago, aur seedhi raah ko tedha karne ke darpe ho jao. Yaad karo woh zamana jabke tum thode thay phir Allah ne tumhein bahut kardiya, aur aakhein khol kar dekho ke duniya mein mufsidon ka kya anjaam hua hai" },
    { number: 87, arabic: "وَإِن كَانَ طَآئِفَةٌۭ مِّنكُمْ ءَامَنُوا۟ بِٱلَّذِىٓ أُرْسِلْتُ بِهِۦ وَطَآئِفَةٌۭ لَّمْ يُؤْمِنُوا۟ فَٱصْبِرُوا۟ حَتَّىٰ يَحْكُمَ ٱللَّهُ بَيْنَنَا ۚ وَهُوَ خَيْرُ ٱلْحَٰكِمِينَ", transliteration: "Wain kana taifatun minkum amanoo biallathee orsiltu bihi wataifatun lam yuminoo faisbiroo hatta yahkuma Allahu baynana wahuwa khayru alhakimeena", transliterationB: "Wa In kaana taaa'ifatum minkum aamanoo billazeee ursiltu bihee wa taaa'ifatul lam yu'minoo fasbiroo hattaa yahkumual laahu bainanaa; wa Huwa khairul haakimeen", english: "And if there is a party among you who believes in the message with which I have been sent, and a party which does not believe, hold yourselves in patience until Allah doth decide between us: for He is the best to decide", romanUrdu: "Agar tum mein se ek giroh is taleem par jiske saath main bheja gaya hoon, iman laata hai aur dusra iman nahin laata, to sabr ke saath dekhte raho yahan tak ke Allah hamare darmiyan faisla karde, aur wahi sabse behtar faisla karne wala hai”" },
    { number: 88, arabic: "۞ قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لَنُخْرِجَنَّكَ يَٰشُعَيْبُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَكَ مِن قَرْيَتِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَا ۚ قَالَ أَوَلَوْ كُنَّا كَٰرِهِينَ", transliteration: "Qala almalao allatheena istakbaroo min qawmihi lanukhrijannaka ya shuAAaybu waallatheena amanoo maAAaka min qaryatina aw lataAAoodunna fee millatina qala awalaw kunna kariheena", transliterationB: "Qaalal mala ul lazeenas takbaroo min qawmihee lanukhrijannaka yaa Shu'aibu wallazeena aamanoo ma'aka min qaryatinaaa aw lata'oo dunna fee millatinaa; qaala awa law kunnaa kaariheen", english: "The leaders, the arrogant party among his people, said: \"O Shu'aib! we shall certainly drive thee out of our city - (thee) and those who believe with thee; or else ye (thou and they) shall have to return to our ways and religion.\" He said: \"What! even though we do detest (them)", romanUrdu: "Uski qaum ke sardaron ne , jo apni badayi ke ghamand mein mubtila thay, ussey kaha ke “aey Shoaib , hum tujhey aur un logon ko jo tere saath iman laye hain apni basti se nikal denge warna tum logon ko hamari millat mein wapas aana hoga”. Shoaib ne jawab diya, “kya zabardasti humein phera jayega khwa hum razi na hon" },
    { number: 89, arabic: "قَدِ ٱفْتَرَيْنَا عَلَى ٱللَّهِ كَذِبًا إِنْ عُدْنَا فِى مِلَّتِكُم بَعْدَ إِذْ نَجَّىٰنَا ٱللَّهُ مِنْهَا ۚ وَمَا يَكُونُ لَنَآ أَن نَّعُودَ فِيهَآ إِلَّآ أَن يَشَآءَ ٱللَّهُ رَبُّنَا ۚ وَسِعَ رَبُّنَا كُلَّ شَىْءٍ عِلْمًا ۚ عَلَى ٱللَّهِ تَوَكَّلْنَا ۚ رَبَّنَا ٱفْتَحْ بَيْنَنَا وَبَيْنَ قَوْمِنَا بِٱلْحَقِّ وَأَنتَ خَيْرُ ٱلْفَٰتِحِينَ", transliteration: "Qadi iftarayna AAala Allahi kathiban in AAudna fee millatikum baAAda ith najjana Allahu minha wama yakoonu lana an naAAooda feeha illa an yashaa Allahu rabbuna wasiAAa rabbuna kulla shayin AAilman AAala Allahi tawakkalna rabbana iftah baynana wabayna qawmina bialhaqqi waanta khayru alfatiheena", transliterationB: "Qadif tarainaa 'alal laahi kaziban in 'udnaa fee millatikum ba'da iz najjaanal laahu minhaa; wa maa yakoonu lanaaa an na'ooda feehaaa illaaa ai yashaaa'al laahu Rabbunaa; wasi'a Rabbunaa kulla shai'in 'ilmaa; 'alal laahi tawakkalnaa; Rabbanaf tah bainanaa wa baina qawminaa bilhaqqi wa Anta khairul faatiheen", english: "We should indeed invent a lie against Allah, if we returned to your ways after Allah hath rescued us therefrom; nor could we by any manner of means return thereto unless it be as in the will and plan of Allah, Our Lord. Our Lord can reach out to the utmost recesses of things by His knowledge. In the Allah is our trust. our Lord! decide Thou between us and our people in truth, for Thou art the best to decide", romanUrdu: "Hum Allah par jhoot ghadne waley hongey agar tumhari millat mein palat aayein jabke Allah humein issey najaat de chuka hai. Hamare liye to iski taraf palatna ab kisi tarah mumkin nahin illa yeh ke khuda hamara Rubb hi aisa chahe. Hamare Rubb ka ilm har cheez par haawi hai, usi par humne aitamaad(bharosa) karliya. Aey Rubb, hamare aur hamari qaum ke darmiyan theek theek faisla karde aur tu behtareen faisla karne wala hai”" },
    { number: 90, arabic: "وَقَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ لَئِنِ ٱتَّبَعْتُمْ شُعَيْبًا إِنَّكُمْ إِذًۭا لَّخَٰسِرُونَ", transliteration: "Waqala almalao allatheena kafaroo min qawmihi laini ittabaAAtum shuAAayban innakum ithan lakhasiroona", transliterationB: "Wa qaalal mala ul lazeena kafaroo min qawmihee la'init taba'tum Shu'aiban innakum izal lakhaasiroon", english: "The leaders, the unbelievers among his people, said: \"If ye follow Shu'aib, be sure then ye are ruined", romanUrdu: "Uski qaum ke Sardaron ne , jo uski baat maanne se inkar kar chuke thay, aapas mein kaha “agar tumne shoaib ki pairwi qabool karli to barbaad ho jaogey.”" },
    { number: 91, arabic: "فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَٰثِمِينَ", transliteration: "Faakhathathumu alrrajfatu faasbahoo fee darihim jathimeena", transliterationB: "Fa akhazat humur rajfatu fa asbahoo fee daarihim jaasimeen", english: "But the earthquake took them unawares, and they lay prostrate in their homes before the morning", romanUrdu: "Magar hua yeh ke ek dehla dene wali aafat ne unko aa liye aur woh apne gharon mein aundhey padey ke padey reh gaye" },
    { number: 92, arabic: "ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًۭا كَأَن لَّمْ يَغْنَوْا۟ فِيهَا ۚ ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًۭا كَانُوا۟ هُمُ ٱلْخَٰسِرِينَ", transliteration: "Allatheena kaththaboo shuAAayban kaan lam yaghnaw feeha allatheena kaththaboo shuAAayban kanoo humu alkhasireena", transliterationB: "Allazeena kazzaboo Shu'aiban ka al alm yaghnaw feehaa; allazeena kazzaboo Shu'aiban kaanoo humul khaasireen", english: "The men who reject Shu'aib became as if they had never been in the homes where they had flourished: the men who rejected Shu'aib - it was they who were ruined", romanUrdu: "Jin logon ne Shoaib ko jhutlaya woh aisey mitey ke goya kabhi un gharon mein basey hi na thay. Shoaib ke jhutlane waley aakhir e kaar barbaad ho kar rahey" },
    { number: 93, arabic: "فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَٰلَٰتِ رَبِّى وَنَصَحْتُ لَكُمْ ۖ فَكَيْفَ ءَاسَىٰ عَلَىٰ قَوْمٍۢ كَٰفِرِينَ", transliteration: "Fatawalla AAanhum waqala ya qawmi laqad ablaghtukum risalati rabbee wanasahtu lakum fakayfa asa AAala qawmin kafireena", transliterationB: "Fatawalla 'anhum wa qaala yaa qawmi laqad ablaghtukum Risaalaati Rabbee wa nasahtu lakum fakaifa aasaa'alaa qawmin kaafireen", english: "So Shu'aib left them, saying: \"O my people! I did indeed convey to you the messages for which I was sent by my Lord: I gave you good counsel, but how shall I lament over a people who refuse to believe", romanUrdu: "Aur Shoaib yeh keh kar unki bastiyon se nikal gaya ke “aey biradraan e qaum , maine apne Rubb ke paigamaat tumhein pahuncha diye aur tumhari khair kwahi ka haqq ada kardiya, ab main us qaum par kaise afsos karoon jo qubool e haqq se inkar karti hai”" },
    { number: 94, arabic: "وَمَآ أَرْسَلْنَا فِى قَرْيَةٍۢ مِّن نَّبِىٍّ إِلَّآ أَخَذْنَآ أَهْلَهَا بِٱلْبَأْسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمْ يَضَّرَّعُونَ", transliteration: "Wama arsalna fee qaryatin min nabiyyin illa akhathna ahlaha bialbasai waalddarrai laAAallahum yaddarraAAoona", transliterationB: "Wa maaa arsalnaa fee qaryatim min Nabiyyin illaaa akhaznaaa ahlahaa bil baasaaa'i waddarraaa'i la'allahum yaddarra'oon", english: "Whenever We sent a prophet to a town, We took up its people in suffering and adversity, in order that they might learn humility", romanUrdu: "Kabhi aisa nahin hua ke humne kisi basti mein Nabi bheja ho aur us basti ke logon ko pehle tanggi aur sakhti mein mubtila na kiya ho is khayal se ke shayad woh aajizi" },
    { number: 95, arabic: "ثُمَّ بَدَّلْنَا مَكَانَ ٱلسَّيِّئَةِ ٱلْحَسَنَةَ حَتَّىٰ عَفَوا۟ وَّقَالُوا۟ قَدْ مَسَّ ءَابَآءَنَا ٱلضَّرَّآءُ وَٱلسَّرَّآءُ فَأَخَذْنَٰهُم بَغْتَةًۭ وَهُمْ لَا يَشْعُرُونَ", transliteration: "Thumma baddalna makana alssayyiati alhasanata hatta AAafaw waqaloo qad massa abaana alddarrao waalssarrao faakhathnahum baghtatan wahum la yashAAuroona", transliterationB: "Summa baddalnaa makaa nas saiyi'atil hasanata hattaa 'afaw wa qaaloo qad massa aabaa'anad darraaa'u wassarraaa'u fa akhaznaahum baghtatanw wa hum laa yash'uroon", english: "Then We changed their suffering into prosperity, until they grew and multiplied, and began to say: \"Our fathers (too) were touched by suffering and affluence\"... Behold! We called them to account of a sudden, while they realised not (their peril)", romanUrdu: "Phir humne unki badh-haali ko khush haali se badal diya yahan tak ke woh khoob phale phoole aur kehne lagey ke “hamare aslaaf par bhi acchey aur burey din aate hi rahey hain”. Aakhir e kaar humne unhein achanak pakad liya aur unhein khabar tak na hui" },
    { number: 96, arabic: "وَلَوْ أَنَّ أَهْلَ ٱلْقُرَىٰٓ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَفَتَحْنَا عَلَيْهِم بَرَكَٰتٍۢ مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ وَلَٰكِن كَذَّبُوا۟ فَأَخَذْنَٰهُم بِمَا كَانُوا۟ يَكْسِبُونَ", transliteration: "Walaw anna ahla alqura amanoo waittaqaw lafatahna AAalayhim barakatin mina alssamai waalardi walakin kaththaboo faakhathnahum bima kanoo yaksiboona", transliterationB: "Wa law anna ahlal quraaa aamanoo wattaqaw lafatahnaa 'alaihim barakaatim minas samaaa'i wal ardi wa laakin kazzaboo fa akhaznaahum bimaa kaanoo yaksiboon", english: "If the people of the towns had but believed and feared Allah, We should indeed have opened out to them (All kinds of) blessings from heaven and earth; but they rejected (the truth), and We brought them to book for their misdeeds", romanUrdu: "Agar bastiyon ke log iman latey aur taqwa ki rawish ikhtiyar karte to hum unpar aasman aur zameen se barkaton ke darwaze khol dete, magar unhon ne to jhutlaya, lihaza humne us buri kamayi ke hisaab mein unhein pakad liya jo woh sameit rahye thay" },
    { number: 97, arabic: "أَفَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا بَيَٰتًۭا وَهُمْ نَآئِمُونَ", transliteration: "Afaamina ahlu alqura an yatiyahum basuna bayatan wahum naimoona", transliterationB: "Afa amina ahlul quraaa ai yaatiyahum baasunaa bayaatanw wa hum naaa'imoon", english: "Did the people of the towns feel secure against the coming of Our wrath by night while they were asleep", romanUrdu: "Phir kya bastiyon ke log ab issey be khauf ho gaye hain ke hamari giraft (pakad) kabhi achanak unpar raat ke waqt na aa jayegi jabke woh sotey padey hon" },
    { number: 98, arabic: "أَوَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا ضُحًۭى وَهُمْ يَلْعَبُونَ", transliteration: "Awa amina ahlu alqura an yatiyahum basuna duhan wahum yalAAaboona", transliterationB: "Awa amina ahlul quraaa ai yaatiyahum baasunaa duhanw wa hum yal'aboon", english: "Or else did they feel secure against its coming in broad daylight while they played about (care-free)", romanUrdu: "Ya unhein itminaan ho gaya hai ke hamara mazboot haath kabhi yakayak unpar din ke waqt na padega jabke woh khel rahey hon" },
    { number: 99, arabic: "أَفَأَمِنُوا۟ مَكْرَ ٱللَّهِ ۚ فَلَا يَأْمَنُ مَكْرَ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْخَٰسِرُونَ", transliteration: "Afaaminoo makra Allahi fala yamanu makra Allahi illa alqawmu alkhasiroona", transliterationB: "Afa aminoo makral laah; falaa yaamanu makral laahi illal qawmul khaasiroon", english: "Did they then feel secure against the plan of Allah?- but no one can feel secure from the Plan of Allah, except those (doomed) to ruin", romanUrdu: "Kya yeh log Allah ki chaal se be khauf hain? Halanke Allah ki chaal se wahi qaum be-khauff hoti hai jo tabaah honay wali ho" },
    { number: 100, arabic: "أَوَلَمْ يَهْدِ لِلَّذِينَ يَرِثُونَ ٱلْأَرْضَ مِنۢ بَعْدِ أَهْلِهَآ أَن لَّوْ نَشَآءُ أَصَبْنَٰهُم بِذُنُوبِهِمْ ۚ وَنَطْبَعُ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَسْمَعُونَ", transliteration: "Awalam yahdi lillatheena yarithoona alarda min baAAdi ahliha an law nashao asabnahum bithunoobihim wanatbaAAu AAala quloobihim fahum la yasmaAAoona", transliterationB: "Awa lam yahdi lillazeena yarisoonal arda mim ba'di ahlihaaa al law nashaaa'u asabnaahum bizunoobihim; wa natba'u 'alaa quloobihim fahum laa yasma'oon", english: "To those who inherit the earth in succession to its (previous) possessors, is it not a guiding, (lesson) that, if We so willed, We could punish them (too) for their sins, and seal up their hearts so that they could not hear", romanUrdu: "Aur kya un logon ko jo sabiq ehle zameen ke baad zameen ke waris hotey hain , is amr e waqayi ne kuch sabaq nahin diya ke agar hum chahein to unke kasooron par unhein pakad sakte hain? (Magar woh sabaq-aamoz haqaiq se tagaful baratte hain) aur hum unke dilon par mohar laga dete hain, phir woh kuch nahin suntey" },
    { number: 101, arabic: "تِلْكَ ٱلْقُرَىٰ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآئِهَا ۚ وَلَقَدْ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَٰتِ فَمَا كَانُوا۟ لِيُؤْمِنُوا۟ بِمَا كَذَّبُوا۟ مِن قَبْلُ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلْكَٰفِرِينَ", transliteration: "Tilka alqura naqussu AAalayka min anbaiha walaqad jaathum rusuluhum bialbayyinati fama kanoo liyuminoo bima kaththaboo min qablu kathalika yatbaAAu Allahu AAala quloobi alkafireena", transliterationB: "Tilkal quraa naqussu 'alaika min ambaaa'ihaa; wa laqad jaaa'at hum Rusuluhum bilbaiyinaati famaa kaanoo liyu'minoo bimaa kazzaboo min qabl; kazaalika yatba'ul laahu 'alaa quloobil kaafireen", english: "Such were the towns whose story We (thus) relate unto thee: There came indeed to them their messengers with clear (signs): But they would not believe what they had rejected before. Thus doth Allah seal up the hearts of those who reject faith", romanUrdu: "Yeh qaumein jinke qissey hum tumhein suna rahey hain (tumhare saamne misaal mein maujood hain). Unke Rasool unke paas khuli khuli nihsnaiyan lekar aaye, magar jis cheez ko woh ek dafa jhutla chuke thay phir usey woh maanne waley na thay. Dekho is tarah hum munkireen e haqq ke dilon par mohar laga dete hain" },
    { number: 102, arabic: "وَمَا وَجَدْنَا لِأَكْثَرِهِم مِّنْ عَهْدٍۢ ۖ وَإِن وَجَدْنَآ أَكْثَرَهُمْ لَفَٰسِقِينَ", transliteration: "Wama wajadna liaktharihim min AAahdin wain wajadna aktharahum lafasiqeena", transliterationB: "Wa maa wajadnaa li aksarihim min 'ahd; wa inw wajadnaaa aksarahum lafaasiqeen", english: "Most of them We found not men (true) to their covenant: but most of them We found rebellious and disobedient", romanUrdu: "Humne un mein se aksar mein koi paas e ahad na paya, balke aksar ko fasiq hi paya" },
    { number: 103, arabic: "ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِم مُّوسَىٰ بِـَٔايَٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَظَلَمُوا۟ بِهَا ۖ فَٱنظُرْ كَيْفَ كَانَ عَٰقِبَةُ ٱلْمُفْسِدِينَ", transliteration: "Thumma baAAathna min baAAdihim moosa biayatina ila firAAawna wamalaihi fathalamoo biha faonuthur kayfa kana AAaqibatu almufsideena", transliterationB: "Summa ba'asnaa mim ba'dihim Moosaa bi Aayaatinaaa ilaa Fir'awana wa mala'ihee fazalamoo bihaa fanzur kaifa kaana 'aaqibatul mufsideen", english: "Then after them We sent Moses with Our signs to Pharaoh and his chiefs, but they wrongfully rejected them: So see what was the end of those who made mischief", romanUrdu: "Phir un qaumon ke baad ( jinka zikr upar kiya gaya) humne Moosa ko apni nishaniyon ke saath Firoun aur uski qaum ke Sardaron ke paas bheja, magar unhon ne bhi hamari nishaniyon ke saath zulm kiya. Pas dekho ke in mufsidon ka kya anjaam hua" },
    { number: 104, arabic: "وَقَالَ مُوسَىٰ يَٰفِرْعَوْنُ إِنِّى رَسُولٌۭ مِّن رَّبِّ ٱلْعَٰلَمِينَ", transliteration: "Waqala moosa ya firAAawnu innee rasoolun min rabbi alAAalameena", transliterationB: "Wa qaala Moosaa yaa Fir'awnu inee Rasoolum mir Rabbil 'aalameen", english: "Moses said: \"O Pharaoh! I am a messenger from the Lord of the worlds", romanUrdu: "Moosa ne kaha “Aey Firoun, main qayinaat ke maalik ki taraf se bheja hua aaya hoon" },
    { number: 105, arabic: "حَقِيقٌ عَلَىٰٓ أَن لَّآ أَقُولَ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ ۚ قَدْ جِئْتُكُم بِبَيِّنَةٍۢ مِّن رَّبِّكُمْ فَأَرْسِلْ مَعِىَ بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Haqeequn AAala an la aqoola AAala Allahi illa alhaqqa qad jitukum bibayyinatin min rabbikum faarsil maAAiya banee israeela", transliterationB: "Haqeequn 'alaaa al laaa aqoola 'alal laahi illal haqq; qad ji'tukum bibaiyinatim mir Rabbikum fa arsil ma'iya Baneee Israaa'eel", english: "One for whom it is right to say nothing but truth about Allah. Now have I come unto you (people), from your Lord, with a clear (Sign): So let the Children of Israel depart along with me", romanUrdu: "Mera mansab yahi hai ke Allah ka naam lekar koi baat haqq ke siwa na kahoon. Main tum logon ke paas tumhare Rubb ki taraf se sareeh daleel e mamuriyat lekar aaya hoon. Lihaza tu bani Israel ko mere saath bhej de.”" },
    { number: 106, arabic: "قَالَ إِن كُنتَ جِئْتَ بِـَٔايَةٍۢ فَأْتِ بِهَآ إِن كُنتَ مِنَ ٱلصَّٰدِقِينَ", transliteration: "Qala in kunta jita biayatin fati biha in kunta mina alssadiqeena", transliterationB: "Qaala in kunta ji'ta bi Aayatin faati bihaaa in kunta minas saadiqeen", english: "(Pharaoh) said: \"If indeed thou hast come with a Sign, show it forth,- if thou tellest the truth", romanUrdu: "Firoun ne kaha “agar tu koi nishani laya hai aur apne dawey (claim) mein saccha hai to usey pesh kar”" },
    { number: 107, arabic: "فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌۭ مُّبِينٌۭ", transliteration: "Faalqa AAasahu faitha hiya thuAAbanun mubeenun", transliterationB: "Qa alqaa 'asaahu fa izaa hiya su'baanum mubeen", english: "Then (Moses) threw his rod, and behold! it was a serpent, plain (for all to see)", romanUrdu: "Moosa ne apna asa (staff/rod) phenka aur yakayak woh ek jeeta jaagta azdaha (serpant) tha" },
    { number: 108, arabic: "وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّٰظِرِينَ", transliteration: "WanazaAAa yadahu faitha hiya baydao lilnnathireena", transliterationB: "Wa naza'a yadahoo fa izaa hiya baidaaa'u linnaazireen", english: "And he drew out his hand, and behold! it was white to all beholders", romanUrdu: "Usne apni jeb se haath nikala aur sab dekhne walon ke saamne woh chamak raha tha" },
    { number: 109, arabic: "قَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ إِنَّ هَٰذَا لَسَٰحِرٌ عَلِيمٌۭ", transliteration: "Qala almalao min qawmi firAAawna inna hatha lasahirun AAaleemun", transliterationB: "Qaalal mala-u min qawmi Fir'awna inna haazaa lasaa hirun 'aleem", english: "Said the Chiefs of the people of Pharaoh: \"This is indeed a sorcerer well-versed", romanUrdu: "Ispar Firoun ki qaum ke sardaron ne aapas mein kaha ke “yaqeenan yeh shaks bada maahir jaadugar hai" },
    { number: 110, arabic: "يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُمْ ۖ فَمَاذَا تَأْمُرُونَ", transliteration: "Yureedu an yukhrijakum min ardikum famatha tamuroona", transliterationB: "Yureedu ai yukhrijakum min ardikum famaazaa taamuroon", english: "His plan is to get you out of your land: then what is it ye counsel", romanUrdu: "Tumhein tumhari zameen se be-dakhal karna chahta hai. Ab kaho kya kehte ho?”" },
    { number: 111, arabic: "قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَأَرْسِلْ فِى ٱلْمَدَآئِنِ حَٰشِرِينَ", transliteration: "Qaloo arjih waakhahu waarsil fee almadaini hashireena", transliterationB: "Qaalooo arjih wa akhaahu wa arsil filmadaaa'ini haashireen", english: "They said: \"Keep him and his brother in suspense (for a while); and send to the cities men to collect", romanUrdu: "Phir un sab ne Firoun ko mashwara diya ke isey aur iske bhai ko intezar mein rakkhiye aur tamaam shehron mein harkarey (heralds) bhej dijiye" },
    { number: 112, arabic: "يَأْتُوكَ بِكُلِّ سَٰحِرٍ عَلِيمٍۢ", transliteration: "Yatooka bikulli sahirin AAaleemin", transliterationB: "Yaatooka bikulli saahirin 'aleem", english: "And bring up to thee all (our) sorcerers well-versed", romanUrdu: "Ke har maahir-e-fun jaadugar ko aapke paas le aayein" },
    { number: 113, arabic: "وَجَآءَ ٱلسَّحَرَةُ فِرْعَوْنَ قَالُوٓا۟ إِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَٰلِبِينَ", transliteration: "Wajaa alssaharatu firAAawna qaloo inna lana laajran in kunna nahnu alghalibeena", transliterationB: "Wa jaaa'as saharatu Fir'awna qaaloo inna lanaa la ajjran in kunnaa nahnul ghaalibeen", english: "So there came the sorcerers to Pharaoh: They said, \"of course we shall have a (suitable) reward if we win", romanUrdu: "Chunanchey jaadugar Firoun ke paas aa gaye. Unhon ne kaha “agar hum gaalib rahey to humein iska sila to zaroor milega?”" },
    { number: 114, arabic: "قَالَ نَعَمْ وَإِنَّكُمْ لَمِنَ ٱلْمُقَرَّبِينَ", transliteration: "Qala naAAam wainnakum lamina almuqarrabeena", transliterationB: "Qaala na'am wa innakum laminal muqarrabeen", english: "He said: \"Yea, (and more),- for ye shall in that case be (raised to posts) nearest (to my person)", romanUrdu: "Firoun ne jawab diya “haan, aur tum muqarrab e baargaah hogey”" },
    { number: 115, arabic: "قَالُوا۟ يَٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ نَحْنُ ٱلْمُلْقِينَ", transliteration: "Qaloo ya moosa imma an tulqiya waimma an nakoona nahnu almulqeena", transliterationB: "Qaaloo yaa Moosaaa immaaa an tulqiya wa immaaa an nakoona nahnul mulqeen", english: "They said: \"O Moses! wilt thou throw (first), or shall we have the (first) throw", romanUrdu: "Phir unhon ne Moosa se kaha “tum phenkte ho ya hum phenkein?”" },
    { number: 116, arabic: "قَالَ أَلْقُوا۟ ۖ فَلَمَّآ أَلْقَوْا۟ سَحَرُوٓا۟ أَعْيُنَ ٱلنَّاسِ وَٱسْتَرْهَبُوهُمْ وَجَآءُو بِسِحْرٍ عَظِيمٍۢ", transliteration: "Qala alqoo falamma alqaw saharoo aAAyuna alnnasi waistarhaboohum wajaoo bisihrin AAatheemin", transliterationB: "Qaala alqoo falam maaa alqaw saharooo a'yunannaasi wastarhaboohum wa jaaa'oo bisihrin 'azeem", english: "Said Moses: \"Throw ye (first).\" So when they threw, they bewitched the eyes of the people, and struck terror into them: for they showed a great (feat of) magic", romanUrdu: "Moosa ne jawab diya “tum hi phenko” unhon ne jo apne anchar [their rods]phenke to nigaahon ko mahsoor (enchanted the eyes) aur dilon ko khauf-zadah kardiya aur bada hi zabardast jaadu bana laye" },
    { number: 117, arabic: "۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَلْقِ عَصَاكَ ۖ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ", transliteration: "Waawhayna ila moosa an alqi AAasaka faitha hiya talqafu ma yafikoona", transliterationB: "Wa awhainaaa ilaa Moosaaa an alqi 'asaaka fa izaa hiya talqafu maa yaafikoon", english: "We put it into Moses's mind by inspiration: \"Throw (now) thy rod\": and behold! it swallows up straight away all the falsehoods which they fake", romanUrdu: "Humne Moosa ko ishara kiya ke phenk apna asa, uska phenkna tha ke aan ki aan mein woh unke is jhoote tilism ko ningalta chala gaya" },
    { number: 118, arabic: "فَوَقَعَ ٱلْحَقُّ وَبَطَلَ مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "FawaqaAAa alhaqqu wabatala ma kanoo yaAAmaloona", transliterationB: "Fawaqa'al haqqu wa batala maa kaanoo ya'maloon", english: "Thus truth was confirmed, and all that they did was made of no effect", romanUrdu: "Is tarah jo haqq tha woh haqq saabit hua aur jo kuch unhon ne bana rakkha tha woh baatil hokar reh gaya" },
    { number: 119, arabic: "فَغُلِبُوا۟ هُنَالِكَ وَٱنقَلَبُوا۟ صَٰغِرِينَ", transliteration: "Faghuliboo hunalika wainqalaboo saghireena", transliterationB: "Faghuliboo hunaalika wanqalaboo saaghireen", english: "So the (great ones) were vanquished there and then, and were made to look small", romanUrdu: "Firoun aur uske saathi maidan e muqable mein magloob huey aur (fatah-mand honay ke bajaye) ultey zaleel ho gaye" },
    { number: 120, arabic: "وَأُلْقِىَ ٱلسَّحَرَةُ سَٰجِدِينَ", transliteration: "Waolqiya alssaharatu sajideena", transliterationB: "Wa ulqiyas saharatu saajideen", english: "But the sorcerers fell down prostrate in adoration", romanUrdu: "Aur jaadugaron ka haal yeh hua ke goya kisi cheez ne andar se unhein sajde mein gira diya" },
    { number: 121, arabic: "قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَٰلَمِينَ", transliteration: "Qaloo amanna birabbi alAAalameena", transliterationB: "Qaaloo aamannaa bi Rabbil 'aalameen", english: "Saying: \"We believe in the Lord of the Worlds", romanUrdu: "Kehne lagey “ humne maan liya Rabbul aalameen ko" },
    { number: 122, arabic: "رَبِّ مُوسَىٰ وَهَٰرُونَ", transliteration: "Rabbi moosa waharoona", transliterationB: "Rabbi Moosaa wa Haaroon", english: "The Lord of Moses and Aaron", romanUrdu: "Us Rubb ko jisey Moosa aur Haroon maantey hain”" },
    { number: 123, arabic: "قَالَ فِرْعَوْنُ ءَامَنتُم بِهِۦ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّ هَٰذَا لَمَكْرٌۭ مَّكَرْتُمُوهُ فِى ٱلْمَدِينَةِ لِتُخْرِجُوا۟ مِنْهَآ أَهْلَهَا ۖ فَسَوْفَ تَعْلَمُونَ", transliteration: "Qala firAAawnu amantum bihi qabla an athana lakum inna hatha lamakrun makartumoohu fee almadeenati litukhrijoo minha ahlaha fasawfa taAAlamoona", transliterationB: "Qaala Fir'awnu aamantum bihee qabla an aazana lakum; inna haaza lamakrum makartumoohu filmadeenati litukhrijoo minhaaa ahlahaa fasawfa ta'almoon", english: "Said Pharaoh: \"Believe ye in Him before I give you permission? Surely this is a trick which ye have planned in the city to drive out its people: but soon shall ye know (the consequences)", romanUrdu: "Firoun ne kaha “ tum ispar iman le aaye qabl iske ke main tumhein ijazat doon? Yaqeenan yeh koi khufiya saazish thi jo tum logon ne is daar-us-sultanat mein ki taa-ke iske maalikon ko iqtedar se be-dakhal kardo. Accha to iska nateeja ab tumhein maloom hua jata hai" },
    { number: 124, arabic: "لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَٰفٍۢ ثُمَّ لَأُصَلِّبَنَّكُمْ أَجْمَعِينَ", transliteration: "LaoqatiAAanna aydiyakum waarjulakum min khilafin thumma laosallibannakum ajmaAAeena", transliterationB: "La uqatti'anna aidiyakum wa arjulakum min khilaafin summa la usallibannakum ajma'een", english: "Be sure I will cut off your hands and your feet on apposite sides, and I will cause you all to die on the cross", romanUrdu: "Main tumhare haath paon mukhalif simton se katwa dunga aur uske baad tum sabko suli par chadhaunga.”" },
    { number: 125, arabic: "قَالُوٓا۟ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ", transliteration: "Qaloo inna ila rabbina munqaliboona", transliterationB: "Qaaloo innaaa ilaa Rabbinaa munqaliboon", english: "They said: \"For us, We are but sent back unto our Lord", romanUrdu: "Unhon ne jawab diya “bahar-haal humein palatna apne Rubb hi ki taraf hai" },
    { number: 126, arabic: "وَمَا تَنقِمُ مِنَّآ إِلَّآ أَنْ ءَامَنَّا بِـَٔايَٰتِ رَبِّنَا لَمَّا جَآءَتْنَا ۚ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًۭا وَتَوَفَّنَا مُسْلِمِينَ", transliteration: "Wama tanqimu minna illa an amanna biayati rabbina lamma jaatna rabbana afrigh AAalayna sabran watawaffana muslimeena", transliterationB: "Wa maa tanqimu minnaaa illaaa an aamannaa bi Aayaati Rabbinaa lammaa jaaa'atnaa; Rabbanaaa afrigh 'alainaa sabranw wa tawaffanaa muslimeen", english: "But thou dost wreak thy vengeance on us simply because we believed in the Signs of our Lord when they reached us! Our Lord! pour out on us patience and constancy, and take our souls unto thee as Muslims (who bow to thy will)", romanUrdu: "Tu jis baat par humse intiqam lena chahta hai woh iske siwa nahin ke hamare Rubb ki nishaniyan jab hamare saamne aa gayi to humne umhein maan liya . Aey Rubb, humpar sabr ka faizan kar aur humein duniya se utha to is haal mein ke hum tere farma-bardaar hon”" },
    { number: 127, arabic: "وَقَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ أَتَذَرُ مُوسَىٰ وَقَوْمَهُۥ لِيُفْسِدُوا۟ فِى ٱلْأَرْضِ وَيَذَرَكَ وَءَالِهَتَكَ ۚ قَالَ سَنُقَتِّلُ أَبْنَآءَهُمْ وَنَسْتَحْىِۦ نِسَآءَهُمْ وَإِنَّا فَوْقَهُمْ قَٰهِرُونَ", transliteration: "Waqala almalao min qawmi firAAawna atatharu moosa waqawmahu liyufsidoo fee alardi wayatharaka waalihataka qala sanuqattilu abnaahum wanastahyee nisaahum wainna fawqahum qahiroona", transliterationB: "Wa qaalal mala-u min qawmi Fir'awna atazaru Moosaa wa qawmahoo liyufsidoo fil ardi wa yazaraka wa aalihatak; qaala sanuqattilu abnaaa 'ahum wa nastahyee nisaaa'ahum wa innaa fawqahum qaahiroon", english: "Said the chiefs of Pharaoh's people: \"Wilt thou leave Moses and his people, to spread mischief in the land, and to abandon thee and thy gods?\" He said: \"Their male children will we slay; (only) their females will we save alive; and we have over them (power) irresistible", romanUrdu: "Firoun se uski qaum ke Sardaron ne kaha “kya tu Moosa aur uski qaum ko yunhi chodh dega ke mulk mein fasaad phaylayein aur woh teri aur tere maboodon ki bandagi chodh baithey?” Firoun ne jawab diya “main unke beton ko qatal karaunga aur unki auraton ko jeeta rehne dunga. Hamare iqtedar ki giraft unpar mazboot hai”" },
    { number: 128, arabic: "قَالَ مُوسَىٰ لِقَوْمِهِ ٱسْتَعِينُوا۟ بِٱللَّهِ وَٱصْبِرُوٓا۟ ۖ إِنَّ ٱلْأَرْضَ لِلَّهِ يُورِثُهَا مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ وَٱلْعَٰقِبَةُ لِلْمُتَّقِينَ", transliteration: "Qala moosa liqawmihi istaAAeenoo biAllahi waisbiroo inna alarda lillahi yoorithuha man yashao min AAibadihi waalAAaqibatu lilmuttaqeena", transliterationB: "Qaala Moosaa liqawmihis ta'eenoo billaahi wasbiroo innal arda lillaahi yoorisuhaa mai yashaaa'u min 'ibaadihee wal 'aaqibatu lilmuttaqeen", english: "Said Moses to his people: \"Pray for help from Allah, and (wait) in patience and constancy: for the earth is Allah's, to give as a heritage to such of His servants as He pleaseth; and the end is (best) for the righteous", romanUrdu: "Moosa ne apni qaum se kaha “Allah se madad maango aur sabr karo, zameen Allah ki hai, apne bandon mein se jisko chahta hai uska waris bana deta hai. Aur aakhri kamiyabi unhi ke liye jo ussey darte huey kaam karein”" },
    { number: 129, arabic: "قَالُوٓا۟ أُوذِينَا مِن قَبْلِ أَن تَأْتِيَنَا وَمِنۢ بَعْدِ مَا جِئْتَنَا ۚ قَالَ عَسَىٰ رَبُّكُمْ أَن يُهْلِكَ عَدُوَّكُمْ وَيَسْتَخْلِفَكُمْ فِى ٱلْأَرْضِ فَيَنظُرَ كَيْفَ تَعْمَلُونَ", transliteration: "Qaloo ootheena min qabli an tatiyana wamin baAAdi ma jitana qala AAasa rabbukum an yuhlika AAaduwwakum wayastakhlifakum fee alardi fayanthura kayfa taAAmaloona", transliterationB: "Qaaloo oozeenaa min qabli an taatiyanaa wa mim ba'di maa ji'tanaa; qaala 'asaa Rabbukum ai yuhlika 'aduwwakum wa yastakhli fakum fil ardi fayanzura kaifa ta'maloon", english: "They said: \"We have had (nothing but) trouble, both before and after thou camest to us.\" He said: \"It may be that your Lord will destroy your enemy and make you inheritors in the earth; that so He may try you by your deeds", romanUrdu: "Uski qaum ke logon ne kaha “tere aane se pehle bhi hum sataye jatey thay aur ab tere aane par bhi sataye jaa rahey hain”. Usne jawab diya “qareeb hai woh waqt ke tumhara Rubb tumhare dushman ko halaak karde aur tumko zameen mein khalifa banaye. Phir dekhe ke tum kaise amal karte ho”" },
    { number: 130, arabic: "وَلَقَدْ أَخَذْنَآ ءَالَ فِرْعَوْنَ بِٱلسِّنِينَ وَنَقْصٍۢ مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمْ يَذَّكَّرُونَ", transliteration: "Walaqad akhathna ala firAAawna bialssineena wanaqsin mina alththamarati laAAallahum yaththakkaroona", transliterationB: "Wa laqad akhaznaaa Aala Fir'awna bis sineena wa naqsim minas samaraati la'allahum yazzakkaroon", english: "We punished the people of Pharaoh with years (of droughts) and shortness of crops; that they might receive admonition", romanUrdu: "Humne Firoun ke logon ko kayi saal tak kehat (drought) aur paidawaar ki kami mein mubtila rakkha ke shayad unko hosh aaye" },
    { number: 131, arabic: "فَإِذَا جَآءَتْهُمُ ٱلْحَسَنَةُ قَالُوا۟ لَنَا هَٰذِهِۦ ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۭ يَطَّيَّرُوا۟ بِمُوسَىٰ وَمَن مَّعَهُۥٓ ۗ أَلَآ إِنَّمَا طَٰٓئِرُهُمْ عِندَ ٱللَّهِ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", transliteration: "Faitha jaathumu alhasanatu qaloo lana hathihi wain tusibhum sayyiatun yattayyaroo bimoosa waman maAAahu ala innama tairuhum AAinda Allahi walakinna aktharahum la yaAAlamoona", transliterationB: "Fa izaa jaaa'at humul hasanatu qaaloo lanaa haazihee wa in tusibhum saiyi'atuny yattaiyaroo bi Moosaa wa mam ma'ah; alaaa innamaa taaa'iruhum 'indal laahi wa laakinna aksarahum laa ya'lamoon", english: "But when good (times) came, they said, \"This is due to us;\" When gripped by calamity, they ascribed it to evil omens connected with Moses and those with him! Behold! in truth the omens of evil are theirs in Allah's sight, but most of them do not understand", romanUrdu: "Magar unka haal yeh tha ke jab accha zamana aata to kehte ke hum isi ke mustahiq hain, aur jab bura zamana aata to Moosa aur uske saathiyon ko apne liye faal-e-badh (misfortune) thehrate, halanke dar haqeeqat unki faal e badh to Allah ke paas thi, magar un mein se aksar be-ilm thay" },
    { number: 132, arabic: "وَقَالُوا۟ مَهْمَا تَأْتِنَا بِهِۦ مِنْ ءَايَةٍۢ لِّتَسْحَرَنَا بِهَا فَمَا نَحْنُ لَكَ بِمُؤْمِنِينَ", transliteration: "Waqaloo mahma tatina bihi min ayatin litasharana biha fama nahnu laka bimumineena", transliterationB: "Wa qaaloo mahmaa taatinaa bihee min Aayatil litasharanaa bihaa famaa nahnu laka bimu'mineen", english: "They said (to Moses): \"Whatever be the Signs thou bringest, to work therewith thy sorcery on us, we shall never believe in thee", romanUrdu: "Unhon ne Moosa se kaha ke “tu humein mahsoor karne ke (to enchant us) liye khwa koi nishani le aaye, hum to teri baat maanne waley nahin hain”" },
    { number: 133, arabic: "فَأَرْسَلْنَا عَلَيْهِمُ ٱلطُّوفَانَ وَٱلْجَرَادَ وَٱلْقُمَّلَ وَٱلضَّفَادِعَ وَٱلدَّمَ ءَايَٰتٍۢ مُّفَصَّلَٰتٍۢ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًۭا مُّجْرِمِينَ", transliteration: "Faarsalna AAalayhimu alttoofana waaljarada waalqummala waalddafadiAAa waalddama ayatin mufassalatin faistakbaroo wakanoo qawman mujrimeena", transliterationB: "Fa arsalnaa 'alaihimut toofaana waljaraada walqum mala waddafaadi'a waddama Aayaatim mufassalaatin fastakbaroo wa kaanoo qawmam mujrimeen", english: "So We sent (plagues) on them: Wholesale death, Locusts, Lice, Frogs, And Blood: Signs openly self-explained: but they were steeped in arrogance,- a people given to sin", romanUrdu: "Aakir e kaar humne unpar toofaan bheja, tiddi-dal chodey, sarsaryan phaylaye (and locusts, and the lice ), mendak(frogs) nikale, aur khoon barsaya. Sab nishaniyan alag alag karke dikhaye, magar woh sarkashi kiye chaley gaye aur woh badey hi mujreem log thay" },
    { number: 134, arabic: "وَلَمَّا وَقَعَ عَلَيْهِمُ ٱلرِّجْزُ قَالُوا۟ يَٰمُوسَى ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ ۖ لَئِن كَشَفْتَ عَنَّا ٱلرِّجْزَ لَنُؤْمِنَنَّ لَكَ وَلَنُرْسِلَنَّ مَعَكَ بَنِىٓ إِسْرَٰٓءِيلَ", transliteration: "Walamma waqaAAa AAalayhimu alrrijzu qaloo ya moosa odAAu lana rabbaka bima AAahida AAindaka lain kashafta AAanna alrrijza lanuminanna laka walanursilanna maAAaka banee israeela", transliterationB: "Wa lammaa waqa'a 'alaihimur rijzu qaaloo ya Moosad-u lanaa rabbaka bimaa 'ahida 'indaka la'in kashafta 'annar rijza lanu 'minanna laka wa lanursilanna ma'aka Banee Israaa'eel", english: "Every time the penalty fell on them, they said: \"O Moses! on your behalf call on thy Lord in virtue of his promise to thee: If thou wilt remove the penalty from us, we shall truly believe in thee, and we shall send away the Children of Israel with thee", romanUrdu: "Jab kabhi unpar balaa nazil ho jati to kehte “ aey Moosa , tujhey apne Rubb ki taraf se jo mansab hasil hai uski bina par hamare haqq mein dua kar. Agar ab ke tu humpar se yeh balaa talwa de to hum teri baat maan lenge aur bani Israel ko tere saath bhej denge”" },
    { number: 135, arabic: "فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلرِّجْزَ إِلَىٰٓ أَجَلٍ هُم بَٰلِغُوهُ إِذَا هُمْ يَنكُثُونَ", transliteration: "Falamma kashafna AAanhumu alrrijza ila ajalin hum balighoohu itha hum yankuthoona", transliterationB: "Falammaa kashafnaa 'anhumur rijza ilaaa ajalin hum baalighoohu izaa hum yankusoon", english: "But every time We removed the penalty from them according to a fixed term which they had to fulfil,- Behold! they broke their word", romanUrdu: "Magar jab hum unpar se apna azaab ek waqt e muqarrar tak keliye, jisko woh bahar haal pahunchne waley thay, hata letey to woh yaklakht apne ahad se phir jatey" },
    { number: 136, arabic: "فَٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَٰهُمْ فِى ٱلْيَمِّ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ عَنْهَا غَٰفِلِينَ", transliteration: "Faintaqamna minhum faaghraqnahum fee alyammi biannahum kaththaboo biayatina wakanoo AAanha ghafileena", transliterationB: "Fantaqamnaa minhum fa aghraqnaahum kazzaboo bi Aayaatinaa wa kaanoo 'anhaa ghaafileen", english: "So We exacted retribution from them: We drowned them in the sea, because they rejected Our Signs and failed to take warning from them", romanUrdu: "Tab humne unsey inteqam liye aur unhein samandar mein garq kardiya kyunke unhon ne hamari nishaniyon ko jhutlaya tha aur unsey be-parwa hogaye thay" },
    { number: 137, arabic: "وَأَوْرَثْنَا ٱلْقَوْمَ ٱلَّذِينَ كَانُوا۟ يُسْتَضْعَفُونَ مَشَٰرِقَ ٱلْأَرْضِ وَمَغَٰرِبَهَا ٱلَّتِى بَٰرَكْنَا فِيهَا ۖ وَتَمَّتْ كَلِمَتُ رَبِّكَ ٱلْحُسْنَىٰ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ بِمَا صَبَرُوا۟ ۖ وَدَمَّرْنَا مَا كَانَ يَصْنَعُ فِرْعَوْنُ وَقَوْمُهُۥ وَمَا كَانُوا۟ يَعْرِشُونَ", transliteration: "Waawrathna alqawma allatheena kanoo yustadAAafoona mashariqa alardi wamagharibaha allatee barakna feeha watammat kalimatu rabbika alhusna AAala banee israeela bima sabaroo wadammarna ma kana yasnaAAu firAAawnu waqawmuhu wama kanoo yaAArishoona", transliterationB: "Wa awrasnal qawmal lazeena kaanoo yustad'afoona mashaariqal ardi wa maghaari bahal latee baaraknaa feehaa wa tammat kalimatu Rabbikal husnaa 'alaa Baneee Israaa'eela bimaa sabaroo wa dammarnaa maa kaana yasna'u Fir'awnu wa qawmuhoo wa maa kaanoo ya'rishoon", english: "And We made a people, considered weak (and of no account), inheritors of lands in both east and west, - lands whereon We sent down Our blessings. The fair promise of thy Lord was fulfilled for the Children of Israel, because they had patience and constancy, and We levelled to the ground the great works and fine buildings which Pharaoh and his people erected (with such pride)", romanUrdu: "Aur unki jagah humne un logon ko jo kamzoar bana kar rakkhey gaye thay, us sar-zameen ke mashriq o magrib ka waris bana diya jisey humne barakaton se maala maal kiya tha. Is tarah bani-Israel ke haqq mein tere Rubb ka wada e khair pura hua kyunke unhon ne sabr se kaam liya tha aur Firoun aur uski qaum ka woh sab kuch barbaad kardiya gaya jo woh banate aur chadhate thay" },
    { number: 138, arabic: "وَجَٰوَزْنَا بِبَنِىٓ إِسْرَٰٓءِيلَ ٱلْبَحْرَ فَأَتَوْا۟ عَلَىٰ قَوْمٍۢ يَعْكُفُونَ عَلَىٰٓ أَصْنَامٍۢ لَّهُمْ ۚ قَالُوا۟ يَٰمُوسَى ٱجْعَل لَّنَآ إِلَٰهًۭا كَمَا لَهُمْ ءَالِهَةٌۭ ۚ قَالَ إِنَّكُمْ قَوْمٌۭ تَجْهَلُونَ", transliteration: "Wajawazna bibanee israeela albahra faataw AAala qawmin yaAAkufoona AAala asnamin lahum qaloo ya moosa ijAAal lana ilahan kama lahum alihatun qala innakum qawmun tajhaloona", transliterationB: "Wa jaawaznaa bi Banneee Israaa'eelal bahra fa ataw 'alaa qawminy ya'kufoona 'alaaa asnaamil lahum; qaaloo yaa Moosaj'al lanaa ilaahan kamaa lahum aalihah; qaala innakum qawmun tajhaloon", english: "We took the Children of Israel (with safety) across the sea. They came upon a people devoted entirely to some idols they had. They said: \"O Moses! fashion for us a god like unto the gods they have.\" He said: \"Surely ye are a people without knowledge", romanUrdu: "Bani Israel ko humne samandar se guzaar diya, phir woh chale aur raaste mein ek aisi qaum par unka guzar hua jo apne chandh buthon (idols) ki girwida (devoted) hui thi. Kehne lagey, “Aey Moosa , hamare liye bhi koi aisa mabood bana de jaise in logon ke mabood hain”.Moosa ne kaha “tum log badi nadaani ki baatein karte ho" },
    { number: 139, arabic: "إِنَّ هَٰٓؤُلَآءِ مُتَبَّرٌۭ مَّا هُمْ فِيهِ وَبَٰطِلٌۭ مَّا كَانُوا۟ يَعْمَلُونَ", transliteration: "Inna haolai mutabbarun ma hum feehi wabatilun ma kanoo yaAAmaloona", transliterationB: "Innaa haaa'ulaaa'i mutabbarum maa hum feehi wa baatilum maa kaanoo ya'maloon", english: "As to these folk,- the cult they are in is (but) a fragment of a ruin, and vain is the (worship) which they practise", romanUrdu: "Yeh log jis tareeqe ki pairwi kar rahey hain woh to barbaad honay wala hai aur jo amal woh kar rahey hain woh sarasar baatil hai.”" },
    { number: 140, arabic: "قَالَ أَغَيْرَ ٱللَّهِ أَبْغِيكُمْ إِلَٰهًۭا وَهُوَ فَضَّلَكُمْ عَلَى ٱلْعَٰلَمِينَ", transliteration: "Qala aghayra Allahi abgheekum ilahan wahuwa faddalakum AAala alAAalameena", transliterationB: "Qaala a-ghairal laahi abgheekum ilaahanw wa Huwa faddalakum 'alal 'aalameen", english: "He said: \"Shall I seek for you a god other than the (true) Allah, when it is Allah Who hath endowed you with gifts above the nations", romanUrdu: "Phir Moosa ne kaha “kya main Allah ke siwa koi aur mabood tumhare liye talash karoon? Halaanke woh Allah hi hai jisne tumhein duniya bhar ki qaumon par fazilat bakshi hai" },
    { number: 141, arabic: "وَإِذْ أَنجَيْنَٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ ۖ يُقَتِّلُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌۭ مِّن رَّبِّكُمْ عَظِيمٌۭ", transliteration: "Waith anjaynakum min ali firAAawna yasoomoonakum sooa alAAathabi yuqattiloona abnaakum wayastahyoona nisaakum wafee thalikum balaon min rabbikum AAatheemun", transliterationB: "Wa iz anjainaakum min Aali Fir'awna yasoomoo nakum sooo'al 'azaab, yuqattiloona abnaaa'akum wa yastahyoona nisaaa'akum; wa fee zaalikum balaaa'um mir Rabbikum 'azeem", english: "And remember We rescued you from Pharaoh's people, who afflicted you with the worst of penalties, who slew your male children and saved alive your females: in that was a momentous trial from your Lord", romanUrdu: "Aur (Allah farmata hai) woh waqt yaad karo jab humne Firoun walon se tumhein nijaat di jinka haal yeh tha ke tumhein sakht azaab mein mubtila rakhte thay, tumhare beton (sons) ko qatal karte aur tumhari auraton ko zinda rehne dete thay aur is mein tumhare Rubb ki taraf se tumhari badi aazmaish thi" },
    { number: 142, arabic: "۞ وَوَٰعَدْنَا مُوسَىٰ ثَلَٰثِينَ لَيْلَةًۭ وَأَتْمَمْنَٰهَا بِعَشْرٍۢ فَتَمَّ مِيقَٰتُ رَبِّهِۦٓ أَرْبَعِينَ لَيْلَةًۭ ۚ وَقَالَ مُوسَىٰ لِأَخِيهِ هَٰرُونَ ٱخْلُفْنِى فِى قَوْمِى وَأَصْلِحْ وَلَا تَتَّبِعْ سَبِيلَ ٱلْمُفْسِدِينَ", transliteration: "WawaAAadna moosa thalatheena laylatan waatmamnaha biAAashrin fatamma meeqatu rabbihi arbaAAeena laylatan waqala moosa liakheehi haroona okhlufnee fee qawmee waaslih wala tattabiAA sabeela almufsideena", transliterationB: "Wa waa'adnaa Moosaa salaaseena lailatanw wa at mamnaahaa bi'ashrim fatamma meeqaatu Rabbihee arba'eena lailah; wa qaala Moosaa liakheehi Haaroonakh lufnee fee qawmee wa aslih wa laa tattabi' sabeelal mufsideen", english: "We appointed for Moses thirty nights, and completed (the period) with ten (more): thus was completed the term (of communion) with his Lord, forty nights. And Moses had charged his brother Aaron (before he went up): \"Act for me amongst my people: Do right, and follow not the way of those who do mischief", romanUrdu: "Humne Moosa ko tees (thirty) shab o roz ke liye [koh e sina (mount sinai) par] talab kiya aur baad mein dus (ten) din ka aur izafa kardiya, is tarah uske Rubb ki muqarrar karda muddat puray chalis (forty) din ho gayi. Moosa ne chalte huey apne bhai Haroon se kaha ke “ mere pichey tum meri qaum mein meri jaanasheeni (take my place) karna aur theek kaam karte rehna aur bigaad paida karne walon ke tareeqe par na chalna”" },
    { number: 143, arabic: "وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِىٓ أَنظُرْ إِلَيْكَ ۚ قَالَ لَن تَرَىٰنِى وَلَٰكِنِ ٱنظُرْ إِلَى ٱلْجَبَلِ فَإِنِ ٱسْتَقَرَّ مَكَانَهُۥ فَسَوْفَ تَرَىٰنِى ۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلْجَبَلِ جَعَلَهُۥ دَكًّۭا وَخَرَّ مُوسَىٰ صَعِقًۭا ۚ فَلَمَّآ أَفَاقَ قَالَ سُبْحَٰنَكَ تُبْتُ إِلَيْكَ وَأَنَا۠ أَوَّلُ ٱلْمُؤْمِنِينَ", transliteration: "Walamma jaa moosa limeeqatina wakallamahu rabbuhu qala rabbi arinee anthur ilayka qala lan taranee walakini onthur ila aljabali faini istaqarra makanahu fasawfa taranee falamma tajalla rabbuhu liljabali jaAAalahu dakkan wakharra moosa saAAiqan falamma afaqa qala subhanaka tubtu ilayka waana awwalu almumineena", transliterationB: "Wa lammaa jaaa'a Moosa limeeqaatinaa wa kallamahoo Rabbuhoo qaala Rabbi arineee anzur ilaik; qaala lan taraanee wa laakininzur ilal jabali fa inistaqarra makaanahoo faswfa taraanee; falammaa tajallaa Rabbuhoo liljabali ja'alahoo dakkanw wa kharra Moosaa sa'iqaa; falammaaa afaaqa qaala Subhaanaka tubtu ilaika wa ana awwalul mu'mineen", english: "When Moses came to the place appointed by Us, and his Lord addressed him, He said: \"O my Lord! show (Thyself) to me, that I may look upon thee.\" Allah said: \"By no means canst thou see Me (direct); But look upon the mount; if it abide in its place, then shalt thou see Me.\" When his Lord manifested His glory on the Mount, He made it as dust. And Moses fell down in a swoon. When he recovered his senses he said: \"Glory be to Thee! to Thee I turn in repentance, and I am the first to believe", romanUrdu: "Jab woh hamare muqarrar kiye huey waqt par pahuncha aur uske Rubb ne ussey kalaam kiya to usne ilteja ki ke “Aey Rubb, mujhey yaaraye nazar de ke main tujhey dekhun” . Farmaya “ Tu mujhey nahin dekh sakta, haan zara saamne ke pahad ki taraf dekh, agar woh apni jagah qayam reh jaye to albatta tu mujhey dekh sakega”. Chunanchey uske Rubb ne jab pahad par tajalli ki to usey reza reza kardiya aur Moosa gash kha kar gir pada (fell down in a swoon), jab hosh aaya to bola “paak hai teri zaat, main tere huzoor tawba karta hoon aur sabse pehla iman laney wala main hoon.”" },
    { number: 144, arabic: "قَالَ يَٰمُوسَىٰٓ إِنِّى ٱصْطَفَيْتُكَ عَلَى ٱلنَّاسِ بِرِسَٰلَٰتِى وَبِكَلَٰمِى فَخُذْ مَآ ءَاتَيْتُكَ وَكُن مِّنَ ٱلشَّٰكِرِينَ", transliteration: "Qala ya moosa innee istafaytuka AAala alnnasi birisalatee wabikalamee fakhuth ma ataytuka wakun mina alshshakireena", transliterationB: "Qaala yaa Moosaaa innis tafaituka 'alan naasi bi Risaalaatee wa bi kalaamee fakhuz maaa aataituka wa kum minash shaakireen", english: "(Allah) said: \"O Moses! I have chosen thee above (other) men, by the mission I (have given thee) and the words I (have spoken to thee): take then the (revelation) which I give thee, and be of those who give thanks", romanUrdu: "Farmaya “Aey Moosa , maine tamaam logon par tarjeeh dekar tujhey muntakhab kiya ke meri paigambari karey aur mujhse hum-kalaam ho, pas jo kuch main tujhey doon usey le aur shukar baja laa”" },
    { number: 145, arabic: "وَكَتَبْنَا لَهُۥ فِى ٱلْأَلْوَاحِ مِن كُلِّ شَىْءٍۢ مَّوْعِظَةًۭ وَتَفْصِيلًۭا لِّكُلِّ شَىْءٍۢ فَخُذْهَا بِقُوَّةٍۢ وَأْمُرْ قَوْمَكَ يَأْخُذُوا۟ بِأَحْسَنِهَا ۚ سَأُو۟رِيكُمْ دَارَ ٱلْفَٰسِقِينَ", transliteration: "Wakatabna lahu fee alalwahi min kulli shayin mawAAithatan watafseelan likulli shayin fakhuthha biquwwatin wamur qawmaka yakhuthoo biahsaniha saoreekum dara alfasiqeena", transliterationB: "Wa katabnaa lahoo fil alwaahi minkulli shai'immaw 'izaanw wa tafseelal likulli shai'in fakhuzhaa biquwwatinw waamur qawmaka yaakhuzoo bi ahsanihaa; wa ooreekum daaral faasiqeen", english: "And We ordained laws for him in the tablets in all matters, both commanding and explaining all things, (and said): \"Take and hold these with firmness, and enjoin thy people to hold fast by the best in the precepts: soon shall I show you the homes of the wicked,- (How they lie desolate)", romanUrdu: "Iske baad humne Moosa ko har shoba e zindagi ke mutaaliq naseehat aur har pehlu ke mutaaliq wazeh hidayat takhtiyon par likh kar de di, aur ussey kaha: “ in hidayaat ko mazboot haathon se sambhaal aur apni qaum ko hukum de ke inke behtar mafhoom ki pairwi karein. Anqareeb main tumhein fasiqon ke ghar dikhaunga" },
    { number: 146, arabic: "سَأَصْرِفُ عَنْ ءَايَٰتِىَ ٱلَّذِينَ يَتَكَبَّرُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَإِن يَرَوْا۟ كُلَّ ءَايَةٍۢ لَّا يُؤْمِنُوا۟ بِهَا وَإِن يَرَوْا۟ سَبِيلَ ٱلرُّشْدِ لَا يَتَّخِذُوهُ سَبِيلًۭا وَإِن يَرَوْا۟ سَبِيلَ ٱلْغَىِّ يَتَّخِذُوهُ سَبِيلًۭا ۚ ذَٰلِكَ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَكَانُوا۟ عَنْهَا غَٰفِلِينَ", transliteration: "Saasrifu AAan ayatiya allatheena yatakabbaroona fee alardi bighayri alhaqqi wain yaraw kulla ayatin la yuminoo biha wain yaraw sabeela alrrushdi la yattakhithoohu sabeelan wain yaraw sabeela alghayyi yattakhithoohu sabeelan thalika biannahum kaththaboo biayatina wakanoo AAanha ghafileena", transliterationB: "Sa asrifu 'an Aayaatiyal lazeena yatakabbaroona fil ardi bighairil haqq; wa iny-yaraw kulla Aayatil laa yu'minoo bihaa wa iny-yaraw sabeelar rushdi laa yattakhizoohu sabeelanw wa iny-yaraw sabeelal ghaiyi yatta khizoohu sabeelaa; zaalika bi annahum kazzaboo bi Aayaatinaa wa kaanoo 'anhaa ghaafileen", english: "Those who behave arrogantly on the earth in defiance of right - them will I turn away from My signs: Even if they see all the signs, they will not believe in them; and if they see the way of right conduct, they will not adopt it as the way; but if they see the way of error, that is the way they will adopt. For they have rejected our signs, and failed to take warning from them", romanUrdu: "Main apne nishaniyon se un logon ki nigaahein pher dunga jo bagair kisi haqq ke zameen mein baday bantay hain, woh khwa koi nishani dekhlein kabhi uspar iman na layenge. Agar seedha raasta unke saamne aaye to usey ikhtiyar na karenge aur agar tedha raasta nazar aaye to uspar chal padenge, isliye ke unhon ne hamari nishaniyon ko jhutlaya aur unse be parwahi karte rahey" },
    { number: 147, arabic: "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَلِقَآءِ ٱلْءَاخِرَةِ حَبِطَتْ أَعْمَٰلُهُمْ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Waallatheena kaththaboo biayatina waliqai alakhirati habitat aAAmaluhum hal yujzawna illa ma kanoo yaAAmaloona", transliterationB: "Wallazeena kazzaboo bi Aayaatinaa wa liqaaa'il Aakhirati habitat 'amaaluhum; hal yujzawna illaa maa kaanoo ya'maloon", english: "Those who reject Our signs and the meeting in the Hereafter,- vain are their deeds: Can they expect to be rewarded except as they have wrought", romanUrdu: "Hamari nishaniyon ko jis kisi ne jhutlaya aur aakhirat ki peshi ka inkar kiya uske saarey aamal zaya ho gaye. Kya log iske siwa kuch aur jaza paa sakte hain ke jaisa karein waisa bharein?”" },
    { number: 148, arabic: "وَٱتَّخَذَ قَوْمُ مُوسَىٰ مِنۢ بَعْدِهِۦ مِنْ حُلِيِّهِمْ عِجْلًۭا جَسَدًۭا لَّهُۥ خُوَارٌ ۚ أَلَمْ يَرَوْا۟ أَنَّهُۥ لَا يُكَلِّمُهُمْ وَلَا يَهْدِيهِمْ سَبِيلًا ۘ ٱتَّخَذُوهُ وَكَانُوا۟ ظَٰلِمِينَ", transliteration: "Waittakhatha qawmu moosa min baAAdihi min huliyyihim AAijlan jasadan lahu khuwarun alam yaraw annahu la yukallimuhum wala yahdeehim sabeelan ittakhathoohu wakanoo thalimeena", transliterationB: "Wattakhaza qawmu Moosaa mim ba'dihee min huliyyihim 'ijlan jasadal lahoo khuwaar; alam yaraw annahoo laa yukallimuhum wa laa yahdeehim sabeelaa; ittakha zoohu wa kaanoo zaalimeen", english: "The people of Moses made, in his absence, out of their ornaments, the image of calf, (for worship): it seemed to low: did they not see that it could neither speak to them, nor show them the way? They took it for worship and they did wrong", romanUrdu: "Moosa ke pichey uski qaum ke logon ne apne zewaron (ornaments) se ek bachde (calf) ka putla bana liya jis mein se bail (cow) ki si awaaz nikalti thi. Kya unhein nazar na aata tha ke woh na unsey bolta hai na kisi maamle mein unki rehnumayi karta hai? Magar phir bhi unhon ne usey mabood bana liya aur woh sakht zalim thay" },
    { number: 149, arabic: "وَلَمَّا سُقِطَ فِىٓ أَيْدِيهِمْ وَرَأَوْا۟ أَنَّهُمْ قَدْ ضَلُّوا۟ قَالُوا۟ لَئِن لَّمْ يَرْحَمْنَا رَبُّنَا وَيَغْفِرْ لَنَا لَنَكُونَنَّ مِنَ ٱلْخَٰسِرِينَ", transliteration: "Walamma suqita fee aydeehim waraaw annahum qad dalloo qaloo lain lam yarhamna rabbuna wayaghfir lana lanakoonanna mina alkhasireena", transliterationB: "Wa lammaa suqita feee aideehim wa ra aw annahum qad dalloo qaaloo la'il lam yarhamnaa Rabbunaa wa yaghfir lanaa lanakoonanna minal khaasireen", english: "When they repented, and saw that they had erred, they said: \"If our Lord have not mercy upon us and forgive us, we shall indeed be of those who perish", romanUrdu: "Phir jab unki fareb khurdagi ka tilism toot gaya aur unhon ne dekh liya ke dar haqeeqat woh gumraah ho gaye hain to kehne lagey ke “agar hamare Rubb ne humpar reham na farmaya aur humse darguzar na kiya to hum barbaad ho jayenge”" },
    { number: 150, arabic: "وَلَمَّا رَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَٰنَ أَسِفًۭا قَالَ بِئْسَمَا خَلَفْتُمُونِى مِنۢ بَعْدِىٓ ۖ أَعَجِلْتُمْ أَمْرَ رَبِّكُمْ ۖ وَأَلْقَى ٱلْأَلْوَاحَ وَأَخَذَ بِرَأْسِ أَخِيهِ يَجُرُّهُۥٓ إِلَيْهِ ۚ قَالَ ٱبْنَ أُمَّ إِنَّ ٱلْقَوْمَ ٱسْتَضْعَفُونِى وَكَادُوا۟ يَقْتُلُونَنِى فَلَا تُشْمِتْ بِىَ ٱلْأَعْدَآءَ وَلَا تَجْعَلْنِى مَعَ ٱلْقَوْمِ ٱلظَّٰلِمِينَ", transliteration: "Walamma rajaAAa moosa ila qawmihi ghadbana asifan qala bisama khalaftumoonee min baAAdee aAAajiltum amra rabbikum waalqa alalwaha waakhatha birasi akheehi yajurruhu ilayhi qala ibna omma inna alqawma istadAAafoonee wakadoo yaqtuloonanee fala tushmit biya alaAAdaa wala tajAAalnee maAAa alqawmi alththalimeena", transliterationB: "Wa lammaa raja'a Moosaaa ilaa qawmihee ghadbaana asifan qaala bi'samaa khalaftumoonee mim ba'dee a-'ajiltum amra Rabbikum wa alqal alwaaha wa akhaza biraasi akheehi yajurruhoo ilaih; qaalab na umma innal qawmas tad'afoonee wa kadoo yaqtu loonanee; falaa tushmit biyal a'daaa'a wa laa taj'alnee ma'al qawmiz zaalimeen", english: "When Moses came back to his people, angry and grieved, he said: \"Evil it is that ye have done in my place in my absence: did ye make haste to bring on the judgment of your Lord?\" He put down the tablets, seized his brother by (the hair of) his head, and dragged him to him. Aaron said: \"Son of my mother! the people did indeed reckon me as naught, and went near to slaying me! Make not the enemies rejoice over my misfortune, nor count thou me amongst the people of sin", romanUrdu: "Udhar se Moosa gussey aur ranjj mein bhara hua apni qaum ki taraf palta. Aatey hi usne kaha “bahut buri jaanashini ki tum logon ne mere baad! Kya tumse itna sabr na hua ke apne Rubb ke hukum ka intezar kar letey?” Aur takhtiyan phenk di aur apne bhai (Haroon) ke sar ke baal pakad kar usey khincha. Haroon ne kaha “aey meri Maa ke bete, in logon ne mujhey daba liya aur qareeb tha ke mujhey maar daalte. Pas tu dushmano ko mujhpar hassne ka mauqa na de aur is zalim giroh ke saath mujhey na shamil kar”" },
    { number: 151, arabic: "قَالَ رَبِّ ٱغْفِرْ لِى وَلِأَخِى وَأَدْخِلْنَا فِى رَحْمَتِكَ ۖ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ", transliteration: "Qala rabbi ighfir lee waliakhee waadkhilna fee rahmatika waanta arhamu alrrahimeena", transliterationB: "Qaala Rabbigh fir lee wa li akhee wa adkhilnaa fee rahmatika wa Anta arhamur raahimeen", english: "Moses prayed: \"O my Lord! forgive me and my brother! admit us to Thy mercy! for Thou art the Most Merciful of those who show mercy", romanUrdu: "Tab Moosa ne kaha “Aey Rubb, mujhey aur mere bhai ko maaf kar aur humein apni rehmat mein dakhil farma, tu sabse badhkar raheem hai.”" },
    { number: 152, arabic: "إِنَّ ٱلَّذِينَ ٱتَّخَذُوا۟ ٱلْعِجْلَ سَيَنَالُهُمْ غَضَبٌۭ مِّن رَّبِّهِمْ وَذِلَّةٌۭ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُفْتَرِينَ", transliteration: "Inna allatheena ittakhathoo alAAijla sayanaluhum ghadabun min rabbihim wathillatun fee alhayati alddunya wakathalika najzee almuftareena", transliterationB: "Innal lazeenat takhazul 'ijla-sa yanaaluhum ghadabum mir Rabbihim wa zillatun fil hayaatid dunyaa; wa kazaalika najzil muftareen", english: "Those who took the calf (for worship) will indeed be overwhelmed with wrath from their Lord, and with shame in this life: thus do We recompense those who invent (falsehoods)", romanUrdu: "(Jawab mein irshad hua ke) “Jin logon ne bachdey (calf) ko mabood banaya woh zaroor apne Rubb ke gazab mein giraftaar hokar rahenge aur duniya ki zindagi mein zaleel hongey. Jhoot ghadne walon ko hum aisi hi saza dete hain" },
    { number: 153, arabic: "وَٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ ثُمَّ تَابُوا۟ مِنۢ بَعْدِهَا وَءَامَنُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌۭ رَّحِيمٌۭ", transliteration: "Waallatheena AAamiloo alssayyiati thumma taboo min baAAdiha waamanoo inna rabbaka min baAAdiha laghafoorun raheemun", transliterationB: "Wallazeena 'amilus saiyiaati summa taaboo mim ba'dihaa wa aamanooo inna Rabbaka mim ba'dihaa la Ghafoorur Raheem", english: "But those who do wrong but repent thereafter and (truly) believe,- verily thy Lord is thereafter Oft-Forgiving, Most Merciful", romanUrdu: "Aur jo log burey amal karein phir tawba karlein aur iman le aayein to yakeenan is tawba o iman ke baad tera Rubb darguzar aur reham farmane wala hai”" },
    { number: 154, arabic: "وَلَمَّا سَكَتَ عَن مُّوسَى ٱلْغَضَبُ أَخَذَ ٱلْأَلْوَاحَ ۖ وَفِى نُسْخَتِهَا هُدًۭى وَرَحْمَةٌۭ لِّلَّذِينَ هُمْ لِرَبِّهِمْ يَرْهَبُونَ", transliteration: "Walamma sakata AAan moosa alghadabu akhatha alalwaha wafee nuskhatiha hudan warahmatun lillatheena hum lirabbihim yarhaboona", transliterationB: "Wa lammaa sakata 'am Moosal ghadabu akhazal al waaha wa fee nnuskhatihaa hudanw wa rahmatul lillazeena hum li Rabbihim yarhaboon", english: "When the anger of Moses was appeased, he took up the tablets: in the writing thereon was guidance and Mercy for such as fear their Lord", romanUrdu: "Phir jab Moosa ka gussa thanda hua to usne woh takhtiyan utha li jinki tehrir (writings) mein hidayat aur rehmat thi un logon ke liye jo apne Rubb se darte hain" },
    { number: 155, arabic: "وَٱخْتَارَ مُوسَىٰ قَوْمَهُۥ سَبْعِينَ رَجُلًۭا لِّمِيقَٰتِنَا ۖ فَلَمَّآ أَخَذَتْهُمُ ٱلرَّجْفَةُ قَالَ رَبِّ لَوْ شِئْتَ أَهْلَكْتَهُم مِّن قَبْلُ وَإِيَّٰىَ ۖ أَتُهْلِكُنَا بِمَا فَعَلَ ٱلسُّفَهَآءُ مِنَّآ ۖ إِنْ هِىَ إِلَّا فِتْنَتُكَ تُضِلُّ بِهَا مَن تَشَآءُ وَتَهْدِى مَن تَشَآءُ ۖ أَنتَ وَلِيُّنَا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا ۖ وَأَنتَ خَيْرُ ٱلْغَٰفِرِينَ", transliteration: "Waikhtara moosa qawmahu sabAAeena rajulan limeeqatina falamma akhathathumu alrrajfatu qala rabbi law shita ahlaktahum min qablu waiyyaya atuhlikuna bima faAAala alssufahao minna in hiya illa fitnatuka tudillu biha man tashao watahdee man tashao anta waliyyuna faighfir lana wairhamna waanta khayru alghafireena", transliterationB: "Wakhtaara Moosaa qawmahoo sab'eena rajjulal limeeqaatinaa falammaa akhazat humur rajfatu qaala Rabbi law shi'ta ahlaktahum min qablu wa iyyaaya atuhlikunna bimaa fa'alas sufahaaa'u minnaa in hiya illaa fitnatuka tudillu bihaa man tashaaa'u wa tahdee man tashaaa'u Anta waliyyunaa faghfir lanaa warhammnnaa wa Anta khairul ghaafireen", english: "And Moses chose seventy of his people for Our place of meeting: when they were seized with violent quaking, he prayed: \"O my Lord! if it had been Thy will Thou couldst have destroyed, long before, both them and me: wouldst Thou destroy us for the deeds of the foolish ones among us? this is no more than Thy trial: by it Thou causest whom Thou wilt to stray, and Thou leadest whom Thou wilt into the right path. Thou art our Protector: so forgive us and give us Thy mercy; for Thou art the best of those who forgive", romanUrdu: "Aur usne apni qaum ke satter (seventy) aadmiyon ko muntakhab kiya taa-ke woh (uske saath) hamare muqarrar kiye huey waqt par haazir hon. Jab in logon ko ek sakht zalzale ne aa pakda to Moosa ne arz kiya “ aey mere sarkar, aap chahte to pehle hi inko aur mujhey halaak kar sakte thay, kya aap us kasoor mein jo hum mein se chandh nadano ne kiya tha hum sab ko halaak kar denge? Yeh to aap ki daali hui ek aazmaish thi jiske zariye se aap jisey chahte hain gumrahi mein mubtila kardete hain aur jisey chahte hain hidayat baksh dete hain. Hamare sarparast to aap hi hain, pas humein maaf kardijiye aur humpar reham farmaiye. Aap sabse badhkar maaf farmane waley hain" },
    { number: 156, arabic: "۞ وَٱكْتُبْ لَنَا فِى هَٰذِهِ ٱلدُّنْيَا حَسَنَةًۭ وَفِى ٱلْءَاخِرَةِ إِنَّا هُدْنَآ إِلَيْكَ ۚ قَالَ عَذَابِىٓ أُصِيبُ بِهِۦ مَنْ أَشَآءُ ۖ وَرَحْمَتِى وَسِعَتْ كُلَّ شَىْءٍۢ ۚ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَٱلَّذِينَ هُم بِـَٔايَٰتِنَا يُؤْمِنُونَ", transliteration: "Waoktub lana fee hathihi alddunya hasanatan wafee alakhirati inna hudna ilayka qala AAathabee oseebu bihi man ashao warahmatee wasiAAat kulla shayin fasaaktubuha lillatheena yattaqoona wayutoona alzzakata waallatheena hum biayatina yuminoona", transliterationB: "Waktub lanaa fee haazi hid dunyaa hasanatanw wa fil Aakhirati innnaa hudnaaa ilaik; qaala 'azaabee useebu bihee man ashaaa'u wa rahmatee wasi'at kulla shai'; fasa aktubuhaa lillazeena yattaqoona wa yu'toonaz Zakaata wallazeena hum bi Aayaatinaa yu'minoon", english: "And ordain for us that which is good, in this life and in the Hereafter: for we have turned unto Thee.\" He said: \"With My punishment I visit whom I will; but My mercy extendeth to all things. That (mercy) I shall ordain for those who do right, and practise regular charity, and those who believe in Our signs", romanUrdu: "Aur hamare liye is duniya ki bhalayi bhi likh dijiye aur aakhirat ki bhi, humne aapki taraf rujoo kar liya”. Jawab mein irshad hua “saza to main jisey chahta hoon deta hoon, magar meri rehmat har cheez par chayi hui hai. Aur usey main un logon ke haqq mein likhunga jo nafarmani se parheiz karenge, zakat denge aur meri aayat par iman layenge.”" },
    { number: 157, arabic: "ٱلَّذِينَ يَتَّبِعُونَ ٱلرَّسُولَ ٱلنَّبِىَّ ٱلْأُمِّىَّ ٱلَّذِى يَجِدُونَهُۥ مَكْتُوبًا عِندَهُمْ فِى ٱلتَّوْرَىٰةِ وَٱلْإِنجِيلِ يَأْمُرُهُم بِٱلْمَعْرُوفِ وَيَنْهَىٰهُمْ عَنِ ٱلْمُنكَرِ وَيُحِلُّ لَهُمُ ٱلطَّيِّبَٰتِ وَيُحَرِّمُ عَلَيْهِمُ ٱلْخَبَٰٓئِثَ وَيَضَعُ عَنْهُمْ إِصْرَهُمْ وَٱلْأَغْلَٰلَ ٱلَّتِى كَانَتْ عَلَيْهِمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ بِهِۦ وَعَزَّرُوهُ وَنَصَرُوهُ وَٱتَّبَعُوا۟ ٱلنُّورَ ٱلَّذِىٓ أُنزِلَ مَعَهُۥٓ ۙ أُو۟لَٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ", transliteration: "Allatheena yattabiAAoona alrrasoola alnnabiyya alommiyya allathee yajidoonahu maktooban AAindahum fee alttawrati waalinjeeli yamuruhum bialmaAAroofi wayanhahum AAani almunkari wayuhillu lahumu alttayyibati wayuharrimu AAalayhimu alkhabaitha wayadaAAu AAanhum israhum waalaghlala allatee kanat AAalayhim faallatheena amanoo bihi waAAazzaroohu wanasaroohu waittabaAAoo alnnoora allathee onzila maAAahu olaika humu almuflihoona", transliterationB: "Allazeena yattabi'oonar Rasoolan Nabiyyal ummiyyal lazee yajidoonahoo maktooban 'indahum fit Tawraati wal Injeeli yaa muruhum bilma'roofi wa yanhaahum 'anil munkari wa yuhillu lahumul taiyibaati wa yuharrimu 'alaihimul khabaaa'isa wa yada'u 'anhum israhum wal aghlaalal latee kaanat 'alaihim; fallazeena aamanoo bihee wa 'azzaroohu wa nnasaroohu wattaba'un nooral lazeee unzila ma'ahooo ulaaa'ika humul muflihoon", english: "Those who follow the messenger, the unlettered Prophet, whom they find mentioned in their own (scriptures),- in the law and the Gospel;- for he commands them what is just and forbids them what is evil; he allows them as lawful what is good (and pure) and prohibits them from what is bad (and impure); He releases them from their heavy burdens and from the yokes that are upon them. So it is those who believe in him, honour him, help him, and follow the light which is sent down with him,- it is they who will prosper", romanUrdu: "(Pas aaj yeh rehmat un logon ka hissa hai) jo is paigambar, Nabi e ummi ki pairwi ikhtiyar karein jiska zikr unhein apne haan Taurat aur Injil mein likha hua milta hai. Woh unhein neki ka hukum deta hai, badhi (all corrupt things) se roakta hai, unke liye paak cheezein halaal aur napaak cheezein haraam karta hai, aur unpar se woh bojh utaarta hai jo unpar laday huey thay aur woh bandishein kholta hai jin mein woh jakdey huey thay. Lihaza jo log ispar iman layein aur iski himayat aur nusrat karein aur woh us roshni ki pairwi ikhtiyar karein jo iske saath nazil ki gayi hai, wahi falaah paney waley hain" },
    { number: 158, arabic: "قُلْ يَٰٓأَيُّهَا ٱلنَّاسُ إِنِّى رَسُولُ ٱللَّهِ إِلَيْكُمْ جَمِيعًا ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ لَآ إِلَٰهَ إِلَّا هُوَ يُحْىِۦ وَيُمِيتُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِ ٱلنَّبِىِّ ٱلْأُمِّىِّ ٱلَّذِى يُؤْمِنُ بِٱللَّهِ وَكَلِمَٰتِهِۦ وَٱتَّبِعُوهُ لَعَلَّكُمْ تَهْتَدُونَ", transliteration: "Qul ya ayyuha alnnasu innee rasoolu Allahi ilaykum jameeAAan allathee lahu mulku alssamawati waalardi la ilaha illa huwa yuhyee wayumeetu faaminoo biAllahi warasoolihi alnnabiyyi alommiyyi allathee yuminu biAllahi wakalimatihi waittabiAAoohu laAAallakum tahtadoona", transliterationB: "Qul yaaa aiyuhan naasu innee Rasoohul laahi ilaikum jamee'anil lazee lahoo mulkus samaawaati wal ardi laaa ilaaha illaa Huwa yuhyee wa yumeetu fa aaminoo billaahi wa Rasoolihin Nabiyyil ummiy yil lazee yu'minu billaahi wa Kalimaatihee wattabi'oohu la'allakum tahtadoon", english: "Say: \"O men! I am sent unto you all, as the Messenger of Allah, to Whom belongeth the dominion of the heavens and the earth: there is no god but He: it is He That giveth both life and death. So believe in Allah and His Messenger, the Unlettered Prophet, who believeth in Allah and His words: follow him that (so) ye may be guided", romanUrdu: "(Aey Muhammad) , kaho ke “ aey Insaano , main tum sab ki taraf us khuda ka paigambar hoon jo zameen aur aasmano ki baadshahi ka maalik hai, uske siwa koi khuda nahin hai, wahi zindagi bakshta hai aur wahi maut deta hai. Pas iman lao Allah par aur uske bheje huey Nabi e ummi par jo Allah aur uske irshadat ko maanta hai, aur pairwi ikhtiyar karo uski, umeed hai ke tum raah e raast paa logey" },
    { number: 159, arabic: "وَمِن قَوْمِ مُوسَىٰٓ أُمَّةٌۭ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ", transliteration: "Wamin qawmi moosa ommatun yahdoona bialhaqqi wabihi yaAAdiloona", transliterationB: "Wa min qawmi Moosaaa ummatuny yahdoona bilhaqqi wa bihee ya'diloon", english: "Of the people of Moses there is a section who guide and do justice in the light of truth", romanUrdu: "Moosa ki qaum mein ek giroh aisa bhi tha jo haqq ke mutabiq hidayat karta aur haqq hi ke mutabiq insaf karta tha" },
    { number: 160, arabic: "وَقَطَّعْنَٰهُمُ ٱثْنَتَىْ عَشْرَةَ أَسْبَاطًا أُمَمًۭا ۚ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ إِذِ ٱسْتَسْقَىٰهُ قَوْمُهُۥٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنۢبَجَسَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًۭا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍۢ مَّشْرَبَهُمْ ۚ وَظَلَّلْنَا عَلَيْهِمُ ٱلْغَمَٰمَ وَأَنزَلْنَا عَلَيْهِمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَٰتِ مَا رَزَقْنَٰكُمْ ۚ وَمَا ظَلَمُونَا وَلَٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ", transliteration: "WaqattaAAnahumu ithnatay AAashrata asbatan omaman waawhayna ila moosa ithi istasqahu qawmuhu ani idrib biAAasaka alhajara fainbajasat minhu ithnata AAashrata AAaynan qad AAalima kullu onasin mashrabahum wathallalna AAalayhimu alghamama waanzalna AAalayhimu almanna waalssalwa kuloo min tayyibati ma razaqnakum wama thalamoona walakin kanoo anfusahum yathlimoona", transliterationB: "Wa qatta' naahumus natai 'ashrata asbaatan umamaa; wa awhainaa ilaa Moosaaa izis tasqaahu qawmuhooo anid rib bi'asaakal hajara fambajasat minhus nata 'ashrata 'ainan qad 'alima kullu unaasim mashrabahm; wa zallalnaa 'alaihimul ghammaamma wa anzalnaa 'alaihimul MManna was Salwaa kuloo min taiyibaati maa razaqnaakum; wa maa zalamoonaa wa laakin kaanooo anfusahum yazlimoon", english: "We divided them into twelve tribes or nations. We directed Moses by inspiration, when his (thirsty) people asked him for water: \"Strike the rock with thy staff\": out of it there gushed forth twelve springs: Each group knew its own place for water. We gave them the shade of clouds, and sent down to them manna and quails, (saying): \"Eat of the good things We have provided for you\": (but they rebelled); to Us they did no harm, but they harmed their own souls", romanUrdu: "Aur humne us qaum ko barah (twelve) gharano mein takseem karke unhein mustaqil girohon ki shakal de di thi. Aur jab Moosa se uski qaum ne pani maanga to humne usko ishara kiya ke falaan chattan par apni lathi maaro. Chunanchey is chattan se yakayak barah chashme (twelve springs) phoot nikle aur har giroh ne apne pani lene ki jagah mutaiyyan karli. Humne unpar badal (cloud) ka saya kiya aur unpar mann o salwa (quails) utara, khao woh paak cheezein jo humne tumko bakshi hain magar iske baad unhon ne jo kuch kiya to humpar zulm nahin kiya balke aap apne hi upar zulm karte rahey" },
    { number: 161, arabic: "وَإِذْ قِيلَ لَهُمُ ٱسْكُنُوا۟ هَٰذِهِ ٱلْقَرْيَةَ وَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ وَقُولُوا۟ حِطَّةٌۭ وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًۭا نَّغْفِرْ لَكُمْ خَطِيٓـَٰٔتِكُمْ ۚ سَنَزِيدُ ٱلْمُحْسِنِينَ", transliteration: "Waith qeela lahumu oskunoo hathihi alqaryata wakuloo minha haythu shitum waqooloo hittatun waodkhuloo albaba sujjadan naghfir lakum khateeatikum sanazeedu almuhsineena", transliterationB: "Wa iz qeela lahumuskunoo haazihil qaryata wa kuloo minhaa haisu shi'tum wa qooloo hittatunw wadkhulul baaba sujjadan naghfir lakum khateee'aatikum; sanazeedul muhsineen", english: "And remember it was said to them: \"Dwell in this town and eat therein as ye wish, but say the word of humility and enter the gate in a posture of humility: We shall forgive you your faults; We shall increase (the portion of) those who do good", romanUrdu: "Yaad karo woh waqt jab unsey kaha gaya tha ke is basti mein jaa kar bass(settle) jao aur iski paidawaar se apne hasb-e-mansha(whatever you please) rozi haasil karo aur hittatun hittatun(repentance) kehte jao aur shehar ke darwaze mein sajda-rez hotey huey daakhil ho. Hum tumhare khataein maaf karenge aur neik rawiyya rakhne walon ko mazeed fazal se nawazenge”" },
    { number: 162, arabic: "فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَرْسَلْنَا عَلَيْهِمْ رِجْزًۭا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَظْلِمُونَ", transliteration: "Fabaddala allatheena thalamoo minhum qawlan ghayra allathee qeela lahum faarsalna AAalayhim rijzan mina alssamai bima kanoo yathlimoona", transliterationB: "Fabaddalal lazeena zalamoo minhum qawlan ghairal lazee qeela lahum fa arsalnaa 'alaihim rijzam minas samaaa'i bimaa kaanoo yazlimoon", english: "But the transgressors among them changed the word from that which had been given them so we sent on them a plague from heaven. For that they repeatedly transgressed", romanUrdu: "Magar jo log unmein se zalim thay unhon ne us baat ko jo unse kahi gayi thi badal dala, aur nateeja yeh hua ke humne unke zulm ki padash mein unpar aasman se azaab bhej diya" },
    { number: 163, arabic: "وَسْـَٔلْهُمْ عَنِ ٱلْقَرْيَةِ ٱلَّتِى كَانَتْ حَاضِرَةَ ٱلْبَحْرِ إِذْ يَعْدُونَ فِى ٱلسَّبْتِ إِذْ تَأْتِيهِمْ حِيتَانُهُمْ يَوْمَ سَبْتِهِمْ شُرَّعًۭا وَيَوْمَ لَا يَسْبِتُونَ ۙ لَا تَأْتِيهِمْ ۚ كَذَٰلِكَ نَبْلُوهُم بِمَا كَانُوا۟ يَفْسُقُونَ", transliteration: "Waisalhum AAani alqaryati allatee kanat hadirata albahri ith yaAAdoona fee alssabti ith tateehim heetanuhum yawma sabtihim shurraAAan wayawma la yasbitoona la tateehim kathalika nabloohum bima kanoo yafsuqoona", transliterationB: "Was'alhum 'anil qaryatil latee kaanat haadiratal bahri iz ya'doona fis Sabt iz taateehim heetaanuhum yawma Sabtihim shurra'anw wa yawma laa yasbitoona laa taateehim; kazaalika nabloohum bimaa kaanoo yafsuqoon", english: "Ask them concerning the town standing close by the sea. Behold! they transgressed in the matter of the Sabbath. For on the day of their Sabbath their fish did come to them, openly holding up their heads, but on the day they had no Sabbath, they came not: thus did We make a trial of them, for they were given to transgression", romanUrdu: "Aur zara inse us basti ka haal bhi pucho jo samandar ke kinarey waqey thi, inhein yaad dilao woh waqiya ke wahan ke log sabt (sabbath/hafte) ke din ehkam e ilahi ki khilaf warzi karte thay aur yeh ke machliyan (fishes) sabt ke din ubhar ubhar kar satah (water's surface) par unke saamne aati thi aur sabt ke siwa baaki dino mein nahin aati thi. Yeh isliye hota tha ke hum unki nafarmaniyon ki wajah se unko aazmaish mein daal rahey thay" },
    { number: 164, arabic: "وَإِذْ قَالَتْ أُمَّةٌۭ مِّنْهُمْ لِمَ تَعِظُونَ قَوْمًا ۙ ٱللَّهُ مُهْلِكُهُمْ أَوْ مُعَذِّبُهُمْ عَذَابًۭا شَدِيدًۭا ۖ قَالُوا۟ مَعْذِرَةً إِلَىٰ رَبِّكُمْ وَلَعَلَّهُمْ يَتَّقُونَ", transliteration: "Waith qalat ommatun minhum lima taAAithoona qawman Allahu muhlikuhum aw muAAaththibuhum AAathaban shadeedan qaloo maAAthiratan ila rabbikum walaAAallahum yattaqoona", transliterationB: "Wa iz qaalat ummatum minhum lima ta'izoona qaw manil laahu muhlikuhum aw mu'azzibuhum 'azaaban shadeedan qaaloo ma'ziratan ilaa Rabbikum wa la'allahum tattaqoon", english: "When some of them said: \"Why do ye preach to a people whom Allah will destroy or visit with a terrible punishment?\"- said the preachers:\" To discharge our duty to your Lord, and perchance they may fear Him", romanUrdu: "Aur inhein yeh bhi yaad dilao ke jab unmein se ek giroh ne dusre giroh se kaha tha ke “tum aisey logon ko kyun naseehat karte ho jinhein Allah halaak karne wala ya sakht saza dene wala hai” to unhon ne jawab diya tha ke “hum yeh sab kuch tumhare Rubb ke huzoor apni maazirat (excuse) pesh karne ke liye karte hain aur is umeed par karte hain ke shayad yeh log uski nafarmani se parheiz karne lagein.”" },
    { number: 165, arabic: "فَلَمَّا نَسُوا۟ مَا ذُكِّرُوا۟ بِهِۦٓ أَنجَيْنَا ٱلَّذِينَ يَنْهَوْنَ عَنِ ٱلسُّوٓءِ وَأَخَذْنَا ٱلَّذِينَ ظَلَمُوا۟ بِعَذَابٍۭ بَـِٔيسٍۭ بِمَا كَانُوا۟ يَفْسُقُونَ", transliteration: "Falamma nasoo ma thukkiroo bihi anjayna allatheena yanhawna AAani alssooi waakhathna allatheena thalamoo biAAathabin baeesin bima kanoo yafsuqoona", transliterationB: "Falammaa nasoo maa zukkiroo bihee anjainal lazeena yanhawna 'anis sooo'i wa akhaznal lazeena zalamoo bi'azaabim ba'eeim bimaa kaanooyafsuqoon", english: "When they disregarded the warnings that had been given them, We rescued those who forbade Evil; but We visited the wrong-doers with a grievous punishment because they were given to transgression", romanUrdu: "Aakhir e kaar jab woh un hidayaat ko bilkul hi faramosh kar gaye jo unhein yaad karayi gayi thin to humne un logon ko bacha liya jo burayi se roakte thay aur baqi sab logon ko jo zalim thay unki nafarmaniyon par sakht azaab mein pakad liya" },
    { number: 166, arabic: "فَلَمَّا عَتَوْا۟ عَن مَّا نُهُوا۟ عَنْهُ قُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَٰسِـِٔينَ", transliteration: "Falamma AAataw AAan ma nuhoo AAanhu qulna lahum koonoo qiradatan khasieena", transliterationB: "Falammaa 'ataw 'ammmaa nuhoo 'anhu qulna lahum kkoonoo qiradatan khaasi'een", english: "When in their insolence they transgressed (all) prohibitions, We said to them: \"Be ye apes, despised and rejected", romanUrdu: "Phir jab woh puri sarkashi ke saath wahi kaam kiye chale gaye jissey unhein roka gaya tha, to humne kaha ke bandar ho jao zaleel aur khwar" },
    { number: 167, arabic: "وَإِذْ تَأَذَّنَ رَبُّكَ لَيَبْعَثَنَّ عَلَيْهِمْ إِلَىٰ يَوْمِ ٱلْقِيَٰمَةِ مَن يَسُومُهُمْ سُوٓءَ ٱلْعَذَابِ ۗ إِنَّ رَبَّكَ لَسَرِيعُ ٱلْعِقَابِ ۖ وَإِنَّهُۥ لَغَفُورٌۭ رَّحِيمٌۭ", transliteration: "Waith taaththana rabbuka layabAAathanna AAalayhim ila yawmi alqiyamati man yasoomuhum sooa alAAathabi inna rabbaka lasareeAAu alAAiqabi wainnahu laghafoorun raheemun", transliterationB: "Wa iz ta azzana Rabbuka la yab'asannna 'alaihim ilaa Yawmil Qiyaamati mai yasoomuhum sooo'al 'azaab; inna Rabbaka lasaree'ul 'iqaab; wa innahoo la Ghafoorur Raheem", english: "Behold! thy Lord did declare that He would send against them, to the Day of Judgment, those who would afflict them with grievous penalty. Thy Lord is quick in retribution, but He is also Oft-forgiving, Most Merciful", romanUrdu: "Aur yaad karo jabke tumhare Rubb ne elan kardiya ke “woh qayamat tak barabar aisey log bani Israel par musallat karta rahega jo unko badhtareen azaab denge.” Yakeenan tumhara Rubb saza dene mein tez-dast (swift in chastising) hai aur yakeenan woh darguzar aur reham se bhi kaam lene waala hai" },
    { number: 168, arabic: "وَقَطَّعْنَٰهُمْ فِى ٱلْأَرْضِ أُمَمًۭا ۖ مِّنْهُمُ ٱلصَّٰلِحُونَ وَمِنْهُمْ دُونَ ذَٰلِكَ ۖ وَبَلَوْنَٰهُم بِٱلْحَسَنَٰتِ وَٱلسَّيِّـَٔاتِ لَعَلَّهُمْ يَرْجِعُونَ", transliteration: "WaqattaAAnahum fee alardi omaman minhumu alssalihoona waminhum doona thalika wabalawnahum bialhasanati waalssayyiati laAAallahum yarjiAAoona", transliterationB: "Wa qatta'naahum fil ardi umamam minhumus aalihoona wa min hum doona zaalika wa balawnaahum bilhasanaati wassaiyi aati la'allahum yarji'oon", english: "We broke them up into sections on this earth. There are among them some that are the righteous, and some that are the opposite. We have tried them with both prosperity and adversity: In order that they might turn (to us)", romanUrdu: "Humne unko zameen mein tukde tukde karke bahut se qaumon mein taqseem kardiya, kuch log inmein neik thay aur kuch issey mukhtalif aur hum unko acchey aur burey halaat se aazmaish mein mubtila karte rahey ke shayad yeh palat aayein" },
    { number: 169, arabic: "فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌۭ وَرِثُوا۟ ٱلْكِتَٰبَ يَأْخُذُونَ عَرَضَ هَٰذَا ٱلْأَدْنَىٰ وَيَقُولُونَ سَيُغْفَرُ لَنَا وَإِن يَأْتِهِمْ عَرَضٌۭ مِّثْلُهُۥ يَأْخُذُوهُ ۚ أَلَمْ يُؤْخَذْ عَلَيْهِم مِّيثَٰقُ ٱلْكِتَٰبِ أَن لَّا يَقُولُوا۟ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ وَدَرَسُوا۟ مَا فِيهِ ۗ وَٱلدَّارُ ٱلْءَاخِرَةُ خَيْرٌۭ لِّلَّذِينَ يَتَّقُونَ ۗ أَفَلَا تَعْقِلُونَ", transliteration: "Fakhalafa min baAAdihim khalfun warithoo alkitaba yakhuthoona AAarada hatha aladna wayaqooloona sayughfaru lana wain yatihim AAaradun mithluhu yakhuthoohu alam yukhath AAalayhim meethaqu alkitabi an la yaqooloo AAala Allahi illa alhaqqa wadarasoo ma feehi waalddaru alakhiratu khayrun lillatheena yattaqoona afala taAAqiloona", transliterationB: "Fakhalafa mim ba'dihim khalfunw warisul Kitaaba yaa khuzoona 'arada haazal adnaa wa yaqooloona sayughfaru lanaa wa iny yaatihim 'aradum misluhoo yaakhuzooh; alam yu'khaz 'alaihim 'aradum misluhoo yaakhuzooh; alam yu'khaz 'alaihim meesaaqul Kitaabi al laa yaqooloo 'alal laahi illal haqqa wa darasoo maa feeh; wad Daarul Aakhirtu khairul lillazeena yattaqoon; afalaa ta'qiloon", english: "After them succeeded an (evil) generation: They inherited the Book, but they chose (for themselves) the vanities of this world, saying (for excuse): \"(Everything) will be forgiven us.\" (Even so), if similar vanities came their way, they would (again) seize them. Was not the covenant of the Book taken from them, that they would not ascribe to Allah anything but the truth? and they study what is in the Book. But best for the righteous is the home in the Hereafter. Will ye not understand", romanUrdu: "Phir agli nasalon ke baad aisey na-khalaf log unke janasheen (sucessors) huey jo kitab e ilahi ke waris hokar isi duniya e dani ke faiyde (goods of this world) sameit-te hain aur kehdete hain ke tawaqqu hai humein maaf kardiya jayega. Aur agar wahi mataa e duniya phir saamne aati hai to phir lapak kar usey le lete hain. Kya unse kitaab ka ahad nahin liya ja chuka hai ke Allah ke naam par wahi baat kahein jo haqq ho? Aur yeh khud padh chuke hain jo kitab mein likha hai, aakhirat ki qayamgaah to khuda-tars logon ke liye hi behtar hai, kya tum itni si baat nahin samajhte" },
    { number: 170, arabic: "وَٱلَّذِينَ يُمَسِّكُونَ بِٱلْكِتَٰبِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ إِنَّا لَا نُضِيعُ أَجْرَ ٱلْمُصْلِحِينَ", transliteration: "Waallatheena yumassikoona bialkitabi waaqamoo alssalata inna la nudeeAAu ajra almusliheena", transliterationB: "Wallazeena yumas sikoona bil Kitaabi wa aqaamus Salaata innaa laa nudee'uajral musliheen", english: "As to those who hold fast by the Book and establish regular prayer,- never shall We suffer the reward of the righteous to perish", romanUrdu: "Jo log kitab ki pabandi karte hain aur jinhon ne namaz qaayam rakkhi hai, yaqeenan aisey neik kirdar logon ka ajar hum zaya nahin karenge" },
    { number: 171, arabic: "۞ وَإِذْ نَتَقْنَا ٱلْجَبَلَ فَوْقَهُمْ كَأَنَّهُۥ ظُلَّةٌۭ وَظَنُّوٓا۟ أَنَّهُۥ وَاقِعٌۢ بِهِمْ خُذُوا۟ مَآ ءَاتَيْنَٰكُم بِقُوَّةٍۢ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ", transliteration: "Waith nataqna aljabala fawqahum kaannahu thullatun wathannoo annahu waqiAAun bihim khuthoo ma ataynakum biquwwatin waothkuroo ma feehi laAAallakum tattaqoona", transliterationB: "Wa iz nataqnal jabala fawqahum ka annahoo zullatunw wa zannooo annahoo waaqi'um bihim khuzoo maaa aatainaakum biquwwatinw wazkuroo maa feehi la'allakum tattaqoon", english: "When We shook the Mount over them, as if it had been a canopy, and they thought it was going to fall on them (We said): \"Hold firmly to what We have given you, and bring (ever) to remembrance what is therein; perchance ye may fear Allah", romanUrdu: "Unhein woh waqt bhi kuch yaad hai jabke humne pahad ko hila kar unpar is tarah chaa diya tha ke goya woh chatri (umbrella/canopy) hai, aur yeh gumaan kar rahey thay ke woh inpar aa padega, aur us waqt humne unsey kaha tha ke jo kitaab hum tumhein de rahey hain isey mazbooti ke saath thaamo (pakdo) aur jo kuch ismein likha hai usey yaad raakho, tawaqqu hai ke tum galat-rawi se bachey rahogey" },
    { number: 172, arabic: "وَإِذْ أَخَذَ رَبُّكَ مِنۢ بَنِىٓ ءَادَمَ مِن ظُهُورِهِمْ ذُرِّيَّتَهُمْ وَأَشْهَدَهُمْ عَلَىٰٓ أَنفُسِهِمْ أَلَسْتُ بِرَبِّكُمْ ۖ قَالُوا۟ بَلَىٰ ۛ شَهِدْنَآ ۛ أَن تَقُولُوا۟ يَوْمَ ٱلْقِيَٰمَةِ إِنَّا كُنَّا عَنْ هَٰذَا غَٰفِلِينَ", transliteration: "Waith akhatha rabbuka min banee adama min thuhoorihim thurriyyatahum waashhadahum AAala anfusihim alastu birabbikum qaloo bala shahidna an taqooloo yawma alqiyamati inna kunna AAan hatha ghafileena", transliterationB: "Wa iz akhaza Rabbuka mim Baneee Aadama min zuhoorihim zurriyyatahum wa ash hadahum 'alaa anfusihim alastu bi Rabbikum qaaloo balaa shahidnaaa; an taqooloo Yawmal Qiyaamati innaa kunnaa 'an haazaa ghaafileen", english: "When thy Lord drew forth from the Children of Adam - from their loins - their descendants, and made them testify concerning themselves, (saying): \"Am I not your Lord (who cherishes and sustains you)?\"- They said: \"Yea! We do testify!\" (This), lest ye should say on the Day of Judgment: \"Of this we were never mindful", romanUrdu: "Aur (aey Nabi), logon ko yaad dilao woh waqt jabke tumhare Rubb ne bani Adam ki pushton se unki nasal ko nikala tha aur unhein khud unke upar gawah banate huey pucha tha, “kya main tumhara Rubb nahin hoon?”Unhon ne kaha, “ zaroor aap hi hamare Rubb hain, hum ispar gawahi dete hain”.Yeh humne is liye kiya ke kahin tum qayamat ke roz yeh na kehdo ke “hum to is baat se be khabar thay”" },
    { number: 173, arabic: "أَوْ تَقُولُوٓا۟ إِنَّمَآ أَشْرَكَ ءَابَآؤُنَا مِن قَبْلُ وَكُنَّا ذُرِّيَّةًۭ مِّنۢ بَعْدِهِمْ ۖ أَفَتُهْلِكُنَا بِمَا فَعَلَ ٱلْمُبْطِلُونَ", transliteration: "Aw taqooloo innama ashraka abaona min qablu wakunna thurriyyatan min baAAdihim afatuhlikuna bima faAAala almubtiloona", transliterationB: "Aw taqoolooo innamaaa ashraka aabaaa 'unaa min qablu wa kunnaa zurriyyatam mim ba'dihim afatuhlikunna bimaa fa'alal mubtiloon", english: "Or lest ye should say: \"Our fathers before us may have taken false gods, but we are (their) descendants after them: wilt Thou then destroy us because of the deeds of men who were futile", romanUrdu: "Ya ye na kehne lago ke “shirk ki ibtida to hamare baap dada ne humse pehle ki thi aur hum baad ko unki nasal se paida huey, phir kya aap humein us kasoor mein pakadte hain jo galat kaar logon ne kiya tha”" },
    { number: 174, arabic: "وَكَذَٰلِكَ نُفَصِّلُ ٱلْءَايَٰتِ وَلَعَلَّهُمْ يَرْجِعُونَ", transliteration: "Wakathalika nufassilu alayati walaAAallahum yarjiAAoona", transliterationB: "Wa kazaalika nufassihul Aayaati wa la'allahum yarji'oon", english: "Thus do We explain the signs in detail; and perchance they may turn (unto Us)", romanUrdu: "Dekho, is tarah hum nishanyan wazeh taur par pesh karte hain aur isliye karte hain ke yeh log palat aayein" },
    { number: 175, arabic: "وَٱتْلُ عَلَيْهِمْ نَبَأَ ٱلَّذِىٓ ءَاتَيْنَٰهُ ءَايَٰتِنَا فَٱنسَلَخَ مِنْهَا فَأَتْبَعَهُ ٱلشَّيْطَٰنُ فَكَانَ مِنَ ٱلْغَاوِينَ", transliteration: "Waotlu AAalayhim nabaa allathee ataynahu ayatina fainsalakha minha faatbaAAahu alshshaytanu fakana mina alghaweena", transliterationB: "Watlu 'alaihim naba allazeee aatainaahu Aayaatinaa fansalakha minhaa fa atba'a hush Shaytaano fakaana minal ghaaween", english: "Relate to them the story of the man to whom We sent Our signs, but he passed them by: so Satan followed him up, and he went astray", romanUrdu: "Aur (aey Muhammad), inke saamne us shaks ka haal bayan karo jisko humne apni aayat ka ilm ata kiya tha magar woh unki pabandi se nikal bhaga. Aakhir e kaar shaytan uske pichey padh gaya yahan tak ke woh bhatakne walon mein shamil hokar raha" },
    { number: 176, arabic: "وَلَوْ شِئْنَا لَرَفَعْنَٰهُ بِهَا وَلَٰكِنَّهُۥٓ أَخْلَدَ إِلَى ٱلْأَرْضِ وَٱتَّبَعَ هَوَىٰهُ ۚ فَمَثَلُهُۥ كَمَثَلِ ٱلْكَلْبِ إِن تَحْمِلْ عَلَيْهِ يَلْهَثْ أَوْ تَتْرُكْهُ يَلْهَث ۚ ذَّٰلِكَ مَثَلُ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا ۚ فَٱقْصُصِ ٱلْقَصَصَ لَعَلَّهُمْ يَتَفَكَّرُونَ", transliteration: "Walaw shina larafaAAnahu biha walakinnahu akhlada ila alardi waittabaAAa hawahu famathaluhu kamathali alkalbi in tahmil AAalayhi yalhath aw tatrukhu yalhath thalika mathalu alqawmi allatheena kaththaboo biayatina faoqsusi alqasasa laAAallahum yatafakkaroona", transliterationB: "Wa law shi'naa larafa'naahu bihaa wa laakin nahooo akhlada ilal ardi watta ba'a hawaah; famasaluhoo kamasalil kalb; in tahmil 'alaihi yalhas aw tatruk hu yalhas; zaalika masalul qawmil lazeena kazzaboo bi Aayaatinaa; faqsusil qasasa la'allahum yatafakkaroon", english: "If it had been Our will, We should have elevated him with Our signs; but he inclined to the earth, and followed his own vain desires. His similitude is that of a dog: if you attack him, he lolls out his tongue, or if you leave him alone, he (still) lolls out his tongue. That is the similitude of those who reject Our signs; So relate the story; perchance they may reflect", romanUrdu: "Agar hum chahte to usey un aayaton ke zariye se bulandi ata karte, magar woh to zameen hi ki taraf jhuk kar reh gaya aur apni khwahish e nafs hi ke pichey pada raha, lihaza uski haalat kuttey ki si ho gayi ke tum uspar hamla karo tab bhi zubaan latkaye rahey aur usey chodh do tab bhi zubaan latkaye rahey. Yahi misaal hai un logon ki jo hamari aayat ko jhutlate hain. Tum yeh hikayaat (parables) inko sunate raho, shayad ke yeh kuch gaur o fikr karein" },
    { number: 177, arabic: "سَآءَ مَثَلًا ٱلْقَوْمُ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا وَأَنفُسَهُمْ كَانُوا۟ يَظْلِمُونَ", transliteration: "Saa mathalan alqawmu allatheena kaththaboo biayatina waanfusahum kanoo yathlimoona", transliterationB: "Saaa'a masalanil qawmul lazeena kazzaboo bi Aayaatinaa wa anfusahum kaanoo yazlimoon", english: "Evil as an example are people who reject Our signs and wrong their own souls", romanUrdu: "Badi hi buri misaal hai aisey logon ki jinhon ne hamari aayat ko jhutlaya, aur woh aap apne hi upar zulm karte rahey hain" },
    { number: 178, arabic: "مَن يَهْدِ ٱللَّهُ فَهُوَ ٱلْمُهْتَدِى ۖ وَمَن يُضْلِلْ فَأُو۟لَٰٓئِكَ هُمُ ٱلْخَٰسِرُونَ", transliteration: "Man yahdi Allahu fahuwa almuhtadee waman yudlil faolaika humu alkhasiroona", transliterationB: "mai yahdil laahu fa huwal muhtadee wa mai yudlil fa ulaaa'ika humul khaasiroon", english: "Whom Allah doth guide,- he is on the right path: whom He rejects from His guidance,- such are the persons who perish", romanUrdu: "Jisey Allah hidayat bakshey bas wahi raah-e-raast paata hai aur jisko Allah apni rehnumayi se mehroon karde wahi nakaam o na-murad hokar rehta hai" },
    { number: 179, arabic: "وَلَقَدْ ذَرَأْنَا لِجَهَنَّمَ كَثِيرًۭا مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ لَهُمْ قُلُوبٌۭ لَّا يَفْقَهُونَ بِهَا وَلَهُمْ أَعْيُنٌۭ لَّا يُبْصِرُونَ بِهَا وَلَهُمْ ءَاذَانٌۭ لَّا يَسْمَعُونَ بِهَآ ۚ أُو۟لَٰٓئِكَ كَٱلْأَنْعَٰمِ بَلْ هُمْ أَضَلُّ ۚ أُو۟لَٰٓئِكَ هُمُ ٱلْغَٰفِلُونَ", transliteration: "Walaqad tharana lijahannama katheeran mina aljinni waalinsi lahum quloobun la yafqahoona biha walahum aAAyunun la yubsiroona biha walahum athanun la yasmaAAoona biha olaika kaalanAAami bal hum adallu olaika humu alghafiloona", transliterationB: "Wa laqad zaraanaa li jahannama kaseeram minal jinni wal insi lahum quloobul laa yafqahoona bihaa wa lahum a'yunul laa yubisiroona bihaa wa lahum aazaanul laa yasma'oona bihaa; ulaaa'ika kal an'aami bal hum adall; ulaaa'ika humul ghaafiloon", english: "Many are the Jinns and men we have made for Hell: They have hearts wherewith they understand not, eyes wherewith they see not, and ears wherewith they hear not. They are like cattle,- nay more misguided: for they are heedless (of warning)", romanUrdu: "Aur yeh haqeeqat hai ke bahut se Jinn aur Insaan aisey hain jinko humne jahannum ke liye paida kiya hai. Unke paas dil hain magar woh unse sochte nahin, unke paas aankhein hain magar woh unse dekhte nahin, unke paas kaan hain magar woh unse sunte nahin. Woh jaanwaron ki tarah hain balke unse bhi zyada gaye guzre. Yeh woh log hain jo gaflat mein khoye gaye hain" },
    { number: 180, arabic: "وَلِلَّهِ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ فَٱدْعُوهُ بِهَا ۖ وَذَرُوا۟ ٱلَّذِينَ يُلْحِدُونَ فِىٓ أَسْمَٰٓئِهِۦ ۚ سَيُجْزَوْنَ مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Walillahi alasmao alhusna faodAAoohu biha watharoo allatheena yulhidoona fee asmaihi sayujzawna ma kanoo yaAAmaloona", transliterationB: "Wa lillaahil Asmaaa 'ul Husnaa fad'oohu bihaa wa zarul lazeena yulhidoona feee Asmaaa'ih; sa yujzawna maa kaanoo ya'maloon", english: "The most beautiful names belong to Allah: so call on him by them; but shun such men as use profanity in his names: for what they do, they will soon be requited", romanUrdu: "Allah acchey naamo ka mustahiq hai. Usko acchey hi naamo se pukaro, aur un logon ko chodh do jo uske naam rakhne mein raasti se munharif ho jatey hain. Jo kuch woh karte rahey hain uska badla woh paa kar rahenge" },
    { number: 181, arabic: "وَمِمَّنْ خَلَقْنَآ أُمَّةٌۭ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ", transliteration: "Wamimman khalaqna ommatun yahdoona bialhaqqi wabihi yaAAdiloona", transliterationB: "Wa mimman khalaqnaaa ummatuny yahdoona bilhaqqi wa bihee ya'diloon", english: "Of those We have created are people who direct (others) with truth. And dispense justice therewith", romanUrdu: "Hamari makhlooq mein ek giroh aisa bhi hai jo theek theek haqq ke mutaabiq hidayat aur haqq hi ke mutaabiq insaf karta hai" },
    { number: 182, arabic: "وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَا سَنَسْتَدْرِجُهُم مِّنْ حَيْثُ لَا يَعْلَمُونَ", transliteration: "Waallatheena kaththaboo biayatina sanastadrijuhum min haythu la yaAAlamoona", transliterationB: "Wallazeena kazzaboo bi Aayaatinaa sanastadrijuhum min haisu laa ya'lamoon", english: "Those who reject Our signs, We shall gradually visit with punishment, in ways they perceive not", romanUrdu: "Rahey woh log jinhon ne hamari aayat ko jhutla diya hai, to unhein hum ba-tadreej (step by step) aisey tareeqe se tabahi ki taraf le jayenge ke unhein khabar tak na hogi" },
    { number: 183, arabic: "وَأُمْلِى لَهُمْ ۚ إِنَّ كَيْدِى مَتِينٌ", transliteration: "Waomlee lahum inna kaydee mateenun", transliterationB: "Wa umlee lahum; inna kaidee mateen", english: "Respite will I grant unto them: for My scheme is strong (and unfailing)", romanUrdu: "Main unko dheel de raha hoon, meri chaal ka koi toad nahin hai" },
    { number: 184, arabic: "أَوَلَمْ يَتَفَكَّرُوا۟ ۗ مَا بِصَاحِبِهِم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌۭ مُّبِينٌ", transliteration: "Awalam yatafakkaroo ma bisahibihim min jinnatin in huwa illa natheerun mubeenun", transliterationB: "Awalam yatafakkaroo maa bisaahibihim min jinnah; in huwa illaa nazeerum mubeen", english: "Do they not reflect? Their companion is not seized with madness: he is but a perspicuous warner", romanUrdu: "Aur kya in logon ne kabhi socha nahin? Inke rafeeq par junoon ka koi asar nahin hai, woh to ek khabardar hai jo (bura anjaam saamne aane se pehle) saaf saaf mutanabbey (warn) kar raha hai" },
    { number: 185, arabic: "أَوَلَمْ يَنظُرُوا۟ فِى مَلَكُوتِ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا خَلَقَ ٱللَّهُ مِن شَىْءٍۢ وَأَنْ عَسَىٰٓ أَن يَكُونَ قَدِ ٱقْتَرَبَ أَجَلُهُمْ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَهُۥ يُؤْمِنُونَ", transliteration: "Awalam yanthuroo fee malakooti alssamawati waalardi wama khalaqa Allahu min shayin waan AAasa an yakoona qadi iqtaraba ajaluhum fabiayyi hadeethin baAAdahu yuminoona", transliterationB: "Awalam yanzuroo fee malakootis samaawaati wal ardi wa maa khalaqal laahu min shai'inw wa an 'asaaa ai yakoona qadiqtaraba ajaluhum fabi aiyi hadeesim ba'dahoo yu'minoon", english: "Do they see nothing in the government of the heavens and the earth and all that Allah hath created? (Do they not see) that it may well be that their terms is nigh drawing to an end? In what message after this will they then believe", romanUrdu: "Kya in logon ne aasman o zameen e intezam par kabhi gaur nahin kiya aur kisi cheez ko bhi jo khuda ne paida ki hai aankhein khol kar nahin dekha? Aur kya yeh bhi unhon ne nahin socha ke shayad inki mohlat e zindagi poori honay ka waqt kareeb aa laga ho? Phir aakhir paigambar ki is tambeeh (warning) ke baad aur kaunsi baat aisi ho sakti hai jispar yeh iman layein" },
    { number: 186, arabic: "مَن يُضْلِلِ ٱللَّهُ فَلَا هَادِىَ لَهُۥ ۚ وَيَذَرُهُمْ فِى طُغْيَٰنِهِمْ يَعْمَهُونَ", transliteration: "Man yudlili Allahu fala hadiya lahu wayatharuhum fee tughyanihim yaAAmahoona", transliterationB: "Mai yadlilil laahu falaa haadiyaa lah; wa yazaruhum fee tughyaanihim ya'mahoon", english: "To such as Allah rejects from His guidance, there can be no guide: He will leave them in their trespasses, wandering in distraction", romanUrdu: "Jisko Allah rehnumayi se mehroom karde uske liye phir koi rehnuma nahin hai, aur Allah inhein inki sarkashi hi mein bhatkata hua chodey deta hai" },
    { number: 187, arabic: "يَسْـَٔلُونَكَ عَنِ ٱلسَّاعَةِ أَيَّانَ مُرْسَىٰهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ رَبِّى ۖ لَا يُجَلِّيهَا لِوَقْتِهَآ إِلَّا هُوَ ۚ ثَقُلَتْ فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ لَا تَأْتِيكُمْ إِلَّا بَغْتَةًۭ ۗ يَسْـَٔلُونَكَ كَأَنَّكَ حَفِىٌّ عَنْهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ ٱللَّهِ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Yasaloonaka AAani alssaAAati ayyana mursaha qul innama AAilmuha AAinda rabbee la yujalleeha liwaqtiha illa huwa thaqulat fee alssamawati waalardi la tateekum illa baghtatan yasaloonaka kaannaka hafiyyun AAanha qul innama AAilmuha AAinda Allahi walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Yas'aloonaka 'anis Saa'ati aiyaana mursaahaa qul innamaa 'ilmuhaa 'inda Rabbee laa yujallaeehaa liwaqtihaaa illaa Hoo; saqulat fis samaawaati wal ard; laa taateekum illaa baghtah; yas'aloonaka ka annaka hafiyyun 'anhaa qul innamaa 'ilmuhaa 'indal laahi wa laakinna aksaran naasi laa ya'lamoon", english: "They ask thee about the (final) Hour - when will be its appointed time? Say: \"The knowledge thereof is with my Lord (alone): None but He can reveal as to when it will occur. Heavy were its burden through the heavens and the earth. Only, all of a sudden will it come to you.\" They ask thee as if thou Wert eager in search thereof: Say: \"The knowledge thereof is with Allah (alone), but most men know not", romanUrdu: "Yeh log tumse puchte hain ke aakhir woh qayamat ki ghadi kab nazil hogi? Kaho“Iska ilm mere Rubb hi ke paas hai, usey apne waqt par wahi zahir karega. Aasmano aur zameen mein woh bada sakht waqt hoga. Woh tumpar achanak aa jayega”. Yeh log uske mutaaliq tumse is tarah puchte hain goya ke tum uski khoj mein lagey huey ho. Kaho, “uska ilm to sirf Allah ko hai magar aksar log is haqeeqat se na-waqif hain”" },
    { number: 188, arabic: "قُل لَّآ أَمْلِكُ لِنَفْسِى نَفْعًۭا وَلَا ضَرًّا إِلَّا مَا شَآءَ ٱللَّهُ ۚ وَلَوْ كُنتُ أَعْلَمُ ٱلْغَيْبَ لَٱسْتَكْثَرْتُ مِنَ ٱلْخَيْرِ وَمَا مَسَّنِىَ ٱلسُّوٓءُ ۚ إِنْ أَنَا۠ إِلَّا نَذِيرٌۭ وَبَشِيرٌۭ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Qul la amliku linafsee nafAAan wala darran illa ma shaa Allahu walaw kuntu aAAlamu alghayba laistakthartu mina alkhayri wama massaniya alssooo in ana illa natheerun wabasheerun liqawmin yuminoona", transliterationB: "Qul laaa amliku linafsee naf'anw wa laa darran illaa maa shaaa'al laah; wa law kuntu a'alamul ghaiba lastaksartu minal khairi wa maa massaniyas soo'; in ana illaa nazeerunw wa basheerul liqawminy yu'minoon", english: "Say: \"I have no power over any good or harm to myself except as Allah willeth. If I had knowledge of the unseen, I should have multiplied all good, and no evil should have touched me: I am but a warner, and a bringer of glad tidings to those who have faith", romanUrdu: "(Aey Muhammad), insey kaho “main apni zaat ke liye kisi nafey (faiyde) aur nuqsan ka ikhtiyar nahin rakhta, Allah hi jo kuch chahta hai woh hota hai aur agar mujhey gaib ka ilm hota to main bahut se faiyde apne liye haasil karleta aur mujhey kabhi koi nuqsan na pahunchta. Main to mehaz ek khabardaar karne wala aur khush-khabri sunane wala hoon un logon ke liye jo meri baat maanein”" },
    { number: 189, arabic: "۞ هُوَ ٱلَّذِى خَلَقَكُم مِّن نَّفْسٍۢ وَٰحِدَةٍۢ وَجَعَلَ مِنْهَا زَوْجَهَا لِيَسْكُنَ إِلَيْهَا ۖ فَلَمَّا تَغَشَّىٰهَا حَمَلَتْ حَمْلًا خَفِيفًۭا فَمَرَّتْ بِهِۦ ۖ فَلَمَّآ أَثْقَلَت دَّعَوَا ٱللَّهَ رَبَّهُمَا لَئِنْ ءَاتَيْتَنَا صَٰلِحًۭا لَّنَكُونَنَّ مِنَ ٱلشَّٰكِرِينَ", transliteration: "Huwa allathee khalaqakum min nafsin wahidatin wajaAAala minha zawjaha liyaskuna ilayha falamma taghashshaha hamalat hamlan khafeefan famarrat bihi falamma athqalat daAAawa Allaha rabbahuma lain ataytana salihan lanakoonanna mina alshshakireena", transliterationB: "Huwal lazee khalaqakum min nafsinw waahidatinw wa ja'ala minhaa zawjahaa liyas kuna ilaihaa falammaa taghash shaahaa hamalat hamlan khafeefan famarrat bihee falammaaa asqalad da'awal laaha Rabbahumaa la'in aayaitanaa saalihal lanakoo nanna minash shaakireen", english: "It is He Who created you from a single person, and made his mate of like nature, in order that he might dwell with her (in love). When they are united, she bears a light burden and carries it about (unnoticed). When she grows heavy, they both pray to Allah their Lord, (saying): \"If Thou givest us a goodly child, we vow we shall (ever) be grateful", romanUrdu: "Woh Allah hi hai jisne tumhein ek jaan se paida kiya aur usi ki jins se uska joda banaya taa-ke uske paas sukoon haasil karey. Phir jab mard ne aurat ko dhank liya to usey ek khafif sa hamal reh gaya jisey liye liye woh chalti phirti rahi, phir jab woh bojhal ho gayi to dono ne milkar Allah, apne Rubb se dua ki ke agar tu nay humko accha sa baccha diya to hum tere shukar guzar hongey" },
    { number: 190, arabic: "فَلَمَّآ ءَاتَىٰهُمَا صَٰلِحًۭا جَعَلَا لَهُۥ شُرَكَآءَ فِيمَآ ءَاتَىٰهُمَا ۚ فَتَعَٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ", transliteration: "Falamma atahuma salihan jaAAala lahu shurakaa feema atahuma fataAAala Allahu AAamma yushrikoona", transliterationB: "Falammaaa aataahumaa saalihan ja'alaa lahoo shurakaaa'a feemaaa aataahumaa; fata'aalal laahu 'ammaa yushrikoon", english: "But when He giveth them a goodly child, they ascribe to others a share in the gift they have received: but Allah is exalted high above the partners they ascribe to Him", romanUrdu: "Magar jab Allah ne unko ek sahih o saalim baccha de diya to woh uski is bakshish o inayat mein dusron ko uska shareek thehrane lagey. Allah bahut buland o bartar hai in mushrikana baaton se jo yeh log karte hain" },
    { number: 191, arabic: "أَيُشْرِكُونَ مَا لَا يَخْلُقُ شَيْـًۭٔا وَهُمْ يُخْلَقُونَ", transliteration: "Ayushrikoona ma la yakhluqu shayan wahum yukhlaqoona", transliterationB: "A yushrikoona maa laa yakhluqu shai'anw wa hum yukhlaqoon", english: "Do they indeed ascribe to Him as partners things that can create nothing, but are themselves created", romanUrdu: "Kaise nadaan hain yeh log ke unko khuda ka shareek thehrate hain jo kisi cheez ko bhi paida nahin karte balke khud paida kiye jatey hain" },
    { number: 192, arabic: "وَلَا يَسْتَطِيعُونَ لَهُمْ نَصْرًۭا وَلَآ أَنفُسَهُمْ يَنصُرُونَ", transliteration: "Wala yastateeAAoona lahum nasran wala anfusahum yansuroona", transliterationB: "Wa laa yastatee'oona lahum nasranw wa laaa anfusahum yansuroon", english: "No aid can they give them, nor can they aid themselves", romanUrdu: "Jo na unki madad kar sakte hain aur na aap apni madad hi par qadir hain" },
    { number: 193, arabic: "وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَتَّبِعُوكُمْ ۚ سَوَآءٌ عَلَيْكُمْ أَدَعَوْتُمُوهُمْ أَمْ أَنتُمْ صَٰمِتُونَ", transliteration: "Wain tadAAoohum ila alhuda la yattabiAAookum sawaon AAalaykum adaAAawtumoohum am antum samitoona", transliterationB: "Wa in tad'oohum ilalhudaa laa yattabi'ookum; sawaaa'un 'alaikum a-da'awtumoohum am antum saamitoon", english: "If ye call them to guidance, they will not obey: For you it is the same whether ye call them or ye hold your peace", romanUrdu: "Agar tum unhein seedhi raah par aane ki dawat do to woh tumhare pichey na aayein, tum khwa unhein pukaro ya khamosh raho, dono suraton mein tumhare liye yaksan hi rahey" },
    { number: 194, arabic: "إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ عِبَادٌ أَمْثَالُكُمْ ۖ فَٱدْعُوهُمْ فَلْيَسْتَجِيبُوا۟ لَكُمْ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Inna allatheena tadAAoona min dooni Allahi AAibadun amthalukum faodAAoohum falyastajeeboo lakum in kuntum sadiqeena", transliterationB: "Innal lazeena tad'oona min doonil laahi 'ibaadun amsaalukum fad'oohum fal yastajeeboo lakum in kuntum saadiqeen", english: "Verily those whom ye call upon besides Allah are servants like unto you: Call upon them, and let them listen to your prayer, if ye are (indeed) truthful", romanUrdu: "Tum log khuda ko chodh kar jinhein pukarte ho woh to mehaz bandey(slaves) hain jaisey tum banday ho. Unsey duaein maang dekho. Yeh tumhari duaon ka jawab dein agar unke barey mein tumhare khayalaat sahih hain" },
    { number: 195, arabic: "أَلَهُمْ أَرْجُلٌۭ يَمْشُونَ بِهَآ ۖ أَمْ لَهُمْ أَيْدٍۢ يَبْطِشُونَ بِهَآ ۖ أَمْ لَهُمْ أَعْيُنٌۭ يُبْصِرُونَ بِهَآ ۖ أَمْ لَهُمْ ءَاذَانٌۭ يَسْمَعُونَ بِهَا ۗ قُلِ ٱدْعُوا۟ شُرَكَآءَكُمْ ثُمَّ كِيدُونِ فَلَا تُنظِرُونِ", transliteration: "Alahum arjulun yamshoona biha am lahum aydin yabtishoona biha am lahum aAAyunun yubsiroona biha am lahum athanun yasmaAAoona biha quli odAAoo shurakaakum thumma keedooni fala tunthirooni", transliterationB: "A lahum arjuluny yamshoona bihaa am lahum aidiny yabtishoona bihaaa am lahum a'yunuy yubsiroona bihaaa am lahum aazaanuny yasma'oona bihaa; qulid'oo shurakaaa'akum summa keedooni falaa tunziroon", english: "Have they feet to walk with? Or hands to lay hold with? Or eyes to see with? Or ears to hear with? Say: \"Call your 'god-partners', scheme (your worst) against me, and give me no respite", romanUrdu: "Kya yeh paon (legs) rakhte hain ke unse chalein? Kya yeh haath rakhte hain ke unse pakadein? Kya yeh aankhein rakhte hain ke unse dekhein? Kya yeh kaan rakhte hain ke unse sunein? (Aey Muhammad), insey kaho ke “ bula lo apne thehraye huey shareekon ko phir tum sab mil kar mere khilaf tadbeerein (scheme/plot) karo aur mujhey hargiz mohlat na do" },
    { number: 196, arabic: "إِنَّ وَلِۦِّىَ ٱللَّهُ ٱلَّذِى نَزَّلَ ٱلْكِتَٰبَ ۖ وَهُوَ يَتَوَلَّى ٱلصَّٰلِحِينَ", transliteration: "Inna waliyyiya Allahu allathee nazzala alkitaba wahuwa yatawalla alssaliheena", transliterationB: "Inna waliyyial laahul lazee nazzalal Kitaaba wa Huwa yatawallas saaliheen", english: "For my Protector is Allah, Who revealed the Book (from time to time), and He will choose and befriend the righteous", romanUrdu: "Mera haami-o-nasir (guardian)woh khuda hai jisne yeh kitab nazil ki hai, aur woh neik aadmiyon ki himayat karta hai" },
    { number: 197, arabic: "وَٱلَّذِينَ تَدْعُونَ مِن دُونِهِۦ لَا يَسْتَطِيعُونَ نَصْرَكُمْ وَلَآ أَنفُسَهُمْ يَنصُرُونَ", transliteration: "Waallatheena tadAAoona min doonihi la yastateeAAoona nasrakum wala anfusahum yansuroona", transliterationB: "Wallazeena tad'oona min doonihee laa yastatee'oona nasrakum wa laaa anfusahum yansuroon", english: "But those ye call upon besides Him, are unable to help you, and indeed to help themselves", romanUrdu: "Ba-khilaf iske tum jinhein khuda ko chodh kar pukarte ho woh na tumhari madad kar sakte hain aur na khud apni madad hi karne ke qabil hain" },
    { number: 198, arabic: "وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَسْمَعُوا۟ ۖ وَتَرَىٰهُمْ يَنظُرُونَ إِلَيْكَ وَهُمْ لَا يُبْصِرُونَ", transliteration: "Wain tadAAoohum ila alhuda la yasmaAAoo watarahum yanthuroona ilayka wahum la yubsiroona", transliterationB: "Wa in tad'oohum ilal hudaa laa yasm'oo wa taraahum yanzuroona ilaika wa hum laa yubsiroon", english: "If thou callest them to guidance, they hear not. Thou wilt see them looking at thee, but they see not", romanUrdu: "Balke agar tum unhein seedhi raah par aane ke liye kaho to woh tumhari baat sun bhi nahin sakte , ba-zaahir tumko aisa nazar aata hai ke woh tumhari taraf dekh rahey hain magar fil-waqeh woh kuch bhi nahin dekhte”" },
    { number: 199, arabic: "خُذِ ٱلْعَفْوَ وَأْمُرْ بِٱلْعُرْفِ وَأَعْرِضْ عَنِ ٱلْجَٰهِلِينَ", transliteration: "Khuthi alAAafwa wamur bialAAurfi waaAArid AAani aljahileena", transliterationB: "khuzil 'afwa waamur bil'urfi waa'rid 'anil jaahileen", english: "Hold to forgiveness; command what is right; But turn away from the ignorant", romanUrdu: "(Aey Nabi), Narmi o darguzar ka tareeqa ikhtiyar karo, maroof ki talqeen kiye jao (enjoin good), aur jahilon se na uljho" },
    { number: 200, arabic: "وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَٰنِ نَزْغٌۭ فَٱسْتَعِذْ بِٱللَّهِ ۚ إِنَّهُۥ سَمِيعٌ عَلِيمٌ", transliteration: "Waimma yanzaghannaka mina alshshaytani nazghun faistaAAith biAllahi innahu sameeAAun AAaleemun", transliterationB: "Wa immaa yanzaghannaka minash Shaitaani nazghun fasta'iz billaah; innahoo Samee'un Aleem", english: "If a suggestion from Satan assail thy (mind), seek refuge with Allah; for He heareth and knoweth (all things)", romanUrdu: "Agar kabhi shaytan tumhein uksaye to Allah ki panaah maango, woh sab kuch sunne aur jaanne wala hai" },
    { number: 201, arabic: "إِنَّ ٱلَّذِينَ ٱتَّقَوْا۟ إِذَا مَسَّهُمْ طَٰٓئِفٌۭ مِّنَ ٱلشَّيْطَٰنِ تَذَكَّرُوا۟ فَإِذَا هُم مُّبْصِرُونَ", transliteration: "Inna allatheena ittaqaw itha massahum taifun mina alshshaytani tathakkaroo faitha hum mubsiroona", transliterationB: "Innal lazeenat taqaw izaa massahum taaa'ifum minash Shaitaani tazakkaroo fa izaa hum mubsiroon", english: "Those who fear Allah, when a thought of evil from Satan assaults them, bring Allah to remembrance, when lo! they see (aright)", romanUrdu: "Haqeeqat mein jo log muttaqi (Allah se darne waley/pious) hain unka haal to yeh hota hai ke kabhi shaytan ke asar se koi bura khayal agar unhein choo bhi jata hai to woh fawran choukanne (alert) ho jatey hain aur phir unhein saaf nazar aane lagta hai ke unke liye saheeh tareeqe-kar kya hai" },
    { number: 202, arabic: "وَإِخْوَٰنُهُمْ يَمُدُّونَهُمْ فِى ٱلْغَىِّ ثُمَّ لَا يُقْصِرُونَ", transliteration: "Waikhwanuhum yamuddoonahum fee alghayyi thumma la yuqsiroona", transliterationB: "Wa ikhwaanuhum yamuddoonahum fil ghaiyi summa laa yuqsiroon", english: "But their brethren (the evil ones) plunge them deeper into error, and never relax (their efforts)", romanUrdu: "Rahey unke (yaani Shaytan ke) bhai bandh, to woh unhein unki kajrawi mein khinchey (deeper into error) liye chale jatey hain aur unhein bhatkane mein koi kasar utha nahin rakhte" },
    { number: 203, arabic: "وَإِذَا لَمْ تَأْتِهِم بِـَٔايَةٍۢ قَالُوا۟ لَوْلَا ٱجْتَبَيْتَهَا ۚ قُلْ إِنَّمَآ أَتَّبِعُ مَا يُوحَىٰٓ إِلَىَّ مِن رَّبِّى ۚ هَٰذَا بَصَآئِرُ مِن رَّبِّكُمْ وَهُدًۭى وَرَحْمَةٌۭ لِّقَوْمٍۢ يُؤْمِنُونَ", transliteration: "Waitha lam tatihim biayatin qaloo lawla ijtabaytaha qul innama attabiAAu ma yooha ilayya min rabbee hatha basairu min rabbikum wahudan warahmatun liqawmin yuminoona", transliterationB: "Wa izaa lam taatihim bi aayatin qaaloo law lajtabai tahaa; qul innamaaa attabi'u maa yoohaaa ilaiya mir Rabbee; haazaa basaaa'iru mir Rabbikum wa hudanw wa rahmatul liqawminy yu'minoon", english: "If thou bring them not a revelation, they say: \"Why hast thou not got it together?\" Say: \"I but follow what is revealed to me from my Lord: this is (nothing but) lights from your Lord, and Guidance, and mercy, for any who have faith", romanUrdu: "(Aey Nabi), jab tum in logon ke saamne koi nishani (yani moajiza) pesh nahin karte to yeh kehte hain ke tumne apne liye koi nishani kyun na intekhab karli? Insey kaho “main to sirf us wahee ki pairwi karta hoon jo mere Rubb ne meri taraf bheji hai, yeh baseerat (vision) ki roshniyan hain tumhare Rubb ki taraf se aur hidayat aur rehmat hai un logon ke liye jo isey qabool karein" },
    { number: 204, arabic: "وَإِذَا قُرِئَ ٱلْقُرْءَانُ فَٱسْتَمِعُوا۟ لَهُۥ وَأَنصِتُوا۟ لَعَلَّكُمْ تُرْحَمُونَ", transliteration: "Waitha quria alquranu faistamiAAoo lahu waansitoo laAAallakum turhamoona", transliterationB: "Wa izaa quri'al Quraanu fastami'oo lahoo wa ansitoo la 'allakum turhamoon", english: "When the Qur'an is read, listen to it with attention, and hold your peace: that ye may receive Mercy", romanUrdu: "Jab Quran tumhare saamne padha jaye to isey tawajju se suno aur khamosh raho, shayad ke tumpar bhi rehmat ho jaye”" },
    { number: 205, arabic: "وَٱذْكُر رَّبَّكَ فِى نَفْسِكَ تَضَرُّعًۭا وَخِيفَةًۭ وَدُونَ ٱلْجَهْرِ مِنَ ٱلْقَوْلِ بِٱلْغُدُوِّ وَٱلْءَاصَالِ وَلَا تَكُن مِّنَ ٱلْغَٰفِلِينَ", transliteration: "Waothkur rabbaka fee nafsika tadarruAAan wakheefatan wadoona aljahri mina alqawli bialghuduwwi waalasali wala takun mina alghafileena", transliterationB: "Wazkur Rabbaka fee nafsika tadarru'anw wa kheefatanw wa doonal jahri minal qawli bilghuduwwi wal aasali wa laa takum minal ghaafileen", english: "And do thou (O reader!) Bring thy Lord to remembrance in thy (very) soul, with humility and in reverence, without loudness in words, in the mornings and evenings; and be not thou of those who are unheedful", romanUrdu: "(Aye Nabi), apne Rubb ko subah o shaam yaad kiya karo dil hi dil mein zaari (humility) aur khauf ke saath, aur zubaan se bhi halki awaz ke saath. Tum un logon mein se na ho jao jo gaflat mein padey huey hain" },
    { number: 206, arabic: "إِنَّ ٱلَّذِينَ عِندَ رَبِّكَ لَا يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِۦ وَيُسَبِّحُونَهُۥ وَلَهُۥ يَسْجُدُونَ ۩", transliteration: "Inna allatheena AAinda rabbika la yastakbiroona AAan AAibadatihi wayusabbihoonahu walahu yasjudoona", transliterationB: "Innal lazeena 'inda Rabbika laa yastakbiroona 'an 'ibaadatihee wa yusabbihoonahoo wa lahoo yasjudoon", english: "Those who are near to thy Lord, disdain not to do Him worship: They celebrate His praises, and prostrate before Him", romanUrdu: "Jo Farishtey tumhare Rubb ke huzoor taqarrub ka muqaam rakhte hain woh kabhi apni badayi ke ghamand mein aakar uski ibadat se mooh nahin moadte aur uski tasbeeh karte hain, aur uske aagey jhuke rehte hain" }
  ]
};
